// Quiz content for Cours29 — Analyse comparative du répertoire : styles et périodes

export interface Question { q: string; opts: string[]; a: number; fb: string; }
export interface Cours29Locale { questions: Question[]; }

const questionsFr: Question[] = [
  // ── TOPIC 1 : Identification de la période baroque ────────────────────────
  { q: "Quelle technique est caractéristique de la basse continue baroque ?", opts: ["Une basse qui imite le soprano", "Une basse chiffrée jouée par un continuo (clavecin, luth, orgue) soutenant la mélodie", "Une basse qui se tait aux cadences", "Une basse jouée uniquement aux cordes"], a: 1, fb: "La basse continue (basso continuo) est le fondement du style baroque : un chiffrage harmonique joué par des instruments d'accompagnement (clavecin, théorbe, orgue) pendant que la mélodie est confiée à d'autres voix. C'est l'un des critères les plus sûrs pour identifier le baroque." },
  { q: "Comment reconnaître une cadence typiquement baroque ?", opts: ["La cadence est évitée ou suspendue — le baroque préfère les demi-cadences", "La cadence est fréquente, affirmée, souvent avec ornements (trille sur la sensible)", "Le baroque n'utilise que la cadence plagale IV–I", "Les cadences baroques ne tombent jamais sur le temps fort"], a: 1, fb: "Le style baroque affectionne les cadences fréquentes et bien affirmées. La cadence authentique V–I avec trille sur la sensible (notation cadentielle baroque) est une signature de l'époque. Ces cadences ponctuent le discours régulièrement, structurant les ritournelles." },
  { q: "Le contrepoint rigoureux (présence de plusieurs voix indépendantes) est caractéristique de :", opts: ["La période classique uniquement", "L'impressionnisme", "La période baroque (Bach, Haendel, Vivaldi)", "Le romantisme tardif"], a: 2, fb: "Le contrepoint — art de faire coexister plusieurs voix indépendantes selon des règles strictes — est au cœur de l'écriture baroque. Les fugues, inventions et canons de Bach illustrent cette maîtrise. La période classique simplifie l'écriture vers une mélodie accompagnée." },
  { q: "Quelle forme est emblématique de l'écriture contrapuntique baroque ?", opts: ["La sonate de Beethoven", "La fugue — exposition d'un sujet développé par imitation entre les voix", "L'opéra de Wagner", "Le prélude de Debussy"], a: 1, fb: "La fugue est la forme contrapuntique par excellence du baroque. Un sujet est présenté seul, puis repris en imitation par toutes les voix selon des règles strictes d'entrée et de réponse. Bach en a porté l'art au sommet dans le Clavier bien tempéré et l'Art de la fugue." },
  { q: "En style baroque, les fonctions tonales I–IV–V sont :", opts: ["Absentes — le baroque n'utilise pas de fonctions tonales", "Présentes mais floues — la modalité domine encore", "Clairement établies et fréquemment affirmées par des cadences", "Réservées aux cadences finales uniquement"], a: 2, fb: "Contrairement aux périodes modales antérieures, le baroque établit clairement les fonctions tonales I, IV, V avec des cadences fréquentes et affirmées. Bach et Haendel structurent leur discours autour de la tonique, dominante et sous-dominante de façon systématique." },
  { q: "Bach (1685–1750) et Haendel (1685–1759) sont contemporains. Ce fait illustre :", opts: ["Que les deux compositeurs avaient le même style", "Que même à la même époque, deux compositeurs peuvent avoir des styles individuels très distincts", "Que le baroque est une période très courte", "Que tous les baroques sont identifiables par les mêmes caractéristiques exactes"], a: 1, fb: "Bach et Haendel sont rigoureusement contemporains mais stylistiquement différents : Bach cultive le contrepoint complexe et l'introspection luthérienne ; Haendel écrit des opéras italiens et des oratorios spectaculaires. L'époque donne un cadre, mais la signature individuelle prime toujours." },
  { q: "Le clavecin est l'instrument à clavier emblématique du baroque. Pourquoi est-il différent du piano ?", opts: ["Il a moins de touches", "Le son est produit par pincement des cordes (pas de nuance dynamique au toucher) — le piano produit le son par frappe et permet les nuances", "Il n'existe plus depuis le classicisme", "Il sonne exactement comme un piano mais plus aigu"], a: 1, fb: "Le clavecin produit son son par pincement des cordes via un plectre — le volume est constant quelle que soit la pression des doigts. Le piano (forte-piano puis piano-forte) introduit au classicisme permet de varier l'intensité au toucher. Cette différence explique les ornements fréquents du baroque pour compenser l'impossibilité du crescendo." },
  { q: "Dans la musique baroque, l'ornementation (trilles, mordants, appogiatures) a pour rôle principal :", opts: ["Décorer arbitrairement la mélodie pour la rendre plus complexe", "Remplacer les nuances dynamiques impossibles sur clavecin, articuler les dissonances et marquer les cadences", "Indiquer la tonalité au public", "Remplacer les notes manquantes de la gamme"], a: 1, fb: "L'ornementation baroque est fonctionnelle : sur clavecin (pas de nuances dynamiques), les trilles allongent les sons et marquent les appuis ; les mordants et appogiatures créent des tensions expressives ; les ornements cadentiels signalent les fins de phrase. Ce n'est pas de la décoration — c'est de la syntaxe musicale." },
  { q: "La 'Suite' baroque (allemande, courante, sarabande, gigue) est caractéristique de :", opts: ["La période romantique", "La période baroque — série de danses stylisées à différents tempos et caractères", "L'impressionnisme", "La période classique viennoise"], a: 1, fb: "La suite baroque est une collection de danses stylisées (conçues pour l'écoute, pas la danse) : allemande (modéré), courante (rapide), sarabande (lent), gigue (très rapide), parfois avec d'autres danses. Bach a composé de nombreuses suites pour clavecin, luth et orchestre. C'est une forme emblématiquement baroque." },
  { q: "Le style 'concerto grosso' (Vivaldi, Haendel, Corelli) oppose :", opts: ["Un soliste et un orchestre de chambre, alternant dans un dialogue", "Le clavecin et les cordes uniquement", "Un petit groupe soliste (concertino) contre le grand orchestre (ripieno), en alternance et en dialogue", "La voix et l'orchestre"], a: 2, fb: "Le concerto grosso baroque oppose deux ensembles : le concertino (petit groupe de solistes) et le ripieno (grand orchestre). Leurs échanges créent un dialogue de masses sonores typique du baroque. Vivaldi a perfectionné ce principe avec ses 500+ concertos pour violon et orchestre." },
  { q: "Quel critère permet le plus sûrement d'identifier une œuvre de la période baroque ?", opts: ["La présence de guitare électrique", "La basse continue, le contrepoint rigoureux et les cadences fréquentes et affirmées", "L'absence totale de chromatisme", "Les accords de 7e toujours non résolus"], a: 1, fb: "Trois critères combinés identifient le baroque : (1) basse continue avec chiffrage harmonique, (2) contrepoint entre voix indépendantes, (3) cadences fréquentes et bien affirmées avec ornements. Aucun de ces critères seul ne suffit, mais leur combinaison est caractéristique." },

  // ── TOPIC 2 : Identification de la période classique ──────────────────────
  { q: "La 'basse d'Alberti' est un accompagnement typique de la période classique. Elle consiste en :", opts: ["Une basse contrapuntique en contrepoint strict", "Un arpège brisé en trois notes : fondamentale – quinte – tierce – quinte, répété", "Une basse qui monte chromatiquement", "Une basse continue chiffrée"], a: 1, fb: "La basse d'Alberti est une formule d'accompagnement très caractéristique du style classique viennois : on alterne fondamentale – note haute – tierce – note haute dans un mouvement régulier. Mozart et Haydn l'utilisent abondamment dans leurs sonates et symphonies. Son nom vient du compositeur Domenico Alberti." },
  { q: "Les phrases symétriques (périodes de 4+4 mesures) sont caractéristiques de :", opts: ["L'improvisation baroque", "La période classique viennoise (Mozart, Haydn)", "L'impressionnisme de Debussy", "Le romantisme tardif de Wagner"], a: 1, fb: "Le style classique viennois structure systématiquement la musique en phrases symétriques de 4+4 mesures : une proposition (antécédent) et une réponse (conséquent). Cette symétrie crée une logique formelle très perceptible, bien différente du contrepoint continu baroque ou du flux romantique." },
  { q: "Comment les cadences sont-elles utilisées dans la période classique par rapport au baroque ?", opts: ["Les cadences classiques sont plus ambiguës et évitées — le classicisme préfère la continuité", "Elles sont claires, bien affirmées et structurent les phrases de façon symétrique — similaire au baroque mais dans un contexte plus homophonique", "Les cadences disparaissent au classicisme", "Les cadences classiques sont toujours plagales (IV–I)"], a: 1, fb: "Le classicisme maintient des cadences claires et affirmées, mais dans un contexte plus homophonique que le baroque. Les cadences parfaites V–I structurent les phrases de 4+4 mesures de façon très lisible. C'est une clarté cadentielle systématique qui diffère du romantisme (cadences évitées) et de l'impressionnisme (cadences absentes)." },
  { q: "La sonate classique (Allegro de sonate) présente une structure caractéristique :", opts: ["Thème A répété indéfiniment", "Exposition (2 thèmes) – Développement – Réexposition : opposition et résolution de tensions tonales", "Introduction – Air – Récitatif – Coda uniquement", "Variations continues sur un thème basse"], a: 1, fb: "La forme sonate classique suit un schéma tripartite : Exposition (thème principal I, pont modulant, thème secondaire V ou III), Développement (exploration harmonique, fragmentation), Réexposition (retour des deux thèmes en I). Ce principe d'opposition tonale (I vs V) puis résolution définit l'esthétique classique." },
  { q: "Mozart (1756–1791) et Haydn (1732–1809) représentent :", opts: ["L'avant-garde de leur époque, incompris de leurs contemporains", "Le cœur du classicisme viennois — équilibre formel, clarté harmonique, élégance mélodique", "Le baroque tardif, continuateurs de Bach", "Les précurseurs directs de l'impressionnisme"], a: 1, fb: "Mozart et Haydn incarnent l'idéal classique : équilibre entre forme et expression, clarté harmonique autour des fonctions I–IV–V, économie de moyens (pas de chromatisme inutile), élégance mélodique. Leurs œuvres définissent le standard stylistique auquel l'analyse se réfère pour identifier le classicisme." },
  { q: "L'harmonie dans le style classique viennois se caractérise par :", opts: ["Une saturation chromatique et des modulations fréquentes par tierces", "Une économie harmonique — peu d'accords (principalement I, IV, V, II, VI) utilisés avec clarté et logique fonctionnelle", "L'absence totale de dominante secondaire", "Des accords de 9e, 11e, 13e systématiques"], a: 1, fb: "Le style classique viennois se distingue par son économie harmonique : Mozart et Haydn utilisent principalement I, IV, V et leurs renversements, avec quelques dominantes secondaires ciblées. Pas de chromatisme excessif — la clarté fonctionnelle prime. C'est cet équilibre qui le distingue du romantisme surchargé." },
  { q: "Dans un menuet classique, la forme typique est :", opts: ["Thème – Variations – Coda", "A (menuet) – B (trio) – A (da capo) avec structure interne de 8+8 mesures", "Fugue en 4 voix – Strette – Final", "Introduction – Allegro – Finale"], a: 1, fb: "Le menuet classique suit la forme ternaire A–B–A (da capo) : le menuet principal, un trio contrastant (souvent dans la tonalité de la dominante ou du relatif), puis retour du menuet. Chaque section est elle-même structurée en 8+8 mesures symétriques. C'est une forme très reconnaissable du classicisme." },
  { q: "Comment reconnaître un quatuor à cordes classique stylistiquement ?", opts: ["Par la présence d'un clavecin continu à la basse", "Par quatre voix en écriture homophonique principalement, avec des échanges thématiques entre les instruments, sans basse continue", "Par la présence systématique d'une voix de basse indépendante contrapuntique", "Par l'absence de violoncelle"], a: 1, fb: "Le quatuor classique (2 violons, alto, violoncelle) abandonne la basse continue baroque au profit d'un dialogue entre les quatre voix. L'écriture est souvent homophonique avec des passages dialogués — loin du contrepoint baroque. Haydn a fondé la forme ; Mozart et Beethoven l'ont perfectionnée." },
  { q: "Beethoven (1770–1827) est souvent classé à la charnière du classicisme et du romantisme. Quel élément l'y place ?", opts: ["Il compose des fugues baroques exclusivement", "Il commence dans le style classique viennois mais introduit progressivement expression dramatique, chromatisme accru et formes élargies", "Il n'utilise jamais les fonctions classiques I–IV–V", "Son style est identique à celui de Mozart"], a: 1, fb: "Beethoven part du classicisme hérité de Haydn et Mozart mais l'étire progressivement : formes allongées (symphonies 20-45 min), chromatisme expressif accru, contrastes dynamiques radicaux (pp subito ff), structures harmoniques plus complexes. Ses dernières œuvres (op. 130-135) préfigurent le romantisme voire le modernisme." },
  { q: "Pour identifier un style classique viennois, quel trio de critères est le plus pertinent ?", opts: ["Basse continue + fugue + cadences évitées", "Phrases symétriques 4+4 + harmonie économe + cadences parfaites affirmées", "Chromatisme total + modulations par tierces + accords altérés", "Modes grecs + parallélismes + absence de résolution V–I"], a: 1, fb: "Le style classique viennois se reconnaît à trois critères combinés : (1) phrases symétriques en 4+4 mesures avec antécédent-conséquent, (2) harmonie économe autour de I, IV, V, (3) cadences parfaites bien affirmées structurant les phrases. Ce triptique contraste avec le contrepoint baroque et le chromatisme romantique." },
  { q: "Dans la période classique, les modulations se font principalement :", opts: ["Vers des tonalités très éloignées (tierce, médiante)", "Vers la dominante (V) ou le relatif mineur/majeur — tonalités voisines à ±1 dièse/bémol", "Vers le triton (substitution tritone)", "Les modulations sont absentes en période classique"], a: 1, fb: "Le classicisme module principalement vers des tonalités proches : dominante (V), relative mineure ou majeure, tonalité de la sus-dominante. Ces modulations sont clairement affirmées par des cadences dans la nouvelle tonalité. Les modulations lointaines (par tierces) arrivent avec le romantisme." },

  // ── TOPIC 3 : Identification du romantisme ────────────────────────────────
  { q: "Le chromatisme romantique se caractérise par :", opts: ["L'utilisation exclusive de la gamme diatonique sans aucune altération", "Des altérations chromatiques fréquentes qui enrichissent et colorent l'harmonie sans nécessairement moduler", "Des quintes parallèles systématiques", "L'absence totale de sensible"], a: 1, fb: "Le chromatisme romantique (Schubert, Chopin, Wagner) introduit des altérations fréquentes qui enrichissent la couleur harmonique : accords empruntés, altérations expressives, notes chromatiques dans les lignes mélodiques. Ces altérations créent des tensions qui peuvent rester sans résolution immédiate — loin de la clarté classique." },
  { q: "Les modulations par tierce (ex. Do majeur → Mi majeur) sont caractéristiques de :", opts: ["La période baroque stricte", "Le romantisme (Schubert, en particulier)", "L'impressionnisme uniquement", "La période classique viennoise"], a: 1, fb: "Les modulations par tierce (Do → Mi, Do → Lab) sont une signature du romantisme, en particulier de Schubert. Elles contournent le circuit des quintes classique (Do → Sol → Ré...) pour créer des changements harmoniques surprenants et colorés. Wagner les utilisera ensuite systématiquement pour créer des effets de lumière orchestrale." },
  { q: "L'accord de sixte augmentée (accord italien, français ou allemand) est typique de :", opts: ["Le baroque de Bach", "La période classique sans altérations", "Le romantisme — il prépare la dominante avec une tension chromatique supplémentaire", "L'impressionnisme de Debussy"], a: 2, fb: "L'accord de sixte augmentée (fondamentale + tierce + sixte augmentée, avec variantes) est une technique romantique par excellence. Il prépare la dominante avec une double tension chromatique : deux notes convergent chromatiquement vers V par demi-tons opposés. Schubert, Chopin et Brahms l'utilisent régulièrement." },
  { q: "Wagner (1813–1883) est connu pour l'utilisation de l'accord de Tristan (début de Tristan et Isolde, 1859). Pourquoi est-il révolutionnaire ?", opts: ["Parce qu'il évite toute dissonance", "Parce qu'il est profondément ambigu tonalement — ses multiples résolutions possibles remettent en question la tonalité fonctionnelle", "Parce qu'il utilise uniquement la gamme par tons", "Parce qu'il résout immédiatement sur I"], a: 1, fb: "L'accord de Tristan (Fa–Si–Ré#–Sol#) est révolutionnaire par son ambiguïté tonale : il peut être analysé comme un accord de 7e de sensible à demi-diminuée, un accord français de sixte augmentée, ou autre chose selon le contexte. Sa résolution suspendue pendant toute l'ouverture symbolise le désir insatisfait — et inaugure l'effondrement de la tonalité." },
  { q: "Le leitmotiv wagnérien est :", opts: ["Une technique baroque de basse continue", "Un motif musical associé à un personnage, une idée ou un sentiment, transformé tout au long de l'opéra", "Une forme de sonate classique", "Un ornement mélodique typique du romantisme"], a: 1, fb: "Le leitmotiv (motif directeur) est une technique narrative inventée par Wagner : un motif mélodico-harmonique court est associé à un élément dramatique (personnage, objet, sentiment) et revient transformé tout au long de l'œuvre. Cette technique influence toute la musique de film contemporaine — John Williams s'en inspire directement." },
  { q: "Chopin (1810–1849) est célèbre pour ses harmonies romantiques au piano. Quel élément les caractérise ?", opts: ["La rigidité fonctionnelle I–IV–V sans déviations", "Une richesse chromatique, des appogiatures expressives, des pédaliers harmoniques et une utilisation poétique des accords empruntés", "L'absence totale de modulation", "Une écriture purement contrapuntique fugue-comme"], a: 1, fb: "Chopin innove par sa richesse harmonique pianistique : appogiatures longues et expressives, pédaliers harmoniques (notes tenues sous des harmonies changeantes), modulations inattendues, accords empruntés (bVI en majeur), chromatisme mélodique. Ses Nocturnes sont un dictionnaire vivant de l'harmonie romantique." },
  { q: "La mélodie infinie (unendliche Melodie) de Wagner se définit comme :", opts: ["Une mélodie qui se répète exactement à l'infini", "Un flux mélodique continu qui évite les cadences conclusives et les phrases symétriques, créant une tension soutenue", "Une mélodie jouée uniquement aux violons sans accompagnement", "Une mélodie en mode dorien sans cadence"], a: 1, fb: "La mélodie infinie wagnérienne refuse les cadences conclusives et les phrases symétriques classiques. Le flux musical est continu, les tensions restent non résolues sur de longues durées. C'est l'opposé de la phrase classique de 4+4 mesures — une suspension permanente qui génère le désir et l'attente propres au drame wagnérien." },
  { q: "Schubert (1797–1828) est célèbre pour ses lieder (mélodies pour voix et piano). Qu'est-ce qui les caractérise harmoniquement ?", opts: ["Une harmonie simple et classique I–IV–V sans déviations", "Des modulations inattendues, des emprunts au mineur en majeur (bVI, bVII), un chromatisme expressif au service du texte poétique", "L'absence totale de pédalier harmonique", "Des cadences plagales exclusives"], a: 1, fb: "Les lieder de Schubert sont harmoniquement novateurs pour son époque : modulations vers des tonalités éloignées (par tierces), emprunts constants au mode mineur parallèle (bVI, bVII en majeur), chromatisme mélodique et harmonique. Tout le discours harmonique est au service du texte — la musique illustre et amplifie les images poétiques." },
  { q: "L'ambiguïté tonale croissante du romantisme tardif (Wagner, Liszt) mène vers :", opts: ["Un retour au baroque strict", "L'atonalisme du XXe siècle — la tonalité s'efface progressivement quand les dissonances cessent de se résoudre", "Le classicisme viennois de Haydn", "L'impressionnisme de Debussy uniquement"], a: 1, fb: "Le romantisme tardif (Tristan de Wagner, Poèmes symphoniques de Liszt, Brahms tardif) pousse la tonalité à ses limites : dissonances de plus en plus longues sans résolution, modulations vers des tonalités éloignées, ambiguïté du centre tonal. Cette évolution mène directement à Schoenberg et l'atonalisme — la tonalité ne peut plus se soutenir." },
  { q: "Pour identifier une œuvre romantique, quel trio de critères est le plus pertinent ?", opts: ["Basse continue + fugue + modulations proches", "Phrases symétriques + harmonie économe + basse d'Alberti", "Chromatisme expressif + modulations par tierces + accords altérés (bVI, sixtes augmentées)", "Parallélismes + modes grecs + absence de V–I"], a: 2, fb: "Le romantisme se reconnaît à trois critères : (1) chromatisme expressif fréquent, (2) modulations par tierces ou vers des tonalités éloignées, (3) accords altérés et empruntés (bVI en majeur, sixte napolitaine, sixtes augmentées). Ce chromatisme harmonique le distingue clairement du classicisme économe et de l'impressionnisme coloriste." },
  { q: "La forme du poème symphonique (Liszt, Strauss) est caractéristique de :", opts: ["La période baroque — c'est une suite de danses", "Le romantisme — une œuvre orchestrale en un seul mouvement à programme littéraire ou pictural", "La période classique — c'est une symphonie en 4 mouvements", "L'impressionnisme — c'est une pièce atonale"], a: 1, fb: "Le poème symphonique (terme inventé par Liszt) est une œuvre orchestrale en un seul mouvement inspirée d'un programme extramusical (poème, tableau, récit mythologique). Liszt en compose une douzaine ; Richard Strauss en porte l'art au sommet (Don Juan, Till, Ainsi parlait Zarathoustra). C'est une forme emblématiquement romantique." },

  // ── TOPIC 4 : Identification de l'impressionnisme ─────────────────────────
  { q: "Le 'planing' harmonique est une technique associée à :", opts: ["Bach et le contrepoint strict", "L'impressionnisme de Debussy et Ravel — mouvement parallèle de tous les intervalles d'un accord", "Le romantisme de Wagner", "La période classique"], a: 1, fb: "Le planing (ou mouvement parallèle) consiste à déplacer un accord entier par mouvement parallèle — toutes les voix bougent dans le même sens du même intervalle. Bach l'interdit (quintes parallèles = faute). Debussy en fait une technique délibérée : les accords glissent comme des taches de couleur, sans résolution fonctionnelle." },
  { q: "La gamme par tons entiers (Do–Ré–Mi–Fa#–Sol#–La#–Do) est caractéristique de :", opts: ["L'écriture baroque en mode dorien", "L'impressionnisme de Debussy — elle crée une ambiguïté tonale totale, sans sensible ni sous-tonique", "La période classique viennoise", "Le chromatisme romantique de Wagner"], a: 1, fb: "La gamme par tons entiers est une gamme à 6 sons dont chaque degré est séparé d'un ton entier. Sans demi-ton, elle n'a pas de sensible ni de sous-tonique — impossible d'y trouver une tonique claire. Debussy l'utilise pour créer des atmosphères flottantes et des couleurs harmoniques ambiguës, sans tension-résolution fonctionnelle." },
  { q: "Les modes médiévaux (dorien, phrygien, lydien, mixolydien) reviennent en faveur avec :", opts: ["Bach et le baroque tardif", "Le classicisme de Mozart", "L'impressionnisme et la musique de Debussy et Ravel", "Wagner et le romantisme tardif"], a: 2, fb: "Debussy et Ravel redécouvrent les modes médiévaux pour échapper à la tonalité majeur-mineur et ses fonctions obligatoires. Le mode dorien (sans sous-tonique rehaussée), le phrygien (sensible abaissée), le lydien (quarte augmentée), le mixolydien (7e abaissée) offrent des couleurs nouvelles. Ces modes reviennent aussi dans le jazz et la musique du XXe siècle." },
  { q: "Comment Debussy utilise-t-il les accords par rapport à la tension-résolution classique ?", opts: ["Il renforce la tension-résolution V–I avec plus de dissonances que le classicisme", "Ses accords sont des taches de couleur qui progressent par couleur et registre — la tension-résolution fonctionnelle est abandonnée", "Il utilise uniquement la cadence plagale IV–I", "Il résout toutes les dissonances vers I selon les règles classiques"], a: 1, fb: "Pour Debussy, un accord n'est pas une fonction dans un système de tension-résolution — c'est une couleur sonore. Les accords de 9e, 11e, 13e ne 'résolvent' pas ; ils glissent vers d'autres couleurs. Cette pensée harmonicochromatique plutôt que fonctionnelle est la révolution impressionniste : la couleur prime sur la fonction." },
  { q: "La gamme pentatonique (Do–Ré–Mi–Sol–La–Do, sans Fa ni Si) est utilisée par Debussy pour :", opts: ["Renforcer la cadence V–I en éliminant la sous-dominante", "Créer des atmosphères exotiques et flottantes, influencées par la musique asiatique (gamelan javanais entendu à l'Exposition universelle de 1889)", "Simplifier l'harmonie pour les débutants", "Retrouver la pureté de la musique baroque"], a: 1, fb: "Debussy découvre le gamelan javanais à l'Exposition universelle de Paris en 1889 — il est fasciné par ses sonorités exotiques basées sur la pentatonique. La gamme pentatonique (5 sons sans demi-tons) crée une atmosphère flottante et suspendue. Cette influence orientale nourrit son impressionnisme : La cathédrale engloutie, Estampes." },
  { q: "Ravel (1875–1937) et Debussy sont souvent associés à l'impressionnisme. Quelle différence stylistique majeure les distingue ?", opts: ["Ravel utilise la gamme par tons, Debussy uniquement la pentatonique", "Ravel conserve une logique formelle plus classique et un contrepoint plus rigoureux ; Debussy est plus libre et flottant dans ses formes", "Les deux sont stylistiquement identiques", "Debussy est plus classique, Ravel plus impressionniste"], a: 1, fb: "Malgré leur association, Ravel et Debussy diffèrent : Ravel maintient une logique formelle plus nette (notamment dans ses formes sonate), un contrepoint plus rigoureux, une architecture plus claire. Debussy est plus libre dans ses formes, plus flottant dans ses progressions. Ravel lui-même affirmait ne pas être 'impressionniste'." },
  { q: "Dans l'impressionnisme musical, le titre d'une pièce (La cathédrale engloutie, La mer, Jeux d'eau) suggère :", opts: ["Un programme dramatique comme les opéras de Wagner", "Des impressions sensorielles, des images évocatrices plutôt qu'une narration — la musique peint une atmosphère", "Une référence à une forme classique abstraite", "Un thème religieux uniquement"], a: 1, fb: "Les titres impressionnistes évoquent des impressions sensorielles, des lumières, des reflets, des textures — non des drames ou des récits. La mer de Debussy n'est pas une tempête narrative (comme Beethoven op.110) — c'est une impression de la mer à différents moments. L'inspiration vient de la peinture impressionniste (Monet) : saisir l'instant, la lumière, pas l'objet." },
  { q: "Les quintes et octaves parallèles sont-elles permises dans l'harmonie impressionniste ?", opts: ["Non — les règles de contrepoint strict s'appliquent toujours", "Oui — c'est même une technique délibérée (planing) chez Debussy", "Oui, uniquement à distance d'octave", "Non, mais les quintes sont autorisées si le mouvement est contraire"], a: 1, fb: "Les quintes et octaves parallèles sont interdites en contrepoint classique et baroque. Debussy les utilise délibérément comme technique expressive — le planing crée cet effet de couleurs glissantes. Ce qui est une faute dans un style (baroque, classique) est une technique dans un autre (impressionnisme). Le contexte historique est déterminant." },
  { q: "Pour identifier une œuvre impressionniste, quel trio de critères est le plus pertinent ?", opts: ["Basse continue + fugue + cadences fréquentes", "Phrases symétriques + cadences V–I affirmées + basse d'Alberti", "Accords parallèles (planing) + modes/gamme par tons/pentatonique + absence de résolution fonctionnelle V–I", "Chromatisme dense + modulations par tierces + accords altérés"], a: 2, fb: "L'impressionnisme se reconnaît à trois critères : (1) accords parallèles (planing) sans résolution fonctionnelle, (2) utilisation de modes, gamme par tons et pentatonique, (3) absence ou dissolution de la cadence V–I fonctionnelle. Ce triptique le distingue nettement du romantisme (chromatisme fonctionnel) et du classicisme (fonctions claires)." },
  { q: "Qu'est-ce qui distingue le chromatisme romantique du chromatisme impressionniste ?", opts: ["Il n'y a aucune différence entre les deux", "Le romantisme utilise le chromatisme pour créer des tensions fonctionnelles résolues ; l'impressionnisme utilise des couleurs non fonctionnelles (modes, tons entiers) sans tension-résolution obligatoire", "L'impressionnisme est plus chromatique que le romantisme", "Le romantisme évite le chromatisme"], a: 1, fb: "La distinction est fondamentale : le chromatisme romantique (Wagner, Chopin) crée des tensions fonctionnelles qui réclament une résolution — les altérations s'inscrivent dans un système tension-résolution. L'impressionnisme (Debussy) utilise des couleurs non fonctionnelles — modes, gamme par tons, pentatonique — sans tension-résolution obligatoire. Ce n'est pas 'plus de chromatisme', c'est un usage radicalement différent." },

  // ── TOPIC 5 : Comparaison stylistique ────────────────────────────────────
  { q: "La même mélodie Do–Mi–Sol–Do harmonisée 'à la Bach' et 'à la Debussy' diffère principalement par :", opts: ["Le tempo utilisé pour la jouer", "Le traitement de la dominante : Bach l'affirme obligatoirement (V–I) ; Debussy peut l'ignorer totalement", "La mélodie elle-même qui change selon le style", "L'instrument utilisé"], a: 1, fb: "La différence fondamentale entre une harmonisation baroque et une impressionniste réside dans le traitement de la dominante. Bach structure obligatoirement son discours autour de V–I. Debussy peut harmoniser la même mélodie avec des accords de 9e en parallèles, sans aucune résolution V–I — la mélodie est la même, l'harmonie est dans un univers radicalement différent." },
  { q: "Quel compositeur utilise systématiquement des cadences parfaites (V–I) affirmées ?", opts: ["Debussy", "Mozart", "Webern", "Messiaen"], a: 1, fb: "Mozart est l'incarnation du style classique avec des cadences parfaites V–I fréquentes et bien affirmées, structurant les phrases de 4+4 mesures. Debussy évite ces cadences fonctionnelles. Webern et Messiaen appartiennent au XXe siècle et utilisent des langages post-tonals." },
  { q: "Quel compositeur est le plus connu pour ses modulations par tierce (ex. Do majeur → Lab majeur) ?", opts: ["Bach", "Mozart", "Schubert", "Debussy"], a: 2, fb: "Schubert est célèbre pour ses modulations par tierce — un de ses traits stylistiques les plus reconnaissables. Dans ses lieder et sonates, il glisse fréquemment vers des tonalités à distance de tierce (majeure ou mineure), créant des changements de couleur soudains et poétiques. Bach module par quintes ; Mozart vers les tonalités proches ; Debussy évite les fonctions modulantes." },
  { q: "Quel compositeur est associé au concept de 'mélodie infinie' (flux continu évitant les cadences conclusives) ?", opts: ["Haydn", "Chopin", "Wagner", "Vivaldi"], a: 2, fb: "Wagner invente le concept de mélodie infinie (unendliche Melodie) pour ses drames musicaux : le flux orchestral et vocal évite les cadences conclusives, créant une tension soutenue sans résolution. C'est l'opposé de la symétrie classique de 4+4 mesures. Haydn et Vivaldi vivent dans un monde de phrases cadencées régulièrement." },
  { q: "Quel compositeur est connu pour la basse d'Alberti (fondamentale–quinte–tierce–quinte répété) ?", opts: ["Bach et le contrepoint", "Mozart et le style classique viennois", "Debussy et l'impressionnisme", "Wagner et le romantisme tardif"], a: 1, fb: "La basse d'Alberti est une signature du style classique viennois, particulièrement de Mozart. Cette formule d'accompagnement omniprésente dans ses sonates pour piano remplace le contrepoint baroque par un accompagnement homophonique régulier. Debussy s'en éloigne radicalement ; Bach ne l'utilise jamais." },
  { q: "Une pièce qui utilise des modes grecs (dorien, lydien, mixolydien) et des accords parallèles est probablement :", opts: ["Une fugue baroque de Bach", "Une sonate classique de Haydn", "Une œuvre impressionniste de Debussy ou Ravel", "Un lied romantique de Schubert"], a: 2, fb: "Les modes grecs et les accords parallèles (planing) sont des signatures impressionnistes. Bach et Haydn n'utilisent pas de modes grecs dans leur harmonie — ils travaillent dans le système majeur/mineur. Schubert utilise parfois le mode dorien mais sans parallélismes. Debussy combine délibérément modes, gamme par tons et planing." },
  { q: "Une pièce qui utilise intensément le triton comme tension non résolue est caractéristique de :", opts: ["L'harmonie classique de Mozart (le triton est toujours résolu)", "Le romantisme tardif de Wagner où les dissonances restent non résolues longtemps", "La musique baroque où le triton est strictement interdit", "La gamme pentatonique qui contient de nombreux tritons"], a: 1, fb: "Le triton (diabolus in musica) doit être résolu en musique classique et baroque. Wagner dans Tristan utilise le triton de façon récurrente en laissant sa résolution suspendue pendant de longues durées — une audace harmonique symbolisant le désir non assouvi. La gamme pentatonique ne contient pas de triton (c'est justement pourquoi elle sonne 'douce')." },
  { q: "Quel style harmonique n'utilise PAS la progression V–I comme cadence structurante ?", opts: ["Le baroque de Bach", "Le classicisme de Mozart", "Le romantisme de Schubert", "L'impressionnisme de Debussy"], a: 3, fb: "Bach, Mozart et Schubert (dans leur écriture tonale) utilisent tous la progression V–I comme cadence structurante fondamentale. Debussy abandonne délibérément ce principe : ses accords progressent par couleur et registre, non par tension-résolution. Chercher des cadences V–I fonctionnelles dans l'impressionnisme, c'est appliquer le mauvais outil analytique." },
  { q: "Un accord de 9e majeure non résolu, suivi d'un accord de 9e un demi-ton plus haut (planing), est caractéristique de :", opts: ["Une fugue baroque", "Une sonate classique", "L'impressionnisme de Debussy", "Un lied romantique de Brahms"], a: 2, fb: "Le planing d'accords complexes (9e, 11e, 13e) sans résolution est une technique impressionniste typique. Un accord de 9e majeure qui glisse par demi-ton vers un autre accord de 9e n'a aucun sens dans le système tension-résolution classique ou romantique — c'est du mouvement par couleur, pas par fonction. C'est Debussy en action." },
  { q: "Analyser 'les Préludes pour piano' de Debussy avec les fonctions T/SD/D est :", opts: ["Pertinent — Debussy utilise les fonctions tonales classiques malgré ses dissonances", "Contre-productif — ses accords sont des couleurs, non des fonctions ; l'analyse modale et timbrale est plus adaptée", "Obligatoire pour tout analyse harmonique sérieuse", "Approprié uniquement pour les préludes baroques"], a: 1, fb: "Appliquer les fonctions T/SD/D à Debussy, c'est utiliser le mauvais outil : ses accords ne fonctionnent pas comme des tensions vers une résolution. Une analyse pertinente des Préludes de Debussy examine les modes utilisés, les parallélismes, les couleurs timbriques, les rapports de registre — non les 'dominantes' et 'sous-dominantes' fonctionnelles." },
  { q: "Pour identifier la période d'une œuvre en 3 indices, on doit examiner :", opts: ["Le pays du compositeur, l'instrument utilisé et la longueur de la pièce", "La densité du chromatisme, la présence ou absence de résolution V–I, et le traitement des dissonances", "Le tempo, la nuance et l'articulation uniquement", "Le nombre de mouvements, la tonalité et le compositeur"], a: 1, fb: "Les trois indices les plus révélateurs de la période historique d'une œuvre : (1) densité du chromatisme (faible=baroque/classique, moyen=romantique, par couleur=impressionnisme), (2) présence/absence de V–I (obligatoire=baroque/classique, évité=romantisme tardif, inexistant=impressionnisme), (3) traitement des dissonances (résolution immédiate=baroque, prolongée=romantisme, non résolue=impressionnisme)." },
  { q: "Quel compositeur 'connaissait parfaitement les règles qu'il transgressait' — illustrant que la liberté requiert la maîtrise préalable ?", opts: ["Bach — qui ignorait les règles modales pour créer librement", "Debussy — dont la liberté impressionniste repose sur une parfaite maîtrise du contrepoint et de l'harmonie classique", "Mozart — qui transgressait les règles de la sonate classique", "Haendel — dont les quintes parallèles sont volontaires"], a: 1, fb: "Debussy illustre parfaitement le paradoxe de la liberté créatrice : il a étudié le contrepoint et l'harmonie classique au Conservatoire de Paris (prix de Rome 1884), maîtrisant parfaitement les règles qu'il allait transgresser. Sa liberté apparente est calculée — pas une ignorance. Pour s'affranchir des règles, il faut d'abord les maîtriser." },
  { q: "Le post-romantisme (Wagner tardif, Mahler, Richard Strauss) se distingue du romantisme par :", opts: ["L'abandon du chromatisme et le retour au diatonisme classique", "Un chromatisme encore plus dense, des accords de 9e–11e–13e, une tonalité présente mais élargie et de longues tensions maintenues", "L'utilisation de la gamme par tons et du planing impressionniste", "La structure en fugue contrapuntique"], a: 1, fb: "Le post-romantisme amplifie le romantisme : chromatisme total (toutes les 12 notes peuvent apparaître dans un court extrait), accords de 9e, 11e, 13e non résolus longuement, tonalité maintenue mais mise sous tension extrême. C'est la tonalité à son point limite avant l'atonalisme — Mahler et Strauss sont dans cet espace entre romantisme et modernisme." },
  { q: "Si une œuvre a des cadences claires V–I mais aussi des accords de dominante secondaire et quelques modulations par tierces, elle est probablement :", opts: ["Strictement baroque", "Du romantisme (Schubert, début Chopin) — les fonctions tonales restent mais s'enrichissent de chromatisme expressif", "De l'impressionnisme pur", "Du classicisme strict de Haydn"], a: 1, fb: "Cette description correspond au romantisme modéré (Schubert, premier Chopin) : les fonctions tonales V–I restent présentes et structurantes, mais enrichies de chromatisme expressif, modulations par tierces, dominantes secondaires. Ce n'est pas encore le romantisme tardif (Wagner) qui suspend longuement les résolutions. C'est la zone de transition entre classicisme et romantisme avancé." },
];

const questionsEn: Question[] = [
  // ── TOPIC 1: Identifying the Baroque period ───────────────────────────────
  { q: "Which technique is characteristic of the Baroque basso continuo?", opts: ["A bass that imitates the soprano", "A figured bass played by a continuo group (harpsichord, lute, organ) supporting the melody", "A bass that falls silent at cadences", "A bass played only by strings"], a: 1, fb: "The basso continuo is the foundation of the Baroque style: a harmonic realization played by accompanying instruments (harpsichord, theorbo, organ) while the melody is entrusted to other voices. It is one of the most reliable criteria for identifying the Baroque." },
  { q: "How do you recognize a typically Baroque cadence?", opts: ["The cadence is avoided or suspended — the Baroque prefers half cadences", "The cadence is frequent, affirmed, often with ornaments (trill on the leading tone)", "The Baroque uses only the plagal cadence IV–I", "Baroque cadences never fall on a strong beat"], a: 1, fb: "The Baroque style favors frequent and clearly affirmed cadences. The authentic cadence V–I with a trill on the leading tone (Baroque cadential notation) is a signature of the period. These cadences punctuate the discourse regularly, structuring the ritornellos." },
  { q: "Strict counterpoint (the presence of several independent voices) is characteristic of:", opts: ["The Classical period only", "Impressionism", "The Baroque period (Bach, Handel, Vivaldi)", "Late Romanticism"], a: 2, fb: "Counterpoint — the art of making several independent voices coexist according to strict rules — is at the heart of Baroque writing. Bach's fugues, inventions, and canons illustrate this mastery. The Classical period simplifies the writing toward accompanied melody." },
  { q: "Which form is emblematic of Baroque contrapuntal writing?", opts: ["Beethoven's sonata", "The fugue — exposition of a subject developed by imitation between voices", "Wagner's opera", "Debussy's prelude"], a: 1, fb: "The fugue is the contrapuntal form par excellence of the Baroque. A subject is presented alone, then imitated by all voices according to strict rules of entry and answer. Bach brought this art to its peak in the Well-Tempered Clavier and The Art of Fugue." },
  { q: "In the Baroque style, the tonal functions I–IV–V are:", opts: ["Absent — the Baroque does not use tonal functions", "Present but vague — modality still dominates", "Clearly established and frequently affirmed by cadences", "Reserved for final cadences only"], a: 2, fb: "Unlike the earlier modal periods, the Baroque clearly establishes the tonal functions I, IV, V with frequent and affirmed cadences. Bach and Handel systematically structure their discourse around the tonic, dominant, and subdominant." },
  { q: "Bach (1685–1750) and Handel (1685–1759) are contemporaries. This fact illustrates:", opts: ["That the two composers had the same style", "That even in the same period, two composers can have very distinct individual styles", "That the Baroque is a very short period", "That all Baroque composers are identifiable by exactly the same characteristics"], a: 1, fb: "Bach and Handel are strictly contemporary but stylistically different: Bach cultivates complex counterpoint and Lutheran introspection; Handel writes Italian operas and spectacular oratorios. The period provides a framework, but individual signature always takes precedence." },
  { q: "The harpsichord is the emblematic keyboard instrument of the Baroque. Why is it different from the piano?", opts: ["It has fewer keys", "Sound is produced by plucking the strings (no dynamic nuance from touch) — the piano produces sound by striking and allows dynamic variation", "It no longer exists since the Classical period", "It sounds exactly like a piano but higher"], a: 1, fb: "The harpsichord produces its sound by plucking strings via a plectrum — the volume is constant regardless of finger pressure. The piano (fortepiano then pianoforte) introduced in the Classical period allows varying intensity by touch. This difference explains the frequent Baroque ornaments compensating for the impossibility of a crescendo." },
  { q: "In Baroque music, ornamentation (trills, mordents, appoggiaturas) has as its main role:", opts: ["Decorating the melody arbitrarily to make it more complex", "Replacing the dynamic nuances impossible on harpsichord, articulating dissonances and marking cadences", "Indicating the key to the audience", "Replacing missing notes from the scale"], a: 1, fb: "Baroque ornamentation is functional: on harpsichord (no dynamic nuances), trills extend sounds and mark strong beats; mordents and appoggiaturas create expressive tensions; cadential ornaments signal phrase endings. It is not decoration — it is musical syntax." },
  { q: "The Baroque 'Suite' (allemande, courante, sarabande, gigue) is characteristic of:", opts: ["The Romantic period", "The Baroque period — a series of stylized dances at different tempos and characters", "Impressionism", "The Viennese Classical period"], a: 1, fb: "The Baroque suite is a collection of stylized dances (designed for listening, not dancing): allemande (moderate), courante (fast), sarabande (slow), gigue (very fast), sometimes with other dances. Bach composed many suites for harpsichord, lute, and orchestra. It is an emblematically Baroque form." },
  { q: "The 'concerto grosso' style (Vivaldi, Handel, Corelli) contrasts:", opts: ["A soloist and a chamber orchestra alternating in dialogue", "Harpsichord and strings only", "A small group of soloists (concertino) against the full orchestra (ripieno), in alternation and dialogue", "Voice and orchestra"], a: 2, fb: "The Baroque concerto grosso contrasts two ensembles: the concertino (small group of soloists) and the ripieno (full orchestra). Their exchanges create a dialogue of sound masses typical of the Baroque. Vivaldi perfected this principle with his 500+ concertos for violin and orchestra." },
  { q: "Which criterion most reliably identifies a work from the Baroque period?", opts: ["The presence of electric guitar", "Basso continuo, strict counterpoint, and frequent affirmed cadences", "Total absence of chromaticism", "Seventh chords always left unresolved"], a: 1, fb: "Three combined criteria identify the Baroque: (1) basso continuo with harmonic figures, (2) counterpoint between independent voices, (3) frequent and clearly affirmed cadences with ornaments. No single criterion is sufficient, but their combination is characteristic." },

  // ── TOPIC 2: Identifying the Classical period ─────────────────────────────
  { q: "The 'Alberti bass' is a typical accompaniment of the Classical period. It consists of:", opts: ["A contrapuntal bass in strict counterpoint", "A broken arpeggio of three notes: root – fifth – third – fifth, repeated", "A chromatically rising bass", "A figured basso continuo"], a: 1, fb: "The Alberti bass is a very characteristic accompaniment formula of the Viennese Classical style: alternating root – high note – third – high note in a regular motion. Mozart and Haydn use it abundantly in their sonatas and symphonies. Its name comes from composer Domenico Alberti." },
  { q: "Symmetrical phrases (periods of 4+4 measures) are characteristic of:", opts: ["Baroque improvisation", "The Viennese Classical period (Mozart, Haydn)", "Debussy's Impressionism", "Wagner's late Romanticism"], a: 1, fb: "The Viennese Classical style systematically structures music in symmetrical phrases of 4+4 measures: a proposition (antecedent) and a response (consequent). This symmetry creates a very perceptible formal logic, very different from continuous Baroque counterpoint or the Romantic flow." },
  { q: "How are cadences used in the Classical period compared to the Baroque?", opts: ["Classical cadences are more ambiguous and avoided — Classicism prefers continuity", "They are clear, well affirmed, and structure phrases symmetrically — similar to the Baroque but in a more homophonic context", "Cadences disappear in Classicism", "Classical cadences are always plagal (IV–I)"], a: 1, fb: "Classicism maintains clear and affirmed cadences, but in a more homophonic context than the Baroque. Perfect cadences V–I structure the 4+4 measure phrases in a very readable way. This systematic cadential clarity differs from Romanticism (avoided cadences) and Impressionism (absent cadences)." },
  { q: "The Classical sonata (sonata Allegro) presents a characteristic structure:", opts: ["Theme A repeated indefinitely", "Exposition (2 themes) – Development – Recapitulation: opposition and resolution of tonal tensions", "Introduction – Aria – Recitative – Coda only", "Continuous variations on a bass theme"], a: 1, fb: "The Classical sonata form follows a tripartite scheme: Exposition (main theme I, modulating bridge, secondary theme V or III), Development (harmonic exploration, fragmentation), Recapitulation (return of both themes in I). This principle of tonal opposition (I vs V) then resolution defines the Classical aesthetic." },
  { q: "Mozart (1756–1791) and Haydn (1732–1809) represent:", opts: ["The avant-garde of their time, misunderstood by their contemporaries", "The heart of Viennese Classicism — formal balance, harmonic clarity, melodic elegance", "Late Baroque, continuers of Bach", "Direct precursors of Impressionism"], a: 1, fb: "Mozart and Haydn embody the Classical ideal: balance between form and expression, harmonic clarity around functions I–IV–V, economy of means (no unnecessary chromaticism), melodic elegance. Their works define the stylistic standard to which analysis refers when identifying Classicism." },
  { q: "Harmony in the Viennese Classical style is characterized by:", opts: ["Chromatic saturation and frequent modulations by thirds", "Harmonic economy — few chords (mainly I, IV, V, II, VI) used with clarity and functional logic", "Total absence of secondary dominants", "Systematic ninths, elevenths, and thirteenth chords"], a: 1, fb: "The Viennese Classical style is distinguished by its harmonic economy: Mozart and Haydn use mainly I, IV, V and their inversions, with a few targeted secondary dominants. No excessive chromaticism — functional clarity takes precedence. This balance distinguishes it from overloaded Romanticism." },
  { q: "In a Classical minuet, the typical form is:", opts: ["Theme – Variations – Coda", "A (minuet) – B (trio) – A (da capo) with internal structure of 8+8 measures", "4-voice Fugue – Stretto – Finale", "Introduction – Allegro – Finale"], a: 1, fb: "The Classical minuet follows the ternary form A–B–A (da capo): the main minuet, a contrasting trio (often in the dominant or relative key), then return of the minuet. Each section is itself structured in 8+8 symmetrical measures. It is a very recognizable Classical form." },
  { q: "How do you stylistically recognize a Classical string quartet?", opts: ["By the presence of a continuo harpsichord in the bass", "By four voices in mainly homophonic writing, with thematic exchanges between instruments, without basso continuo", "By the systematic presence of an independent contrapuntal bass voice", "By the absence of cello"], a: 1, fb: "The Classical quartet (2 violins, viola, cello) abandons the Baroque basso continuo in favor of dialogue among the four voices. The writing is often homophonic with dialogued passages — far from Baroque counterpoint. Haydn founded the form; Mozart and Beethoven perfected it." },
  { q: "Beethoven (1770–1827) is often placed at the junction of Classicism and Romanticism. What places him there?", opts: ["He composes exclusively Baroque fugues", "He begins in the Viennese Classical style but progressively introduces dramatic expression, increased chromaticism, and enlarged forms", "He never uses Classical functions I–IV–V", "His style is identical to Mozart's"], a: 1, fb: "Beethoven departs from the Classicism inherited from Haydn and Mozart but progressively stretches it: elongated forms (symphonies 20-45 min), increased expressive chromaticism, radical dynamic contrasts (pp subito ff), more complex harmonic structures. His last works (op. 130-135) foreshadow Romanticism and even Modernism." },
  { q: "To identify a Viennese Classical style, which trio of criteria is most relevant?", opts: ["Basso continuo + fugue + avoided cadences", "Symmetrical 4+4 phrases + economical harmony + affirmed perfect cadences", "Total chromaticism + modulations by thirds + altered chords", "Greek modes + parallelisms + absence of V–I resolution"], a: 1, fb: "The Viennese Classical style is recognized by three combined criteria: (1) symmetrical phrases in 4+4 measures with antecedent-consequent, (2) economical harmony around I, IV, V, (3) clearly affirmed perfect cadences structuring the phrases. This triptych contrasts with Baroque counterpoint and Romantic chromaticism." },
  { q: "In the Classical period, modulations are made mainly:", opts: ["To very distant keys (third, mediant)", "To the dominant (V) or relative minor/major — neighboring keys at ±1 sharp/flat", "To the tritone (tritone substitution)", "Modulations are absent in the Classical period"], a: 1, fb: "Classicism modulates mainly to nearby keys: dominant (V), relative minor or major, subdominant key. These modulations are clearly affirmed by cadences in the new key. Distant modulations (by thirds) arrive with Romanticism." },

  // ── TOPIC 3: Identifying Romanticism ─────────────────────────────────────
  { q: "Romantic chromaticism is characterized by:", opts: ["Exclusive use of the diatonic scale without any alteration", "Frequent chromatic alterations that enrich and color the harmony without necessarily modulating", "Systematic parallel fifths", "Total absence of the leading tone"], a: 1, fb: "Romantic chromaticism (Schubert, Chopin, Wagner) introduces frequent alterations that enrich the harmonic color: borrowed chords, expressive alterations, chromatic notes in melodic lines. These alterations create tensions that can remain without immediate resolution — far from Classical clarity." },
  { q: "Modulations by third (e.g., C major → E major) are characteristic of:", opts: ["Strict Baroque period", "Romanticism (Schubert, in particular)", "Impressionism only", "Viennese Classical period"], a: 1, fb: "Modulations by third (C → E, C → Ab) are a signature of Romanticism, particularly of Schubert. They bypass the Classical cycle of fifths (C → G → D...) to create surprising and colorful harmonic changes. Wagner would then use them systematically to create orchestral lighting effects." },
  { q: "The augmented sixth chord (Italian, French, or German) is typical of:", opts: ["Bach's Baroque", "The Classical period without alterations", "Romanticism — it prepares the dominant with additional chromatic tension", "Debussy's Impressionism"], a: 2, fb: "The augmented sixth chord (root + third + augmented sixth, with variants) is a Romantic technique par excellence. It prepares the dominant with a double chromatic tension: two notes converge chromatically toward V by opposite semitones. Schubert, Chopin, and Brahms use it regularly." },
  { q: "Wagner (1813–1883) is known for the use of the Tristan chord (opening of Tristan und Isolde, 1859). Why is it revolutionary?", opts: ["Because it avoids all dissonance", "Because it is deeply tonally ambiguous — its multiple possible resolutions call into question functional tonality", "Because it uses only the whole-tone scale", "Because it resolves immediately to I"], a: 1, fb: "The Tristan chord (F–B–D#–G#) is revolutionary by its tonal ambiguity: it can be analyzed as a half-diminished seventh chord, a French augmented sixth chord, or something else depending on context. Its suspended resolution throughout the overture symbolizes unfulfilled desire — and inaugurates the collapse of tonality." },
  { q: "Wagner's leitmotif is:", opts: ["A Baroque technique of basso continuo", "A musical motif associated with a character, idea, or feeling, transformed throughout the opera", "A Classical sonata form", "A melodic ornament typical of Romanticism"], a: 1, fb: "The leitmotif (leading motif) is a narrative technique invented by Wagner: a short melodico-harmonic motif is associated with a dramatic element (character, object, feeling) and returns transformed throughout the work. This technique influences all contemporary film music — John Williams draws directly from it." },
  { q: "Chopin (1810–1849) is famous for his Romantic piano harmonies. What characterizes them?", opts: ["Rigid functional I–IV–V without deviations", "A chromatic richness, expressive appoggiaturas, harmonic pedal points, and a poetic use of borrowed chords", "Total absence of modulation", "Purely fugue-like contrapuntal writing"], a: 1, fb: "Chopin innovates through his pianistic harmonic richness: long and expressive appoggiaturas, harmonic pedal points (held notes under changing harmonies), unexpected modulations, borrowed chords (bVI in major), melodic chromaticism. His Nocturnes are a living dictionary of Romantic harmony." },
  { q: "Wagner's 'infinite melody' (unendliche Melodie) is defined as:", opts: ["A melody that repeats exactly infinitely", "A continuous melodic flow that avoids conclusive cadences and symmetrical phrases, creating sustained tension", "A melody played only by violins without accompaniment", "A melody in Dorian mode without cadence"], a: 1, fb: "Wagnerian infinite melody refuses conclusive cadences and Classical symmetrical phrases. The musical flow is continuous, tensions remain unresolved for long durations. It is the opposite of the Classical 4+4 measure phrase — a permanent suspension that generates the desire and expectation proper to Wagnerian drama." },
  { q: "Schubert (1797–1828) is famous for his lieder (songs for voice and piano). What characterizes them harmonically?", opts: ["Simple Classical harmony I–IV–V without deviations", "Unexpected modulations, borrowings from minor in major (bVI, bVII), expressive chromaticism in service of the poetic text", "Total absence of harmonic pedal point", "Exclusive plagal cadences"], a: 1, fb: "Schubert's lieder are harmonically innovative for his time: modulations to distant keys (by thirds), constant borrowings from parallel minor (bVI, bVII in major), melodic and harmonic chromaticism. The entire harmonic discourse serves the text — music illustrates and amplifies the poetic images." },
  { q: "The growing tonal ambiguity of late Romanticism (Wagner, Liszt) leads toward:", opts: ["A return to strict Baroque", "Twentieth-century atonalism — tonality gradually fades as dissonances cease to resolve", "Haydn's Viennese Classicism", "Only Debussy's Impressionism"], a: 1, fb: "Late Romanticism (Wagner's Tristan, Liszt's Symphonic Poems, late Brahms) pushes tonality to its limits: increasingly long unresolved dissonances, modulations to distant keys, ambiguity of the tonal center. This evolution leads directly to Schoenberg and atonalism — tonality can no longer sustain itself." },
  { q: "To identify a Romantic work, which trio of criteria is most relevant?", opts: ["Basso continuo + fugue + nearby modulations", "Symmetrical phrases + economical harmony + Alberti bass", "Expressive chromaticism + modulations by thirds + altered chords (bVI, augmented sixths)", "Parallelisms + Greek modes + absence of V–I"], a: 2, fb: "Romanticism is recognized by three criteria: (1) frequent expressive chromaticism, (2) modulations by thirds or to distant keys, (3) altered and borrowed chords (bVI in major, Neapolitan sixth, augmented sixths). This harmonic chromaticism clearly distinguishes it from economical Classicism and colorist Impressionism." },
  { q: "The form of the symphonic poem (Liszt, Strauss) is characteristic of:", opts: ["The Baroque period — it is a suite of dances", "Romanticism — an orchestral work in a single movement with a literary or pictorial program", "The Classical period — it is a symphony in 4 movements", "Impressionism — it is an atonal piece"], a: 1, fb: "The symphonic poem (a term coined by Liszt) is an orchestral work in a single movement inspired by an extramusical program (poem, painting, mythological story). Liszt composed a dozen; Richard Strauss brought the art to its peak (Don Juan, Till Eulenspiegel, Thus Spoke Zarathustra). It is an emblematically Romantic form." },

  // ── TOPIC 4: Identifying Impressionism ────────────────────────────────────
  { q: "'Planing' is a technique associated with:", opts: ["Bach and strict counterpoint", "Debussy and Ravel's Impressionism — parallel motion of all intervals of a chord", "Wagner's Romanticism", "The Classical period"], a: 1, fb: "Planing (or parallel motion) consists of moving an entire chord in parallel motion — all voices move in the same direction by the same interval. Bach forbids it (parallel fifths = error). Debussy makes it a deliberate technique: chords slide like patches of color, without functional resolution." },
  { q: "The whole-tone scale (C–D–E–F#–G#–A#–C) is characteristic of:", opts: ["Baroque writing in Dorian mode", "Debussy's Impressionism — it creates total tonal ambiguity, without leading tone or subtonic", "Viennese Classical period", "Wagner's Romantic chromaticism"], a: 1, fb: "The whole-tone scale is a 6-note scale where each degree is separated by a whole step. Without semitones, it has no leading tone or subtonic — impossible to find a clear tonic in it. Debussy uses it to create floating atmospheres and ambiguous harmonic colors, without functional tension-resolution." },
  { q: "Medieval modes (Dorian, Phrygian, Lydian, Mixolydian) come back into favor with:", opts: ["Bach and late Baroque", "Mozart's Classicism", "Impressionism and the music of Debussy and Ravel", "Wagner and late Romanticism"], a: 2, fb: "Debussy and Ravel rediscover medieval modes to escape major-minor tonality and its obligatory functions. Dorian mode (no raised subtonic), Phrygian (lowered leading tone), Lydian (augmented fourth), Mixolydian (lowered seventh) offer new colors. These modes also return in jazz and twentieth-century music." },
  { q: "How does Debussy use chords compared to Classical tension-resolution?", opts: ["He reinforces V–I tension-resolution with more dissonances than Classicism", "His chords are patches of color that progress by color and register — functional tension-resolution is abandoned", "He uses only the plagal cadence IV–I", "He resolves all dissonances to I according to Classical rules"], a: 1, fb: "For Debussy, a chord is not a function in a tension-resolution system — it is a sound color. Ninth, eleventh, thirteenth chords do not 'resolve'; they slide toward other colors. This harmonic-chromatic rather than functional thinking is the Impressionist revolution: color takes precedence over function." },
  { q: "The pentatonic scale (C–D–E–G–A–C, without F or B) is used by Debussy to:", opts: ["Reinforce the V–I cadence by eliminating the subdominant", "Create exotic and floating atmospheres, influenced by Asian music (Javanese gamelan heard at the 1889 World Exhibition)", "Simplify harmony for beginners", "Recover the purity of Baroque music"], a: 1, fb: "Debussy discovers the Javanese gamelan at the Paris World Exhibition in 1889 — he is fascinated by its exotic sounds based on the pentatonic scale. The pentatonic scale (5 notes without semitones) creates a floating and suspended atmosphere. This oriental influence nourishes his Impressionism: La cathédrale engloutie, Estampes." },
  { q: "Ravel (1875–1937) and Debussy are often associated with Impressionism. What major stylistic difference distinguishes them?", opts: ["Ravel uses the whole-tone scale, Debussy only the pentatonic", "Ravel maintains a more Classical formal logic and more rigorous counterpoint; Debussy is freer and more floating in his forms", "The two are stylistically identical", "Debussy is more Classical, Ravel more Impressionist"], a: 1, fb: "Despite their association, Ravel and Debussy differ: Ravel maintains a cleaner formal logic (notably in his sonata forms), more rigorous counterpoint, clearer architecture. Debussy is freer in his forms, more floating in his progressions. Ravel himself claimed not to be 'Impressionist.'" },
  { q: "In musical Impressionism, the title of a piece (La cathédrale engloutie, La mer, Jeux d'eau) suggests:", opts: ["A dramatic program like Wagner's operas", "Sensory impressions, evocative images rather than a narrative — the music paints an atmosphere", "A reference to an abstract Classical form", "A religious theme only"], a: 1, fb: "Impressionist titles evoke sensory impressions, lights, reflections, textures — not dramas or stories. Debussy's La mer is not a narrative storm (like Beethoven's op.110) — it is an impression of the sea at different moments. The inspiration comes from Impressionist painting (Monet): capturing the instant, the light, not the object." },
  { q: "Are parallel fifths and octaves permitted in Impressionist harmony?", opts: ["No — the rules of strict counterpoint always apply", "Yes — it is even a deliberate technique (planing) in Debussy", "Yes, but only at the octave distance", "No, but fifths are allowed if the motion is contrary"], a: 1, fb: "Parallel fifths and octaves are forbidden in Classical and Baroque counterpoint. Debussy uses them deliberately as an expressive technique — planing creates this effect of sliding colors. What is an error in one style (Baroque, Classical) is a technique in another (Impressionism). Historical context is decisive." },
  { q: "To identify an Impressionist work, which trio of criteria is most relevant?", opts: ["Basso continuo + fugue + frequent cadences", "Symmetrical phrases + affirmed V–I cadences + Alberti bass", "Parallel chords (planing) + modes/whole-tone/pentatonic scales + absence of functional V–I resolution", "Dense chromaticism + modulations by thirds + altered chords"], a: 2, fb: "Impressionism is recognized by three criteria: (1) parallel chords (planing) without functional resolution, (2) use of modes, whole-tone scale, and pentatonic, (3) absence or dissolution of the functional V–I cadence. This triptych clearly distinguishes it from Romanticism (functional chromaticism) and Classicism (clear functions)." },
  { q: "What distinguishes Romantic chromaticism from Impressionist chromaticism?", opts: ["There is no difference between the two", "Romanticism uses chromaticism to create functional tensions that are resolved; Impressionism uses non-functional colors (modes, whole tones) without obligatory tension-resolution", "Impressionism is more chromatic than Romanticism", "Romanticism avoids chromaticism"], a: 1, fb: "The distinction is fundamental: Romantic chromaticism (Wagner, Chopin) creates functional tensions that require resolution — the alterations inscribe themselves in a tension-resolution system. Impressionism (Debussy) uses non-functional colors — modes, whole-tone scale, pentatonic — without obligatory tension-resolution. It is not 'more chromaticism', it is a radically different use." },

  // ── TOPIC 5: Stylistic comparison ─────────────────────────────────────────
  { q: "The same melody C–E–G–C harmonized 'in Bach's style' and 'in Debussy's style' differs mainly in:", opts: ["The tempo used to play it", "The treatment of the dominant: Bach necessarily affirms it (V–I); Debussy can ignore it totally", "The melody itself which changes according to style", "The instrument used"], a: 1, fb: "The fundamental difference between a Baroque and an Impressionist harmonization lies in the treatment of the dominant. Bach necessarily structures his discourse around V–I. Debussy can harmonize the same melody with parallel ninth chords, without any V–I resolution — the melody is the same, the harmony is in a radically different universe." },
  { q: "Which composer systematically uses affirmed perfect cadences (V–I)?", opts: ["Debussy", "Mozart", "Webern", "Messiaen"], a: 1, fb: "Mozart is the embodiment of the Classical style with frequent and clearly affirmed V–I perfect cadences, structuring the 4+4 measure phrases. Debussy avoids these functional cadences. Webern and Messiaen belong to the twentieth century and use post-tonal languages." },
  { q: "Which composer is best known for modulations by third (e.g., C major → Ab major)?", opts: ["Bach", "Mozart", "Schubert", "Debussy"], a: 2, fb: "Schubert is famous for his modulations by third — one of his most recognizable stylistic traits. In his lieder and sonatas, he frequently slides toward keys at a third's distance (major or minor), creating sudden and poetic color changes. Bach modulates by fifths; Mozart to nearby keys; Debussy avoids modulating functions." },
  { q: "Which composer is associated with the concept of 'infinite melody' (continuous flow avoiding conclusive cadences)?", opts: ["Haydn", "Chopin", "Wagner", "Vivaldi"], a: 2, fb: "Wagner invents the concept of infinite melody (unendliche Melodie) for his music dramas: the orchestral and vocal flow avoids conclusive cadences, creating sustained tension without resolution. It is the opposite of Classical symmetry of 4+4 measures. Haydn and Vivaldi live in a world of regularly cadenced phrases." },
  { q: "Which composer is known for the Alberti bass (root–fifth–third–fifth repeated)?", opts: ["Bach and counterpoint", "Mozart and the Viennese Classical style", "Debussy and Impressionism", "Wagner and late Romanticism"], a: 1, fb: "The Alberti bass is a signature of the Viennese Classical style, particularly of Mozart. This accompaniment formula omnipresent in his piano sonatas replaces Baroque counterpoint with a regular homophonic accompaniment. Debussy moves radically away from it; Bach never uses it." },
  { q: "A piece that uses Greek modes (Dorian, Lydian, Mixolydian) and parallel chords is probably:", opts: ["A Baroque fugue by Bach", "A Classical sonata by Haydn", "An Impressionist work by Debussy or Ravel", "A Romantic lied by Schubert"], a: 2, fb: "Greek modes and parallel chords (planing) are Impressionist signatures. Bach and Haydn do not use Greek modes in their harmony — they work in the major/minor system. Schubert sometimes uses Dorian mode but without parallelisms. Debussy deliberately combines modes, whole-tone scale, and planing." },
  { q: "A piece that intensively uses the tritone as an unresolved tension is characteristic of:", opts: ["Mozart's Classical harmony (the tritone is always resolved)", "Wagner's late Romanticism where dissonances remain unresolved for a long time", "Baroque music where the tritone is strictly forbidden", "The pentatonic scale which contains many tritones"], a: 1, fb: "The tritone (diabolus in musica) must be resolved in Classical and Baroque music. Wagner in Tristan uses the tritone recurrently, leaving its resolution suspended for long durations — a harmonic audacity symbolizing unsatisfied desire. The pentatonic scale does not contain a tritone (that is precisely why it sounds 'soft')." },
  { q: "Which harmonic style does NOT use the V–I progression as a structural cadence?", opts: ["Bach's Baroque", "Mozart's Classicism", "Schubert's Romanticism", "Debussy's Impressionism"], a: 3, fb: "Bach, Mozart, and Schubert (in their tonal writing) all use the V–I progression as a fundamental structural cadence. Debussy deliberately abandons this principle: his chords progress by color and register, not by tension-resolution. Seeking functional V–I cadences in Impressionism is applying the wrong analytical tool." },
  { q: "An unresolved major ninth chord followed by another ninth chord a half step higher (planing) is characteristic of:", opts: ["A Baroque fugue", "A Classical sonata", "Debussy's Impressionism", "A Romantic lied by Brahms"], a: 2, fb: "Planing complex chords (9th, 11th, 13th) without resolution is a typical Impressionist technique. A major ninth chord sliding by a semitone to another ninth chord makes no sense in the Classical or Romantic tension-resolution system — it is movement by color, not by function. That is Debussy at work." },
  { q: "Analyzing Debussy's 'Préludes for piano' with the functions T/SD/D is:", opts: ["Relevant — Debussy uses Classical tonal functions despite his dissonances", "Counterproductive — his chords are colors, not functions; modal and timbral analysis is more appropriate", "Mandatory for any serious harmonic analysis", "Appropriate only for Baroque preludes"], a: 1, fb: "Applying T/SD/D functions to Debussy is using the wrong tool: his chords do not function as tensions toward a resolution. A relevant analysis of Debussy's Préludes examines the modes used, parallelisms, timbral colors, register relationships — not functional 'dominants' and 'subdominants.'" },
  { q: "To identify the period of a work using 3 clues, one must examine:", opts: ["The composer's country, the instrument used, and the length of the piece", "The density of chromaticism, the presence or absence of V–I resolution, and the treatment of dissonances", "Tempo, dynamic, and articulation only", "The number of movements, the key, and the composer"], a: 1, fb: "The three most revealing clues to the historical period of a work: (1) density of chromaticism (low=Baroque/Classical, medium=Romantic, by color=Impressionism), (2) presence/absence of V–I (obligatory=Baroque/Classical, avoided=late Romanticism, absent=Impressionism), (3) treatment of dissonances (immediate resolution=Baroque, prolonged=Romanticism, unresolved=Impressionism)." },
  { q: "Which composer 'knew perfectly the rules he was transgressing' — illustrating that freedom requires prior mastery?", opts: ["Bach — who ignored modal rules to create freely", "Debussy — whose Impressionist freedom rests on a perfect mastery of counterpoint and Classical harmony", "Mozart — who transgressed the rules of Classical sonata", "Handel — whose parallel fifths are intentional"], a: 1, fb: "Debussy perfectly illustrates the paradox of creative freedom: he studied counterpoint and Classical harmony at the Paris Conservatoire (Prix de Rome 1884), perfectly mastering the rules he was about to transgress. His apparent freedom is calculated — not ignorance. To break free from rules, one must first master them." },
  { q: "Post-Romanticism (late Wagner, Mahler, Richard Strauss) is distinguished from Romanticism by:", opts: ["Abandonment of chromaticism and return to Classical diatonicism", "An even denser chromaticism, ninth–eleventh–thirteenth chords, a present but expanded tonality, and long maintained tensions", "Use of the whole-tone scale and Impressionist planing", "Contrapuntal fugue structure"], a: 1, fb: "Post-Romanticism amplifies Romanticism: total chromaticism (all 12 notes may appear in a short excerpt), ninth, eleventh, thirteenth chords unresolved for long, tonality maintained but under extreme tension. It is tonality at its limit before atonalism — Mahler and Strauss inhabit this space between Romanticism and Modernism." },
  { q: "If a work has clear V–I cadences but also secondary dominant chords and a few third-modulations, it is probably:", opts: ["Strictly Baroque", "Romanticism (Schubert, early Chopin) — tonal functions remain but are enriched by expressive chromaticism", "Pure Impressionism", "Strict Classicism of Haydn"], a: 1, fb: "This description corresponds to moderate Romanticism (Schubert, early Chopin): V–I tonal functions remain present and structural, but enriched by expressive chromaticism, third-modulations, secondary dominants. This is not yet late Romanticism (Wagner) which suspends resolutions for long durations. It is the transition zone between Classicism and advanced Romanticism." },
];

const questionsEs: Question[] = [
  // ── TEMA 1: Identificación del período barroco ────────────────────────────
  { q: "¿Qué técnica es característica del bajo continuo barroco?", opts: ["Un bajo que imita al soprano", "Un bajo cifrado tocado por un continuo (clave, laúd, órgano) que sostiene la melodía", "Un bajo que enmudece en las cadencias", "Un bajo tocado únicamente por las cuerdas"], a: 1, fb: "El bajo continuo (basso continuo) es el fundamento del estilo barroco: un cifrado armónico tocado por instrumentos de acompañamiento (clave, tiorba, órgano) mientras la melodía se confía a otras voces. Es uno de los criterios más seguros para identificar el barroco." },
  { q: "¿Cómo reconocer una cadencia típicamente barroca?", opts: ["La cadencia es evitada o suspendida — el barroco prefiere las semicadencias", "La cadencia es frecuente, afirmada, a menudo con ornamentos (trino en la sensible)", "El barroco solo usa la cadencia plagal IV–I", "Las cadencias barrocas nunca caen en el tiempo fuerte"], a: 1, fb: "El estilo barroco aprecia las cadencias frecuentes y bien afirmadas. La cadencia auténtica V–I con trino en la sensible (notación cadencial barroca) es una firma de la época. Estas cadencias puntuán el discurso regularmente, estructurando los ritornelos." },
  { q: "El contrapunto riguroso (presencia de varias voces independientes) es característico de:", opts: ["El período clásico únicamente", "El impresionismo", "El período barroco (Bach, Haendel, Vivaldi)", "El romanticismo tardío"], a: 2, fb: "El contrapunto — el arte de hacer coexistir varias voces independientes según reglas estrictas — está en el corazón de la escritura barroca. Las fugas, invenciones y cánones de Bach ilustran esta maestría. El período clásico simplifica la escritura hacia una melodía acompañada." },
  { q: "¿Qué forma es emblemática de la escritura contrapuntística barroca?", opts: ["La sonata de Beethoven", "La fuga — exposición de un sujeto desarrollado por imitación entre las voces", "La ópera de Wagner", "El preludio de Debussy"], a: 1, fb: "La fuga es la forma contrapuntística por excelencia del barroco. Un sujeto se presenta solo, luego es retomado por imitación por todas las voces según reglas estrictas de entrada y respuesta. Bach llevó este arte a su cima en el Clave bien temperado y El arte de la fuga." },
  { q: "En el estilo barroco, las funciones tonales I–IV–V son:", opts: ["Ausentes — el barroco no usa funciones tonales", "Presentes pero vagas — la modalidad sigue dominando", "Claramente establecidas y frecuentemente afirmadas por cadencias", "Reservadas solo a las cadencias finales"], a: 2, fb: "A diferencia de los períodos modales anteriores, el barroco establece claramente las funciones tonales I, IV, V con cadencias frecuentes y afirmadas. Bach y Haendel estructuran su discurso de forma sistemática alrededor de la tónica, dominante y subdominante." },
  { q: "Bach (1685–1750) y Haendel (1685–1759) son contemporáneos. Este hecho ilustra:", opts: ["Que los dos compositores tenían el mismo estilo", "Que incluso en la misma época, dos compositores pueden tener estilos individuales muy distintos", "Que el barroco es un período muy corto", "Que todos los barrocos son identificables por las mismas características exactas"], a: 1, fb: "Bach y Haendel son rigurosamente contemporáneos pero estilísticamente diferentes: Bach cultiva el contrapunto complejo y la introspección luterana; Haendel escribe óperas italianas y oratorios espectaculares. La época proporciona un marco, pero la firma individual siempre prevalece." },
  { q: "El clave es el instrumento de teclado emblemático del barroco. ¿Por qué es diferente del piano?", opts: ["Tiene menos teclas", "El sonido se produce por punteo de las cuerdas (sin matiz dinámico al tacto) — el piano produce el sonido por golpe y permite los matices", "Ya no existe desde el clasicismo", "Suena exactamente como un piano pero más agudo"], a: 1, fb: "El clave produce su sonido mediante el punteo de las cuerdas con un plectro — el volumen es constante independientemente de la presión de los dedos. El piano (fortepiano) introducido en el clasicismo permite variar la intensidad al tacto. Esta diferencia explica los ornamentos frecuentes del barroco para compensar la imposibilidad del crescendo." },
  { q: "En la música barroca, la ornamentación (trinos, mordentes, apoyaturas) tiene como papel principal:", opts: ["Decorar arbitrariamente la melodía para hacerla más compleja", "Reemplazar los matices dinámicos imposibles en el clave, articular las disonancias y marcar las cadencias", "Indicar la tonalidad al público", "Reemplazar las notas que faltan en la escala"], a: 1, fb: "La ornamentación barroca es funcional: en el clave (sin matices dinámicos), los trinos alargan los sonidos y marcan los apoyos; los mordentes y apoyaturas crean tensiones expresivas; los ornamentos cadenciales señalan los finales de frase. No es decoración — es sintaxis musical." },
  { q: "La 'Suite' barroca (allemande, courante, zarabanda, giga) es característica de:", opts: ["El período romántico", "El período barroco — serie de danzas estilizadas a diferentes tempos y caracteres", "El impresionismo", "El período clásico vienés"], a: 1, fb: "La suite barroca es una colección de danzas estilizadas (diseñadas para la escucha, no para el baile): allemande (moderado), courante (rápida), zarabanda (lenta), giga (muy rápida), a veces con otras danzas. Bach compuso numerosas suites para clave, laúd y orquesta. Es una forma emblemáticamente barroca." },
  { q: "El estilo 'concerto grosso' (Vivaldi, Haendel, Corelli) opone:", opts: ["Un solista y una orquesta de cámara, alternando en diálogo", "El clave y las cuerdas únicamente", "Un pequeño grupo de solistas (concertino) contra la gran orquesta (ripieno), en alternancia y diálogo", "La voz y la orquesta"], a: 2, fb: "El concerto grosso barroco opone dos conjuntos: el concertino (pequeño grupo de solistas) y el ripieno (gran orquesta). Sus intercambios crean un diálogo de masas sonoras típico del barroco. Vivaldi perfeccionó este principio con sus más de 500 conciertos para violín y orquesta." },
  { q: "¿Qué criterio permite identificar con más seguridad una obra del período barroco?", opts: ["La presencia de guitarra eléctrica", "El bajo continuo, el contrapunto riguroso y las cadencias frecuentes y afirmadas", "La ausencia total de cromatismo", "Los acordes de 7ª siempre sin resolver"], a: 1, fb: "Tres criterios combinados identifican el barroco: (1) bajo continuo con cifrado armónico, (2) contrapunto entre voces independientes, (3) cadencias frecuentes y bien afirmadas con ornamentos. Ninguno de estos criterios por sí solo es suficiente, pero su combinación es característica." },

  // ── TEMA 2: Identificación del período clásico ────────────────────────────
  { q: "El 'bajo de Alberti' es un acompañamiento típico del período clásico. Consiste en:", opts: ["Un bajo contrapuntístico en contrapunto estricto", "Un arpegio roto de tres notas: fundamental – quinta – tercera – quinta, repetido", "Un bajo que sube cromáticamente", "Un bajo continuo cifrado"], a: 1, fb: "El bajo de Alberti es una fórmula de acompañamiento muy característica del estilo clásico vienés: se alterna fundamental – nota alta – tercera – nota alta en un movimiento regular. Mozart y Haydn lo usan abundantemente en sus sonatas y sinfonías. Su nombre viene del compositor Domenico Alberti." },
  { q: "Las frases simétricas (períodos de 4+4 compases) son características de:", opts: ["La improvisación barroca", "El período clásico vienés (Mozart, Haydn)", "El impresionismo de Debussy", "El romanticismo tardío de Wagner"], a: 1, fb: "El estilo clásico vienés estructura sistemáticamente la música en frases simétricas de 4+4 compases: una proposición (antecedente) y una respuesta (consecuente). Esta simetría crea una lógica formal muy perceptible, muy diferente del contrapunto continuo barroco o del flujo romántico." },
  { q: "¿Cómo se usan las cadencias en el período clásico en comparación con el barroco?", opts: ["Las cadencias clásicas son más ambiguas y evitadas — el clasicismo prefiere la continuidad", "Son claras, bien afirmadas y estructuran las frases de forma simétrica — similar al barroco pero en un contexto más homofónico", "Las cadencias desaparecen en el clasicismo", "Las cadencias clásicas son siempre plagales (IV–I)"], a: 1, fb: "El clasicismo mantiene cadencias claras y afirmadas, pero en un contexto más homofónico que el barroco. Las cadencias perfectas V–I estructuran las frases de 4+4 compases de forma muy legible. Es una claridad cadencial sistemática que difiere del romanticismo (cadencias evitadas) y del impresionismo (cadencias ausentes)." },
  { q: "La sonata clásica (Allegro de sonata) presenta una estructura característica:", opts: ["Tema A repetido indefinidamente", "Exposición (2 temas) – Desarrollo – Reexposición: oposición y resolución de tensiones tonales", "Introducción – Aria – Recitativo – Coda únicamente", "Variaciones continuas sobre un tema de bajo"], a: 1, fb: "La forma sonata clásica sigue un esquema tripartito: Exposición (tema principal I, puente modulante, tema secundario V o III), Desarrollo (exploración armónica, fragmentación), Reexposición (retorno de los dos temas en I). Este principio de oposición tonal (I vs V) y luego resolución define la estética clásica." },
  { q: "Mozart (1756–1791) y Haydn (1732–1809) representan:", opts: ["La vanguardia de su época, incomprendidos por sus contemporáneos", "El núcleo del clasicismo vienés — equilibrio formal, claridad armónica, elegancia melódica", "El barroco tardío, continuadores de Bach", "Los precursores directos del impresionismo"], a: 1, fb: "Mozart y Haydn encarnan el ideal clásico: equilibrio entre forma y expresión, claridad armónica alrededor de las funciones I–IV–V, economía de medios (sin cromatismo innecesario), elegancia melódica. Sus obras definen el estándar estilístico al que el análisis se refiere para identificar el clasicismo." },
  { q: "La armonía en el estilo clásico vienés se caracteriza por:", opts: ["Una saturación cromática y modulaciones frecuentes por terceras", "Una economía armónica — pocos acordes (principalmente I, IV, V, II, VI) usados con claridad y lógica funcional", "La ausencia total de dominante secundaria", "Acordes de 9ª, 11ª, 13ª sistemáticos"], a: 1, fb: "El estilo clásico vienés se distingue por su economía armónica: Mozart y Haydn usan principalmente I, IV, V y sus inversiones, con algunas dominantes secundarias específicas. Sin cromatismo excesivo — la claridad funcional prevalece. Es este equilibrio lo que lo distingue del romanticismo sobrecargado." },
  { q: "En un minueto clásico, la forma típica es:", opts: ["Tema – Variaciones – Coda", "A (minueto) – B (trío) – A (da capo) con estructura interna de 8+8 compases", "Fuga en 4 voces – Strette – Final", "Introducción – Allegro – Final"], a: 1, fb: "El minueto clásico sigue la forma ternaria A–B–A (da capo): el minueto principal, un trío contrastante (a menudo en la tonalidad de la dominante o del relativo), luego retorno del minueto. Cada sección está a su vez estructurada en 8+8 compases simétricos. Es una forma muy reconocible del clasicismo." },
  { q: "¿Cómo reconocer estilísticamente un cuarteto de cuerdas clásico?", opts: ["Por la presencia de un clave continuo en el bajo", "Por cuatro voces en escritura principalmente homofónica, con intercambios temáticos entre los instrumentos, sin bajo continuo", "Por la presencia sistemática de una voz de bajo independiente contrapuntística", "Por la ausencia de violonchelo"], a: 1, fb: "El cuarteto clásico (2 violines, viola, violonchelo) abandona el bajo continuo barroco en favor de un diálogo entre las cuatro voces. La escritura es a menudo homofónica con pasajes dialogados — lejos del contrapunto barroco. Haydn fundó la forma; Mozart y Beethoven la perfeccionaron." },
  { q: "Beethoven (1770–1827) se sitúa a menudo en la bisagra entre el clasicismo y el romanticismo. ¿Qué elemento lo sitúa allí?", opts: ["Compone fugas barrocas exclusivamente", "Comienza en el estilo clásico vienés pero introduce progresivamente expresión dramática, cromatismo aumentado y formas ampliadas", "Nunca usa las funciones clásicas I–IV–V", "Su estilo es idéntico al de Mozart"], a: 1, fb: "Beethoven parte del clasicismo heredado de Haydn y Mozart pero lo estira progresivamente: formas alargadas (sinfonías de 20-45 min), cromatismo expresivo aumentado, contrastes dinámicos radicales (pp subito ff), estructuras armónicas más complejas. Sus últimas obras (op. 130-135) prefiguran el romanticismo e incluso el modernismo." },
  { q: "Para identificar un estilo clásico vienés, ¿cuál trío de criterios es más pertinente?", opts: ["Bajo continuo + fuga + cadencias evitadas", "Frases simétricas 4+4 + armonía económica + cadencias perfectas afirmadas", "Cromatismo total + modulaciones por terceras + acordes alterados", "Modos griegos + paralelismos + ausencia de resolución V–I"], a: 1, fb: "El estilo clásico vienés se reconoce por tres criterios combinados: (1) frases simétricas de 4+4 compases con antecedente-consecuente, (2) armonía económica alrededor de I, IV, V, (3) cadencias perfectas bien afirmadas que estructuran las frases. Este tríptico contrasta con el contrapunto barroco y el cromatismo romántico." },
  { q: "En el período clásico, las modulaciones se hacen principalmente:", opts: ["Hacia tonalidades muy lejanas (tercera, mediante)", "Hacia la dominante (V) o el relativo menor/mayor — tonalidades vecinas a ±1 sostenido/bemol", "Hacia el tritono (sustitución de tritono)", "Las modulaciones están ausentes en el período clásico"], a: 1, fb: "El clasicismo modula principalmente hacia tonalidades cercanas: dominante (V), relativo menor o mayor, tonalidad de la superdominante. Estas modulaciones están claramente afirmadas por cadencias en la nueva tonalidad. Las modulaciones lejanas (por terceras) llegan con el romanticismo." },

  // ── TEMA 3: Identificación del romanticismo ───────────────────────────────
  { q: "El cromatismo romántico se caracteriza por:", opts: ["El uso exclusivo de la escala diatónica sin ninguna alteración", "Alteraciones cromáticas frecuentes que enriquecen y colorean la armonía sin necesariamente modular", "Quintas paralelas sistemáticas", "La ausencia total de sensible"], a: 1, fb: "El cromatismo romántico (Schubert, Chopin, Wagner) introduce alteraciones frecuentes que enriquecen el color armónico: acordes prestados, alteraciones expresivas, notas cromáticas en las líneas melódicas. Estas alteraciones crean tensiones que pueden permanecer sin resolución inmediata — lejos de la claridad clásica." },
  { q: "Las modulaciones por tercera (ej. Do mayor → Mi mayor) son características de:", opts: ["El período barroco estricto", "El romanticismo (Schubert, en particular)", "El impresionismo únicamente", "El período clásico vienés"], a: 1, fb: "Las modulaciones por tercera (Do → Mi, Do → Lab) son una firma del romanticismo, especialmente de Schubert. Eluden el circuito de quintas clásico (Do → Sol → Re...) para crear cambios armónicos sorprendentes y coloridos. Wagner los usará sistemáticamente para crear efectos de luz orquestal." },
  { q: "El acorde de sexta aumentada (acorde italiano, francés o alemán) es típico de:", opts: ["El barroco de Bach", "El período clásico sin alteraciones", "El romanticismo — prepara la dominante con una tensión cromática adicional", "El impresionismo de Debussy"], a: 2, fb: "El acorde de sexta aumentada (fundamental + tercera + sexta aumentada, con variantes) es una técnica romántica por excelencia. Prepara la dominante con una doble tensión cromática: dos notas convergen cromáticamente hacia V por semitonos opuestos. Schubert, Chopin y Brahms lo usan regularmente." },
  { q: "Wagner (1813–1883) es conocido por el uso del acorde de Tristán (inicio de Tristán e Isolda, 1859). ¿Por qué es revolucionario?", opts: ["Porque evita toda disonancia", "Porque es profundamente ambiguo tonalmente — sus múltiples resoluciones posibles cuestionan la tonalidad funcional", "Porque usa únicamente la escala de tonos enteros", "Porque resuelve inmediatamente en I"], a: 1, fb: "El acorde de Tristán (Fa–Si–Re#–Sol#) es revolucionario por su ambigüedad tonal: puede analizarse como un acorde de 7ª sensible semidisminuida, un acorde francés de sexta aumentada, u otra cosa según el contexto. Su resolución suspendida durante toda la obertura simboliza el deseo insatisfecho — e inaugura el derrumbe de la tonalidad." },
  { q: "El leitmotiv wagneriano es:", opts: ["Una técnica barroca de bajo continuo", "Un motivo musical asociado a un personaje, una idea o un sentimiento, transformado a lo largo de la ópera", "Una forma de sonata clásica", "Un ornamento melódico típico del romanticismo"], a: 1, fb: "El leitmotiv (motivo conductor) es una técnica narrativa inventada por Wagner: un motivo melódico-armónico corto se asocia a un elemento dramático (personaje, objeto, sentimiento) y regresa transformado a lo largo de la obra. Esta técnica influye en toda la música cinematográfica contemporánea — John Williams se inspira directamente en ella." },
  { q: "Chopin (1810–1849) es célebre por sus armonías románticas al piano. ¿Qué elemento las caracteriza?", opts: ["La rigidez funcional I–IV–V sin desviaciones", "Una riqueza cromática, apoyaturas expresivas, pedales armónicos y un uso poético de los acordes prestados", "La ausencia total de modulación", "Una escritura puramente contrapuntística tipo fuga"], a: 1, fb: "Chopin innova por su riqueza armónica pianística: apoyaturas largas y expresivas, pedales armónicos (notas sostenidas bajo armonías cambiantes), modulaciones inesperadas, acordes prestados (bVI en mayor), cromatismo melódico. Sus Nocturnos son un diccionario vivo de la armonía romántica." },
  { q: "La melodía infinita (unendliche Melodie) de Wagner se define como:", opts: ["Una melodía que se repite exactamente al infinito", "Un flujo melódico continuo que evita las cadencias conclusivas y las frases simétricas, creando una tensión sostenida", "Una melodía tocada únicamente por los violines sin acompañamiento", "Una melodía en modo dórico sin cadencia"], a: 1, fb: "La melodía infinita wagneriana rechaza las cadencias conclusivas y las frases simétricas clásicas. El flujo musical es continuo, las tensiones permanecen sin resolver durante largas duraciones. Es lo opuesto de la frase clásica de 4+4 compases — una suspensión permanente que genera el deseo y la espera propios del drama wagneriano." },
  { q: "Schubert (1797–1828) es célebre por sus lieder (melodías para voz y piano). ¿Qué los caracteriza armónicamente?", opts: ["Una armonía simple y clásica I–IV–V sin desviaciones", "Modulaciones inesperadas, préstamos del menor en mayor (bVI, bVII), un cromatismo expresivo al servicio del texto poético", "La ausencia total de pedal armónico", "Cadencias plagales exclusivas"], a: 1, fb: "Los lieder de Schubert son armónicamente innovadores para su época: modulaciones hacia tonalidades lejanas (por terceras), préstamos constantes del modo menor paralelo (bVI, bVII en mayor), cromatismo melódico y armónico. Todo el discurso armónico está al servicio del texto — la música ilustra y amplifica las imágenes poéticas." },
  { q: "La creciente ambigüedad tonal del romanticismo tardío (Wagner, Liszt) conduce hacia:", opts: ["Un retorno al barroco estricto", "El atonalismo del siglo XX — la tonalidad se desvanece progresivamente cuando las disonancias dejan de resolverse", "El clasicismo vienés de Haydn", "El impresionismo de Debussy únicamente"], a: 1, fb: "El romanticismo tardío (Tristán de Wagner, Poemas sinfónicos de Liszt, Brahms tardío) lleva la tonalidad a sus límites: disonancias cada vez más largas sin resolución, modulaciones hacia tonalidades lejanas, ambigüedad del centro tonal. Esta evolución conduce directamente a Schoenberg y el atonalismo — la tonalidad ya no puede sostenerse." },
  { q: "Para identificar una obra romántica, ¿cuál trío de criterios es más pertinente?", opts: ["Bajo continuo + fuga + modulaciones cercanas", "Frases simétricas + armonía económica + bajo de Alberti", "Cromatismo expresivo + modulaciones por terceras + acordes alterados (bVI, sextas aumentadas)", "Paralelismos + modos griegos + ausencia de V–I"], a: 2, fb: "El romanticismo se reconoce por tres criterios: (1) cromatismo expresivo frecuente, (2) modulaciones por terceras o hacia tonalidades lejanas, (3) acordes alterados y prestados (bVI en mayor, sexta napolitana, sextas aumentadas). Este cromatismo armónico lo distingue claramente del clasicismo económico y del impresionismo colorista." },
  { q: "La forma del poema sinfónico (Liszt, Strauss) es característica de:", opts: ["El período barroco — es una suite de danzas", "El romanticismo — una obra orquestal en un solo movimiento con programa literario o pictórico", "El período clásico — es una sinfonía en 4 movimientos", "El impresionismo — es una pieza atonal"], a: 1, fb: "El poema sinfónico (término inventado por Liszt) es una obra orquestal en un solo movimiento inspirada en un programa extramusical (poema, cuadro, relato mitológico). Liszt compone una docena; Richard Strauss lleva el arte a su cima (Don Juan, Till Eulenspiegel, Así habló Zaratustra). Es una forma emblemáticamente romántica." },

  // ── TEMA 4: Identificación del impresionismo ──────────────────────────────
  { q: "El 'planing' armónico es una técnica asociada a:", opts: ["Bach y el contrapunto estricto", "El impresionismo de Debussy y Ravel — movimiento paralelo de todos los intervalos de un acorde", "El romanticismo de Wagner", "El período clásico"], a: 1, fb: "El planing (o movimiento paralelo) consiste en desplazar un acorde entero en movimiento paralelo — todas las voces se mueven en la misma dirección con el mismo intervalo. Bach lo prohíbe (quintas paralelas = error). Debussy lo convierte en una técnica deliberada: los acordes se deslizan como manchas de color, sin resolución funcional." },
  { q: "La escala de tonos enteros (Do–Re–Mi–Fa#–Sol#–La#–Do) es característica de:", opts: ["La escritura barroca en modo dórico", "El impresionismo de Debussy — crea una ambigüedad tonal total, sin sensible ni subtónica", "El período clásico vienés", "El cromatismo romántico de Wagner"], a: 1, fb: "La escala de tonos enteros es una escala de 6 sonidos donde cada grado está separado por un tono entero. Sin semitono, no tiene sensible ni subtónica — imposible encontrar en ella una tónica clara. Debussy la usa para crear atmósferas flotantes y colores armónicos ambiguos, sin tensión-resolución funcional." },
  { q: "Los modos medievales (dórico, frigio, lidio, mixolidio) vuelven a estar en boga con:", opts: ["Bach y el barroco tardío", "El clasicismo de Mozart", "El impresionismo y la música de Debussy y Ravel", "Wagner y el romanticismo tardío"], a: 2, fb: "Debussy y Ravel redescubren los modos medievales para escapar de la tonalidad mayor-menor y sus funciones obligatorias. El modo dórico (sin subtónica elevada), el frigio (sensible rebajada), el lidio (cuarta aumentada), el mixolidio (7ª rebajada) ofrecen colores nuevos. Estos modos también regresan en el jazz y la música del siglo XX." },
  { q: "¿Cómo usa Debussy los acordes en comparación con la tensión-resolución clásica?", opts: ["Refuerza la tensión-resolución V–I con más disonancias que el clasicismo", "Sus acordes son manchas de color que progresan por color y registro — la tensión-resolución funcional es abandonada", "Usa únicamente la cadencia plagal IV–I", "Resuelve todas las disonancias hacia I según las reglas clásicas"], a: 1, fb: "Para Debussy, un acorde no es una función en un sistema de tensión-resolución — es un color sonoro. Los acordes de 9ª, 11ª, 13ª no 'resuelven'; se deslizan hacia otros colores. Este pensamiento armónico-cromático en lugar de funcional es la revolución impresionista: el color prima sobre la función." },
  { q: "La escala pentatónica (Do–Re–Mi–Sol–La–Do, sin Fa ni Si) es usada por Debussy para:", opts: ["Reforzar la cadencia V–I eliminando la subdominante", "Crear atmósferas exóticas y flotantes, influenciadas por la música asiática (gamelan javanés escuchado en la Exposición Universal de 1889)", "Simplificar la armonía para principiantes", "Recuperar la pureza de la música barroca"], a: 1, fb: "Debussy descubre el gamelan javanés en la Exposición Universal de París en 1889 — queda fascinado por sus sonoridades exóticas basadas en la pentatónica. La escala pentatónica (5 sonidos sin semitonos) crea una atmósfera flotante y suspendida. Esta influencia oriental nutre su impresionismo: La catedral sumergida, Estampas." },
  { q: "Ravel (1875–1937) y Debussy suelen asociarse al impresionismo. ¿Qué diferencia estilística principal los distingue?", opts: ["Ravel usa la escala de tonos, Debussy únicamente la pentatónica", "Ravel conserva una lógica formal más clásica y un contrapunto más riguroso; Debussy es más libre y flotante en sus formas", "Los dos son estilísticamente idénticos", "Debussy es más clásico, Ravel más impresionista"], a: 1, fb: "A pesar de su asociación, Ravel y Debussy difieren: Ravel mantiene una lógica formal más nítida (especialmente en sus formas sonata), un contrapunto más riguroso, una arquitectura más clara. Debussy es más libre en sus formas, más flotante en sus progresiones. El propio Ravel afirmaba no ser 'impresionista'." },
  { q: "En el impresionismo musical, el título de una pieza (La catedral sumergida, El mar, Juegos de agua) sugiere:", opts: ["Un programa dramático como las óperas de Wagner", "Impresiones sensoriales, imágenes evocadoras más que una narración — la música pinta una atmósfera", "Una referencia a una forma clásica abstracta", "Un tema religioso únicamente"], a: 1, fb: "Los títulos impresionistas evocan impresiones sensoriales, luces, reflejos, texturas — no dramas ni relatos. El mar de Debussy no es una tormenta narrativa (como la de Beethoven op.110) — es una impresión del mar en diferentes momentos. La inspiración viene de la pintura impresionista (Monet): capturar el instante, la luz, no el objeto." },
  { q: "¿Están permitidas las quintas y octavas paralelas en la armonía impresionista?", opts: ["No — las reglas del contrapunto estricto se aplican siempre", "Sí — es incluso una técnica deliberada (planing) en Debussy", "Sí, únicamente a distancia de octava", "No, pero las quintas están autorizadas si el movimiento es contrario"], a: 1, fb: "Las quintas y octavas paralelas están prohibidas en el contrapunto clásico y barroco. Debussy las usa deliberadamente como técnica expresiva — el planing crea ese efecto de colores deslizantes. Lo que es un error en un estilo (barroco, clásico) es una técnica en otro (impresionismo). El contexto histórico es determinante." },
  { q: "Para identificar una obra impresionista, ¿cuál trío de criterios es más pertinente?", opts: ["Bajo continuo + fuga + cadencias frecuentes", "Frases simétricas + cadencias V–I afirmadas + bajo de Alberti", "Acordes paralelos (planing) + modos/escala de tonos/pentatónica + ausencia de resolución funcional V–I", "Cromatismo denso + modulaciones por terceras + acordes alterados"], a: 2, fb: "El impresionismo se reconoce por tres criterios: (1) acordes paralelos (planing) sin resolución funcional, (2) uso de modos, escala de tonos y pentatónica, (3) ausencia o disolución de la cadencia funcional V–I. Este tríptico lo distingue claramente del romanticismo (cromatismo funcional) y del clasicismo (funciones claras)." },
  { q: "¿Qué distingue el cromatismo romántico del cromatismo impresionista?", opts: ["No hay ninguna diferencia entre los dos", "El romanticismo usa el cromatismo para crear tensiones funcionales resueltas; el impresionismo usa colores no funcionales (modos, tonos enteros) sin tensión-resolución obligatoria", "El impresionismo es más cromático que el romanticismo", "El romanticismo evita el cromatismo"], a: 1, fb: "La distinción es fundamental: el cromatismo romántico (Wagner, Chopin) crea tensiones funcionales que reclaman resolución — las alteraciones se inscriben en un sistema tensión-resolución. El impresionismo (Debussy) usa colores no funcionales — modos, escala de tonos, pentatónica — sin tensión-resolución obligatoria. No es 'más cromatismo', es un uso radicalmente diferente." },

  // ── TEMA 5: Comparación estilística ──────────────────────────────────────
  { q: "La misma melodía Do–Mi–Sol–Do armonizada 'al estilo de Bach' y 'al estilo de Debussy' difiere principalmente en:", opts: ["El tempo usado para tocarla", "El tratamiento de la dominante: Bach la afirma obligatoriamente (V–I); Debussy puede ignorarla totalmente", "La melodía misma que cambia según el estilo", "El instrumento utilizado"], a: 1, fb: "La diferencia fundamental entre una armonización barroca y una impresionista reside en el tratamiento de la dominante. Bach estructura obligatoriamente su discurso alrededor de V–I. Debussy puede armonizar la misma melodía con acordes de 9ª en paralelas, sin ninguna resolución V–I — la melodía es la misma, la armonía está en un universo radicalmente diferente." },
  { q: "¿Qué compositor usa sistemáticamente cadencias perfectas (V–I) afirmadas?", opts: ["Debussy", "Mozart", "Webern", "Messiaen"], a: 1, fb: "Mozart es la encarnación del estilo clásico con cadencias perfectas V–I frecuentes y bien afirmadas, que estructuran las frases de 4+4 compases. Debussy evita estas cadencias funcionales. Webern y Messiaen pertenecen al siglo XX y usan lenguajes postonales." },
  { q: "¿Qué compositor es más conocido por sus modulaciones por tercera (ej. Do mayor → Lab mayor)?", opts: ["Bach", "Mozart", "Schubert", "Debussy"], a: 2, fb: "Schubert es célebre por sus modulaciones por tercera — uno de sus rasgos estilísticos más reconocibles. En sus lieder y sonatas, se desliza frecuentemente hacia tonalidades a distancia de tercera (mayor o menor), creando cambios de color repentinos y poéticos. Bach modula por quintas; Mozart hacia tonalidades cercanas; Debussy evita las funciones modulantes." },
  { q: "¿Qué compositor está asociado al concepto de 'melodía infinita' (flujo continuo que evita las cadencias conclusivas)?", opts: ["Haydn", "Chopin", "Wagner", "Vivaldi"], a: 2, fb: "Wagner inventa el concepto de melodía infinita (unendliche Melodie) para sus dramas musicales: el flujo orquestal y vocal evita las cadencias conclusivas, creando una tensión sostenida sin resolución. Es lo opuesto de la simetría clásica de 4+4 compases. Haydn y Vivaldi viven en un mundo de frases cadenciadas regularmente." },
  { q: "¿Qué compositor es conocido por el bajo de Alberti (fundamental–quinta–tercera–quinta repetido)?", opts: ["Bach y el contrapunto", "Mozart y el estilo clásico vienés", "Debussy y el impresionismo", "Wagner y el romanticismo tardío"], a: 1, fb: "El bajo de Alberti es una firma del estilo clásico vienés, especialmente de Mozart. Esta fórmula de acompañamiento omnipresente en sus sonatas para piano reemplaza el contrapunto barroco por un acompañamiento homofónico regular. Debussy se aleja radicalmente de él; Bach nunca lo usa." },
  { q: "Una pieza que usa modos griegos (dórico, lidio, mixolidio) y acordes paralelos es probablemente:", opts: ["Una fuga barroca de Bach", "Una sonata clásica de Haydn", "Una obra impresionista de Debussy o Ravel", "Un lied romántico de Schubert"], a: 2, fb: "Los modos griegos y los acordes paralelos (planing) son firmas impresionistas. Bach y Haydn no usan modos griegos en su armonía — trabajan en el sistema mayor/menor. Schubert usa a veces el modo dórico pero sin paralelismos. Debussy combina deliberadamente modos, escala de tonos y planing." },
  { q: "Una pieza que usa intensamente el tritono como tensión no resuelta es característica de:", opts: ["La armonía clásica de Mozart (el tritono siempre se resuelve)", "El romanticismo tardío de Wagner donde las disonancias permanecen sin resolver durante mucho tiempo", "La música barroca donde el tritono está estrictamente prohibido", "La escala pentatónica que contiene numerosos tritonos"], a: 1, fb: "El tritono (diabolus in musica) debe resolverse en la música clásica y barroca. Wagner en Tristán usa el tritono de forma recurrente dejando su resolución suspendida durante largas duraciones — una audacia armónica que simboliza el deseo insatisfecho. La escala pentatónica no contiene tritono (precisamente por eso suena 'suave')." },
  { q: "¿Qué estilo armónico NO usa la progresión V–I como cadencia estructurante?", opts: ["El barroco de Bach", "El clasicismo de Mozart", "El romanticismo de Schubert", "El impresionismo de Debussy"], a: 3, fb: "Bach, Mozart y Schubert (en su escritura tonal) usan todos la progresión V–I como cadencia estructurante fundamental. Debussy la abandona deliberadamente: sus acordes progresan por color y registro, no por tensión-resolución. Buscar cadencias V–I funcionales en el impresionismo es aplicar la herramienta analítica incorrecta." },
  { q: "Un acorde de 9ª mayor no resuelto, seguido de un acorde de 9ª un semitono más agudo (planing), es característico de:", opts: ["Una fuga barroca", "Una sonata clásica", "El impresionismo de Debussy", "Un lied romántico de Brahms"], a: 2, fb: "El planing de acordes complejos (9ª, 11ª, 13ª) sin resolución es una técnica impresionista típica. Un acorde de 9ª mayor que se desliza por semitono hacia otro acorde de 9ª no tiene ningún sentido en el sistema tensión-resolución clásico o romántico — es movimiento por color, no por función. Eso es Debussy en acción." },
  { q: "Analizar los 'Preludios para piano' de Debussy con las funciones T/SD/D es:", opts: ["Pertinente — Debussy usa las funciones tonales clásicas a pesar de sus disonancias", "Contraproducente — sus acordes son colores, no funciones; el análisis modal y tímbrico es más adecuado", "Obligatorio para cualquier análisis armónico serio", "Apropiado únicamente para los preludios barrocos"], a: 1, fb: "Aplicar las funciones T/SD/D a Debussy es usar la herramienta incorrecta: sus acordes no funcionan como tensiones hacia una resolución. Un análisis pertinente de los Preludios de Debussy examina los modos usados, los paralelismos, los colores tímbricos, las relaciones de registro — no las 'dominantes' y 'subdominantes' funcionales." },
  { q: "Para identificar el período de una obra en 3 indicios, hay que examinar:", opts: ["El país del compositor, el instrumento utilizado y la duración de la pieza", "La densidad del cromatismo, la presencia o ausencia de resolución V–I, y el tratamiento de las disonancias", "El tempo, la dinámica y la articulación únicamente", "El número de movimientos, la tonalidad y el compositor"], a: 1, fb: "Los tres indicios más reveladores del período histórico de una obra: (1) densidad del cromatismo (baja=barroco/clásico, media=romántico, por color=impresionismo), (2) presencia/ausencia de V–I (obligatorio=barroco/clásico, evitado=romanticismo tardío, inexistente=impresionismo), (3) tratamiento de las disonancias (resolución inmediata=barroco, prolongada=romanticismo, no resuelta=impresionismo)." },
  { q: "¿Qué compositor 'conocía perfectamente las reglas que transgredía' — ilustrando que la libertad requiere el dominio previo?", opts: ["Bach — que ignoraba las reglas modales para crear libremente", "Debussy — cuya libertad impresionista reposa en un perfecto dominio del contrapunto y la armonía clásica", "Mozart — que transgredía las reglas de la sonata clásica", "Haendel — cuyas quintas paralelas son voluntarias"], a: 1, fb: "Debussy ilustra perfectamente la paradoja de la libertad creativa: estudió el contrapunto y la armonía clásica en el Conservatorio de París (Premio de Roma 1884), dominando perfectamente las reglas que iba a transgredir. Su libertad aparente es calculada — no una ignorancia. Para liberarse de las reglas, primero hay que dominarlas." },
  { q: "El postromanticismo (Wagner tardío, Mahler, Richard Strauss) se distingue del romanticismo por:", opts: ["El abandono del cromatismo y el retorno al diatonismo clásico", "Un cromatismo aún más denso, acordes de 9ª–11ª–13ª, una tonalidad presente pero ampliada y largas tensiones mantenidas", "El uso de la escala de tonos y del planing impresionista", "La estructura en fuga contrapuntística"], a: 1, fb: "El postromanticismo amplifica el romanticismo: cromatismo total (las 12 notas pueden aparecer en un extracto corto), acordes de 9ª, 11ª, 13ª sin resolver durante mucho tiempo, tonalidad mantenida pero bajo tensión extrema. Es la tonalidad en su punto límite antes del atonalismo — Mahler y Strauss están en este espacio entre el romanticismo y el modernismo." },
  { q: "Si una obra tiene cadencias claras V–I pero también acordes de dominante secundaria y algunas modulaciones por terceras, probablemente es:", opts: ["Estrictamente barroca", "Del romanticismo (Schubert, inicio de Chopin) — las funciones tonales permanecen pero se enriquecen de cromatismo expresivo", "Del impresionismo puro", "Del clasicismo estricto de Haydn"], a: 1, fb: "Esta descripción corresponde al romanticismo moderado (Schubert, primer Chopin): las funciones tonales V–I permanecen presentes y estructurantes, pero enriquecidas de cromatismo expresivo, modulaciones por terceras, dominantes secundarias. No es todavía el romanticismo tardío (Wagner) que suspende largamente las resoluciones. Es la zona de transición entre el clasicismo y el romanticismo avanzado." },
];

const questionsDe: Question[] = [
  // ── THEMA 1: Identifikation der Barockzeit ────────────────────────────────
  { q: "Welche Technik ist charakteristisch für den barocken Generalbass?", opts: ["Ein Bass, der den Sopran imitiert", "Ein bezifferter Bass, gespielt vom Continuo-Ensemble (Cembalo, Laute, Orgel), der die Melodie trägt", "Ein Bass, der an den Kadenzen schweigt", "Ein Bass, der nur von Streichern gespielt wird"], a: 1, fb: "Der Generalbass (Basso continuo) ist das Fundament des Barockstils: ein harmonisches Gerüst, gespielt von Begleitinstrumenten (Cembalo, Theorbe, Orgel), während die Melodie anderen Stimmen anvertraut wird. Es ist eines der zuverlässigsten Merkmale zur Identifikation des Barock." },
  { q: "Woran erkennt man eine typisch barocke Kadenz?", opts: ["Die Kadenz wird vermieden oder ausgesetzt — der Barock bevorzugt Halbkadenzen", "Die Kadenz ist häufig, ausgeprägt, oft mit Verzierungen (Triller auf dem Leitton)", "Der Barock verwendet nur die plagale Kadenz IV–I", "Barocke Kadenzen fallen nie auf den schweren Taktteil"], a: 1, fb: "Der Barockstil liebt häufige und klar ausgeprägte Kadenzen. Die authentische Kadenz V–I mit Triller auf dem Leitton ist eine Signatur der Epoche. Diese Kadenzen strukturieren den musikalischen Diskurs regelmäßig und gliedern die Ritornelle." },
  { q: "Strenger Kontrapunkt (Vorhandensein mehrerer selbstständiger Stimmen) ist charakteristisch für:", opts: ["Die Klassik allein", "Den Impressionismus", "Die Barockzeit (Bach, Händel, Vivaldi)", "Die Spätromantik"], a: 2, fb: "Der Kontrapunkt — die Kunst, mehrere selbstständige Stimmen nach strengen Regeln zusammenzuführen — steht im Mittelpunkt der barocken Schreibweise. Bachs Fugen, Inventionen und Kanons illustrieren diese Meisterschaft. Die Klassik vereinfacht die Schreibweise hin zur begleiteten Melodie." },
  { q: "Welche Form ist emblematisch für den barocken Kontrapunkt?", opts: ["Beethovens Sonate", "Die Fuge — Exposition eines Themas, das durch Imitation zwischen den Stimmen entwickelt wird", "Wagners Oper", "Debussys Prélude"], a: 1, fb: "Die Fuge ist die kontrapunktische Form schlechthin des Barock. Ein Thema wird solo vorgestellt, dann von allen Stimmen imitierend aufgenommen, nach strengen Regeln des Ein- und Gegensatzes. Bach brachte diese Kunst in seinem Wohltemperierten Klavier und der Kunst der Fuge auf den Höhepunkt." },
  { q: "Im Barockstil sind die Tonalfunktionen I–IV–V:", opts: ["Abwesend — der Barock kennt keine Tonalfunktionen", "Vorhanden, aber undeutlich — die Modalität dominiert noch", "Klar ausgeprägt und durch häufige Kadenzen bestätigt", "Nur für abschließende Kadenzen reserviert"], a: 2, fb: "Im Gegensatz zu früheren modalen Epochen etabliert der Barock klar die Tonalfunktionen I, IV, V mit häufigen und ausgeprägten Kadenzen. Bach und Händel strukturieren ihren Diskurs systematisch um Tonika, Dominante und Subdominante." },
  { q: "Bach (1685–1750) und Händel (1685–1759) sind Zeitgenossen. Diese Tatsache zeigt:", opts: ["Dass beide Komponisten denselben Stil hatten", "Dass zwei Komponisten selbst in derselben Epoche sehr unterschiedliche individuelle Stile haben können", "Dass der Barock eine sehr kurze Periode ist", "Dass alle Barockkomponisten an genau denselben Merkmalen erkennbar sind"], a: 1, fb: "Bach und Händel sind streng zeitgenössisch, aber stilistisch verschieden: Bach pflegt komplexen Kontrapunkt und lutherische Innerlichkeit; Händel schreibt italienische Opern und spektakuläre Oratorien. Die Epoche gibt einen Rahmen vor, aber die individuelle Handschrift bleibt stets vorrangig." },
  { q: "Das Cembalo ist das emblematische Tasteninstrument des Barock. Warum unterscheidet es sich vom Klavier?", opts: ["Es hat weniger Tasten", "Der Klang entsteht durch Zupfen der Saiten (keine dynamischen Nuancen durch den Anschlag) — das Klavier erzeugt den Klang durch Anschlagen und erlaubt Dynamikschwankungen", "Es existiert seit der Klassik nicht mehr", "Es klingt genau wie ein Klavier, nur höher"], a: 1, fb: "Das Cembalo erzeugt seinen Klang durch Zupfen der Saiten mittels eines Plektrons — die Lautstärke ist unabhängig vom Fingerdruck konstant. Das Klavier (Fortepiano, dann Pianoforte), eingeführt in der Klassik, erlaubt es, die Intensität durch den Anschlag zu variieren. Dieser Unterschied erklärt die häufigen Verzierungen des Barock, die das unmögliche Crescendo kompensieren." },
  { q: "In der Barockmusik hat die Ornamentik (Triller, Mordente, Appoggiaturen) als Hauptaufgabe:", opts: ["Die Melodie willkürlich zu verzieren, um sie komplexer zu machen", "Dynamische Nuancen zu ersetzen, die auf dem Cembalo unmöglich sind, Dissonanzen zu artikulieren und Kadenzen zu markieren", "Dem Publikum die Tonart anzuzeigen", "Fehlende Töne der Tonleiter zu ersetzen"], a: 1, fb: "Die barocke Ornamentik ist funktional: auf dem Cembalo (ohne dynamische Nuancen) verlängern Triller die Töne und markieren Akzentpunkte; Mordente und Appoggiaturen erzeugen expressive Spannungen; Kadenzverzierungen signalisieren Phrasenenden. Das ist keine Dekoration — das ist musikalische Syntax." },
  { q: "Die barocke 'Suite' (Allemande, Courante, Sarabande, Gigue) ist charakteristisch für:", opts: ["Die Romantik", "Die Barockzeit — eine Folge stilisierter Tänze in verschiedenen Tempi und Charakteren", "Den Impressionismus", "Die Wiener Klassik"], a: 1, fb: "Die Barocksuite ist eine Sammlung stilisierter Tänze (zum Hören konzipiert, nicht zum Tanzen): Allemande (mäßig), Courante (schnell), Sarabande (langsam), Gigue (sehr schnell), manchmal mit weiteren Tänzen. Bach komponierte zahlreiche Suiten für Cembalo, Laute und Orchester. Es ist eine emblematisch barocke Form." },
  { q: "Der 'Concerto grosso'-Stil (Vivaldi, Händel, Corelli) stellt gegenüber:", opts: ["Einen Solisten und ein Kammerorchester, die sich im Dialog abwechseln", "Nur Cembalo und Streicher", "Eine kleine Solistengruppe (Concertino) gegen das große Orchester (Ripieno), im Wechsel und im Dialog", "Stimme und Orchester"], a: 2, fb: "Das barocke Concerto grosso stellt zwei Ensembles gegenüber: das Concertino (kleine Solistengruppe) und das Ripieno (großes Orchester). Ihr Wechselspiel erzeugt einen für den Barock typischen Dialog der Klangmassen. Vivaldi perfektionierte dieses Prinzip mit seinen mehr als 500 Konzerten für Violine und Orchester." },
  { q: "Welches Kriterium identifiziert am zuverlässigsten ein Werk der Barockzeit?", opts: ["Das Vorhandensein einer E-Gitarre", "Generalbass, strenger Kontrapunkt und häufige, ausgeprägte Kadenzen", "Vollständiges Fehlen von Chromatik", "Septimenakkorde stets ohne Auflösung"], a: 1, fb: "Drei kombinierte Kriterien identifizieren den Barock: (1) Generalbass mit harmonischer Bezifferung, (2) Kontrapunkt zwischen selbstständigen Stimmen, (3) häufige und klar ausgeprägte Kadenzen mit Verzierungen. Kein einzelnes Kriterium reicht allein aus, aber ihre Kombination ist charakteristisch." },

  // ── THEMA 2: Identifikation der Klassik ──────────────────────────────────
  { q: "Der 'Alberti-Bass' ist eine typische Begleitung der Klassik. Er besteht aus:", opts: ["Einem kontrapunktischen Bass in strengem Kontrapunkt", "Einem gebrochenen Dreiklang aus drei Tönen: Grundton – Quinte – Terz – Quinte, wiederholt", "Einem chromatisch aufsteigenden Bass", "Einem bezifferten Generalbass"], a: 1, fb: "Der Alberti-Bass ist eine sehr charakteristische Begleitformel des Wiener Klassikstils: Man wechselt Grundton – obere Note – Terz – obere Note in regelmäßiger Bewegung. Mozart und Haydn verwenden ihn reichlich in ihren Sonaten und Sinfonien. Der Name stammt vom Komponisten Domenico Alberti." },
  { q: "Symmetrische Phrasen (Perioden von 4+4 Takten) sind charakteristisch für:", opts: ["Barocke Improvisation", "Die Wiener Klassik (Mozart, Haydn)", "Debussys Impressionismus", "Wagners Spätromantik"], a: 1, fb: "Der Wiener Klassikstil strukturiert Musik systematisch in symmetrische Phrasen von 4+4 Takten: ein Vordersatz (Antezedenz) und ein Nachsatz (Konsequenz). Diese Symmetrie erzeugt eine sehr wahrnehmbare formale Logik, ganz anders als der kontinuierliche barocke Kontrapunkt oder der romantische Fluss." },
  { q: "Wie werden Kadenzen in der Klassik im Vergleich zum Barock verwendet?", opts: ["Klassische Kadenzen sind mehrdeutiger und werden vermieden — die Klassik bevorzugt Kontinuität", "Sie sind klar, gut ausgeprägt und strukturieren die Phrasen symmetrisch — ähnlich dem Barock, aber in einem homophoneren Kontext", "Kadenzen verschwinden in der Klassik", "Klassische Kadenzen sind stets plagal (IV–I)"], a: 1, fb: "Die Klassik bewahrt klare und ausgeprägte Kadenzen, aber in einem homophoneren Kontext als der Barock. Vollständige Kadenzen V–I strukturieren die 4+4-Takt-Phrasen auf sehr lesbare Weise. Diese systematische Kadenzklarheit unterscheidet sich von der Romantik (vermiedene Kadenzen) und dem Impressionismus (fehlende Kadenzen)." },
  { q: "Die klassische Sonate (Sonatenallegro) hat eine charakteristische Struktur:", opts: ["Thema A unendlich wiederholt", "Exposition (2 Themen) – Durchführung – Reprise: Gegenüberstellung und Auflösung tonaler Spannungen", "Introduktion – Arie – Rezitativ – Coda allein", "Kontinuierliche Variationen über ein Bassthema"], a: 1, fb: "Die klassische Sonatenform folgt einem dreiteiligen Schema: Exposition (Hauptthema I, Überleitung, Seitenthema V oder III), Durchführung (harmonische Ausarbeitung, Zersplitterung), Reprise (Rückkehr beider Themen in I). Dieses Prinzip der tonalen Gegenüberstellung (I gegen V) und anschließenden Auflösung definiert die klassische Ästhetik." },
  { q: "Mozart (1756–1791) und Haydn (1732–1809) stehen für:", opts: ["Die Avantgarde ihrer Zeit, von ihren Zeitgenossen unverstanden", "Das Herzstück der Wiener Klassik — formales Gleichgewicht, harmonische Klarheit, melodische Eleganz", "Den Spätbarock, Fortführer Bachs", "Die direkten Vorläufer des Impressionismus"], a: 1, fb: "Mozart und Haydn verkörpern das klassische Ideal: Gleichgewicht zwischen Form und Ausdruck, harmonische Klarheit rund um die Funktionen I–IV–V, Sparsamkeit der Mittel (kein unnötiger Chromatismus), melodische Eleganz. Ihre Werke definieren den stilistischen Maßstab, auf den sich die Analyse bei der Identifikation von Klassik bezieht." },
  { q: "Die Harmonik im Wiener Klassikstil ist gekennzeichnet durch:", opts: ["Chromatische Sättigung und häufige Modulationen durch Terzen", "Harmonische Ökonomie — wenige Akkorde (hauptsächlich I, IV, V, II, VI) mit Klarheit und funktionaler Logik", "Vollständiges Fehlen von Sekundärdominanten", "Systematische None-, Undezim- und Tredezimakkorde"], a: 1, fb: "Der Wiener Klassikstil zeichnet sich durch harmonische Ökonomie aus: Mozart und Haydn verwenden hauptsächlich I, IV, V und ihre Umkehrungen, mit einigen gezielten Sekundärdominanten. Kein übermäßiger Chromatismus — funktionale Klarheit hat Vorrang. Dieses Gleichgewicht unterscheidet ihn von der überladenen Romantik." },
  { q: "In einem klassischen Menuett ist die typische Form:", opts: ["Thema – Variationen – Coda", "A (Menuett) – B (Trio) – A (da capo) mit innerer Struktur von 8+8 Takten", "4-stimmige Fuge – Strette – Finale", "Introduktion – Allegro – Finale"], a: 1, fb: "Das klassische Menuett folgt der dreiteiligen Form A–B–A (da capo): das Hauptmenuett, ein kontrastierendes Trio (oft in der Dominant- oder Paralleltonart), dann Rückkehr des Menuetts. Jeder Abschnitt ist selbst in 8+8 symmetrische Takte gegliedert. Es ist eine sehr erkennbare klassische Form." },
  { q: "Wie erkennt man ein klassisches Streichquartett stilistisch?", opts: ["Am Vorhandensein eines Continuo-Cembalos im Bass", "An vier Stimmen in vorwiegend homophoner Schreibweise, mit thematischen Wechseln zwischen den Instrumenten, ohne Generalbass", "Am systematischen Vorhandensein einer selbstständigen kontrapunktischen Bassstimme", "Am Fehlen des Cellos"], a: 1, fb: "Das klassische Quartett (2 Violinen, Viola, Cello) gibt den barocken Generalbass zugunsten eines Dialogs zwischen den vier Stimmen auf. Die Schreibweise ist oft homophon mit dialogisierten Passagen — weit entfernt vom barocken Kontrapunkt. Haydn begründete die Form; Mozart und Beethoven vervollkommneten sie." },
  { q: "Beethoven (1770–1827) wird oft an der Schnittstelle zwischen Klassik und Romantik verortet. Was platziert ihn dort?", opts: ["Er komponiert ausschließlich Barockfugen", "Er beginnt im Wiener Klassikstil, fügt aber schrittweise dramatischen Ausdruck, verstärkte Chromatik und erweiterte Formen ein", "Er verwendet nie die klassischen Funktionen I–IV–V", "Sein Stil ist identisch mit dem Mozarts"], a: 1, fb: "Beethoven geht vom Klassizismus Haydns und Mozarts aus, streckt ihn aber schrittweise: verlängerte Formen (Sinfonien 20–45 Min.), gesteigerter expressiver Chromatismus, radikale dynamische Kontraste (pp subito ff), komplexere harmonische Strukturen. Seine letzten Werke (op. 130–135) nehmen die Romantik und sogar die Moderne vorweg." },
  { q: "Um einen Wiener Klassikstil zu identifizieren, welches Kriteriendreiklang ist am treffendsten?", opts: ["Generalbass + Fuge + vermiedene Kadenzen", "Symmetrische 4+4-Phrasen + sparsame Harmonik + ausgeprägte Ganzschlüsse", "Totale Chromatik + Modulationen durch Terzen + alteriertete Akkorde", "Griechische Modi + Parallelismen + Fehlen der V–I-Auflösung"], a: 1, fb: "Der Wiener Klassikstil ist an drei kombinierten Kriterien erkennbar: (1) symmetrische Phrasen von 4+4 Takten mit Vorder- und Nachsatz, (2) sparsame Harmonik rund um I, IV, V, (3) klar ausgeprägte Ganzschlüsse, die die Phrasen strukturieren. Dieses Dreiklang kontrastiert mit dem barocken Kontrapunkt und der romantischen Chromatik." },
  { q: "In der Klassik erfolgen Modulationen hauptsächlich:", opts: ["In sehr entfernte Tonarten (Terze, Mediante)", "In die Dominanttonart (V) oder die Parallel-Moll/Dur-Tonart — Nachbartonarten mit ±1 Kreuz/Bé", "In die Tritonustonart (Tritonussubstitution)", "Modulationen fehlen in der Klassik"], a: 1, fb: "Die Klassik moduliert hauptsächlich in Nachbartonarten: Dominante (V), Paralleltonart (Moll oder Dur), Subdominante. Diese Modulationen werden durch Kadenzen in der neuen Tonart klar bestätigt. Entfernte Modulationen (durch Terzen) kommen erst mit der Romantik." },

  // ── THEMA 3: Identifikation der Romantik ─────────────────────────────────
  { q: "Die romantische Chromatik ist gekennzeichnet durch:", opts: ["Ausschließliche Verwendung der diatonischen Tonleiter ohne jede Alteration", "Häufige chromatische Alterationen, die die Harmonik bereichern und färben, ohne unbedingt zu modulieren", "Systematische Quintenparallelen", "Vollständiges Fehlen des Leittons"], a: 1, fb: "Die romantische Chromatik (Schubert, Chopin, Wagner) bringt häufige Alterationen, die den harmonischen Klang bereichern: Entlehnungsakkorde, expressive Alterationen, chromatische Töne in Melodielinien. Diese Alterationen erzeugen Spannungen, die ohne sofortige Auflösung bleiben können — weit entfernt von der klassischen Klarheit." },
  { q: "Modulationen durch Terzen (z. B. C-Dur → E-Dur) sind charakteristisch für:", opts: ["Den strengen Barock", "Die Romantik (Schubert, insbesondere)", "Nur den Impressionismus", "Die Wiener Klassik"], a: 1, fb: "Modulationen durch Terzen (C → E, C → As) sind eine Signatur der Romantik, insbesondere Schuberts. Sie umgehen den klassischen Quintenzirkel (C → G → D...) und erzeugen überraschende und farbenfrohe harmonische Wechsel. Wagner wird sie später systematisch für orchestrale Lichteffekte nutzen." },
  { q: "Der übermäßige Sextakkord (italienischer, französischer oder deutscher) ist typisch für:", opts: ["Bachs Barock", "Die Klassik ohne Alterationen", "Die Romantik — er bereitet die Dominante mit zusätzlicher chromatischer Spannung vor", "Debussys Impressionismus"], a: 2, fb: "Der übermäßige Sextakkord (Grundton + Terz + übermäßige Sexte, mit Varianten) ist eine romantische Technik par excellence. Er bereitet die Dominante mit doppelter chromatischer Spannung vor: zwei Töne konvergieren chromatisch durch entgegengesetzte Halbtöne auf V. Schubert, Chopin und Brahms verwenden ihn regelmäßig." },
  { q: "Wagner (1813–1883) ist bekannt für den Tristan-Akkord (Beginn von Tristan und Isolde, 1859). Warum ist er revolutionär?", opts: ["Weil er jede Dissonanz vermeidet", "Weil er tonal zutiefst mehrdeutig ist — seine zahlreichen möglichen Auflösungen stellen die Funktionstonalität in Frage", "Weil er ausschließlich die Ganztonleiter verwendet", "Weil er sofort auf I auflöst"], a: 1, fb: "Der Tristan-Akkord (F–H–Dis–Gis) ist durch seine tonale Mehrdeutigkeit revolutionär: Er kann als halbverminderter Septimenakkord, als französischer übermäßiger Sextakkord oder als etwas anderes je nach Kontext analysiert werden. Seine während der gesamten Ouvertüre aufgeschobene Auflösung symbolisiert das unerfüllte Verlangen — und läutet den Verfall der Tonalität ein." },
  { q: "Das wagnersche Leitmotiv ist:", opts: ["Eine barocke Generalbasstechnik", "Ein musikalisches Motiv, das einer Figur, einer Idee oder einem Gefühl zugeordnet wird und sich im Laufe der Oper verwandelt", "Eine klassische Sonatenform", "Ein melodisches Ornament typisch für die Romantik"], a: 1, fb: "Das Leitmotiv ist eine von Wagner erfundene Erzähltechnik: Ein kurzes melodisch-harmonisches Motiv wird einem dramatischen Element (Figur, Gegenstand, Gefühl) zugeordnet und kehrt im Laufe des Werkes verwandelt wieder. Diese Technik beeinflusst die gesamte zeitgenössische Filmmusik — John Williams schöpft direkt daraus." },
  { q: "Chopin (1810–1849) ist berühmt für seine romantische Klavierharmonik. Welches Element kennzeichnet sie?", opts: ["Funktionale Starrheit I–IV–V ohne Abweichungen", "Chromatischer Reichtum, ausdrucksvolle Appoggiaturen, harmonische Pedale und eine poetische Verwendung von Entlehnungsakkorden", "Völliges Fehlen von Modulationen", "Rein fugenartige kontrapunktische Schreibweise"], a: 1, fb: "Chopin innoviert durch seinen pianistischen harmonischen Reichtum: lange und ausdrucksvolle Appoggiaturen, harmonische Pedale (gehaltene Töne unter wechselnden Harmonien), unerwartete Modulationen, Entlehnungsakkorde (bVI in Dur), melodische Chromatik. Seine Nocturnes sind ein lebendiges Wörterbuch der romantischen Harmonik." },
  { q: "Wagners 'unendliche Melodie' ist definiert als:", opts: ["Eine Melodie, die sich exakt unendlich wiederholt", "Ein kontinuierlicher Melodiefluss, der abschließende Kadenzen und symmetrische Phrasen meidet und eine anhaltende Spannung erzeugt", "Eine Melodie, die nur von Geigen ohne Begleitung gespielt wird", "Eine Melodie im dorischen Modus ohne Kadenz"], a: 1, fb: "Wagners unendliche Melodie verwirft abschließende Kadenzen und klassische symmetrische Phrasen. Der musikalische Fluss ist kontinuierlich, Spannungen bleiben über lange Zeitspannen unaufgelöst. Es ist das Gegenteil der klassischen 4+4-Takt-Phrase — eine permanente Aussetzung, die das Verlangen und die Erwartung des wagnerschen Dramas erzeugt." },
  { q: "Schubert (1797–1828) ist berühmt für seine Lieder (für Singstimme und Klavier). Was kennzeichnet sie harmonisch?", opts: ["Eine einfache klassische Harmonik I–IV–V ohne Abweichungen", "Unerwartete Modulationen, Entlehnungen aus Moll in Dur (bVI, bVII), ausdrucksvolle Chromatik im Dienst des Dichterwortes", "Völliges Fehlen harmonischer Pedale", "Ausschließlich plagale Kadenzen"], a: 1, fb: "Schuberts Lieder sind harmonisch für ihre Zeit innovativ: Modulationen in entfernte Tonarten (durch Terzen), ständige Entlehnungen aus der Paralleltonart (bVI, bVII in Dur), melodische und harmonische Chromatik. Der gesamte harmonische Diskurs dient dem Text — die Musik illustriert und verstärkt die poetischen Bilder." },
  { q: "Die wachsende Tonalitätsmehrdeutigkeit der Spätromantik (Wagner, Liszt) führt hin zur:", opts: ["Rückkehr zum strengen Barock", "Atonalität des 20. Jahrhunderts — die Tonalität verblasst allmählich, wenn Dissonanzen aufhören sich aufzulösen", "Wiener Klassik Haydns", "Ausschließlich zu Debussys Impressionismus"], a: 1, fb: "Die Spätromantik (Wagners Tristan, Liszts Sinfonische Dichtungen, später Brahms) treibt die Tonalität an ihre Grenzen: immer längere unaufgelöste Dissonanzen, Modulationen in entfernte Tonarten, Mehrdeutigkeit des tonalen Zentrums. Diese Entwicklung führt direkt zu Schönberg und der Atonalität — die Tonalität kann sich nicht mehr halten." },
  { q: "Um ein romantisches Werk zu identifizieren, welches Kriteriendreiklang ist am treffendsten?", opts: ["Generalbass + Fuge + nahe Modulationen", "Symmetrische Phrasen + sparsame Harmonik + Alberti-Bass", "Ausdrucksvolle Chromatik + Modulationen durch Terzen + alteriertete Akkorde (bVI, übermäßige Sexten)", "Parallelismen + griechische Modi + Fehlen von V–I"], a: 2, fb: "Die Romantik ist an drei Kriterien erkennbar: (1) häufige expressive Chromatik, (2) Modulationen durch Terzen oder in entfernte Tonarten, (3) alteriertete und entlehnte Akkorde (bVI in Dur, neapolitanische Sexte, übermäßige Sexten). Diese harmonische Chromatik unterscheidet sie klar von der sparsamen Klassik und dem koloristischen Impressionismus." },
  { q: "Die Form der sinfonischen Dichtung (Liszt, Strauss) ist charakteristisch für:", opts: ["Die Barockzeit — es ist eine Tanzfolge", "Die Romantik — ein einsätziges Orchesterwerk mit literarischem oder bildlichem Programm", "Die Klassik — es ist eine viersätzige Sinfonie", "Den Impressionismus — es ist ein atonales Stück"], a: 1, fb: "Die sinfonische Dichtung (ein von Liszt geprägter Begriff) ist ein einsätziges Orchesterwerk, das von einem außermusikalischen Programm (Gedicht, Gemälde, mythologischer Stoff) inspiriert wird. Liszt komponierte über ein Dutzend; Richard Strauss trieb diese Kunst auf den Höhepunkt (Don Juan, Till Eulenspiegel, Also sprach Zarathustra). Es ist eine emblematisch romantische Form." },

  // ── THEMA 4: Identifikation des Impressionismus ───────────────────────────
  { q: "Das 'Planing' (harmonisches Parallelführen) ist eine Technik, die assoziiert wird mit:", opts: ["Bach und strengem Kontrapunkt", "Debussys und Ravels Impressionismus — Parallelbewegung aller Intervalle eines Akkords", "Wagners Romantik", "Der Klassik"], a: 1, fb: "Planing (oder Parallelbewegung) besteht darin, einen ganzen Akkord in Parallelbewegung zu verschieben — alle Stimmen bewegen sich in dieselbe Richtung um dasselbe Intervall. Bach verbietet dies (Quintenparallelen = Fehler). Debussy macht es zu einer bewussten Technik: Die Akkorde gleiten wie Farbflecken, ohne funktionale Auflösung." },
  { q: "Die Ganztonleiter (C–D–E–Fis–Gis–Ais–C) ist charakteristisch für:", opts: ["Barocke Schreibweise im dorischen Modus", "Debussys Impressionismus — sie schafft völlige tonale Mehrdeutigkeit, ohne Leitton oder Unterstufe", "Die Wiener Klassik", "Wagners romantische Chromatik"], a: 1, fb: "Die Ganztonleiter ist eine 6-tönicge Tonleiter, bei der jeder Ton durch einen Ganzton getrennt ist. Ohne Halbton gibt es keinen Leitton oder Grundton — unmöglich, darin eine klare Tonika zu finden. Debussy verwendet sie zur Erzeugung schwebender Atmosphären und mehrdeutiger Klangfarben, ohne funktionale Spannung-Auflösung." },
  { q: "Mittelalterliche Modi (Dorisch, Phrygisch, Lydisch, Mixolydisch) kommen wieder in Mode mit:", opts: ["Bach und dem Spätbarock", "Mozarts Klassik", "Dem Impressionismus und der Musik von Debussy und Ravel", "Wagner und der Spätromantik"], a: 2, fb: "Debussy und Ravel entdecken mittelalterliche Modi neu, um der Dur-Moll-Tonalität und ihren zwingenden Funktionen zu entkommen. Dorisch (ohne erhöhte Unterstufe), Phrygisch (erniedrigter Leitton), Lydisch (übermäßige Quarte), Mixolydisch (erniedrigte Septime) bieten neue Klangfarben. Diese Modi kehren auch im Jazz und in der Musik des 20. Jahrhunderts zurück." },
  { q: "Wie verwendet Debussy Akkorde im Vergleich zur klassischen Spannung-Auflösung?", opts: ["Er verstärkt die V–I-Spannung-Auflösung mit mehr Dissonanzen als die Klassik", "Seine Akkorde sind Klangfarben, die nach Farbe und Register fortschreiten — die funktionale Spannung-Auflösung wird aufgegeben", "Er verwendet nur die plagale Kadenz IV–I", "Er löst alle Dissonanzen nach I gemäß den klassischen Regeln auf"], a: 1, fb: "Für Debussy ist ein Akkord keine Funktion in einem Spannungs-Auflösungs-System — er ist eine Klangfarbe. Nonen-, Undezim-, Tredezimakkorde 'lösen sich nicht auf'; sie gleiten zu anderen Farben. Dieses harmonisch-koloristische statt funktionale Denken ist die impressionistische Revolution: Farbe geht vor Funktion." },
  { q: "Die Pentatonik (C–D–E–G–A–C, ohne F und H) wird von Debussy verwendet, um:", opts: ["Die V–I-Kadenz zu verstärken, indem die Subdominante weggelassen wird", "Exotische und schwebende Atmosphären zu schaffen, beeinflusst von asiatischer Musik (javanisches Gamelan, gehört auf der Weltausstellung von 1889)", "Die Harmonik für Anfänger zu vereinfachen", "Die Reinheit der Barockmusik wiederzufinden"], a: 1, fb: "Debussy entdeckt das javanische Gamelan auf der Pariser Weltausstellung 1889 — er ist fasziniert von seinen exotischen, auf der Pentatonik basierenden Klängen. Die Pentatonik (5 Töne ohne Halbtöne) schafft eine schwebende und schwebende Atmosphäre. Dieser orientalische Einfluss nährt seinen Impressionismus: La cathédrale engloutie, Estampes." },
  { q: "Ravel (1875–1937) und Debussy werden oft mit dem Impressionismus assoziiert. Welcher wesentliche Stilunterschied unterscheidet sie?", opts: ["Ravel verwendet die Ganztonleiter, Debussy nur die Pentatonik", "Ravel bewahrt eine klassischere formale Logik und einen strengeren Kontrapunkt; Debussy ist in seinen Formen freier und schwebender", "Beide sind stilistisch identisch", "Debussy ist klassischer, Ravel impressionistischer"], a: 1, fb: "Trotz ihrer Assoziation unterscheiden sich Ravel und Debussy: Ravel bewahrt eine klarere formale Logik (besonders in seinen Sonatenformen), einen strengeren Kontrapunkt, eine klarere Architektur. Debussy ist freier in seinen Formen, schwebender in seinen Progressionen. Ravel selbst behauptete, kein 'Impressionist' zu sein." },
  { q: "Im musikalischen Impressionismus deutet der Titel eines Stücks (La cathédrale engloutie, La mer, Jeux d'eau) an:", opts: ["Ein dramatisches Programm wie Wagners Opern", "Sinnliche Eindrücke, evokative Bilder statt einer Erzählung — die Musik malt eine Atmosphäre", "Eine Referenz auf eine abstrakte klassische Form", "Nur ein religiöses Thema"], a: 1, fb: "Impressionistische Titel evozieren sinnliche Eindrücke, Lichter, Reflexe, Texturen — keine Dramen oder Erzählungen. Debussys La mer ist kein narrativer Sturm (wie Beethovens op.110) — es ist ein Eindruck des Meeres zu verschiedenen Augenblicken. Die Inspiration kommt von der impressionistischen Malerei (Monet): den Moment, das Licht festhalten, nicht das Objekt." },
  { q: "Sind Quinten- und Oktavenparallelen in der impressionistischen Harmonik erlaubt?", opts: ["Nein — die Regeln des strengen Kontrapunkts gelten stets", "Ja — es ist sogar eine bewusste Technik (Planing) bei Debussy", "Ja, aber nur im Oktavabstand", "Nein, aber Quinten sind erlaubt, wenn die Bewegung gegensätzlich ist"], a: 1, fb: "Quinten- und Oktavenparallelen sind im klassischen und barocken Kontrapunkt verboten. Debussy verwendet sie bewusst als expressive Technik — das Planing erzeugt diesen Effekt gleitender Farben. Was in einem Stil (barock, klassisch) ein Fehler ist, ist in einem anderen (Impressionismus) eine Technik. Der historische Kontext ist entscheidend." },
  { q: "Um ein impressionistisches Werk zu identifizieren, welches Kriteriendreiklang ist am treffendsten?", opts: ["Generalbass + Fuge + häufige Kadenzen", "Symmetrische Phrasen + ausgeprägte V–I-Kadenzen + Alberti-Bass", "Parallele Akkorde (Planing) + Modi/Ganztonleiter/Pentatonik + Fehlen funktionaler V–I-Auflösung", "Dichte Chromatik + Modulationen durch Terzen + alteriertete Akkorde"], a: 2, fb: "Der Impressionismus ist an drei Kriterien erkennbar: (1) parallele Akkorde (Planing) ohne funktionale Auflösung, (2) Verwendung von Modi, Ganztonleiter und Pentatonik, (3) Fehlen oder Auflösung der funktionalen V–I-Kadenz. Dieser Dreiklang unterscheidet ihn klar von der Romantik (funktionale Chromatik) und der Klassik (klare Funktionen)." },
  { q: "Was unterscheidet romantische Chromatik von impressionistischer Chromatik?", opts: ["Es gibt keinen Unterschied zwischen beiden", "Die Romantik verwendet Chromatik, um funktionale Spannungen zu erzeugen, die aufgelöst werden; der Impressionismus verwendet nicht-funktionale Farben (Modi, Ganztöne) ohne obligatorische Spannung-Auflösung", "Der Impressionismus ist chromatischer als die Romantik", "Die Romantik vermeidet Chromatik"], a: 1, fb: "Der Unterschied ist grundlegend: Romantische Chromatik (Wagner, Chopin) erzeugt funktionale Spannungen, die eine Auflösung verlangen — die Alterationen fügen sich in ein Spannungs-Auflösungs-System ein. Der Impressionismus (Debussy) verwendet nicht-funktionale Farben — Modi, Ganztonleiter, Pentatonik — ohne obligatorische Spannung-Auflösung. Das ist nicht 'mehr Chromatik', das ist ein grundlegend anderer Gebrauch." },

  // ── THEMA 5: Stilistischer Vergleich ─────────────────────────────────────
  { q: "Dieselbe Melodie C–E–G–C, harmonisiert 'im Stile Bachs' und 'im Stile Debussys', unterscheidet sich hauptsächlich in:", opts: ["Dem verwendeten Tempo", "Der Behandlung der Dominante: Bach bestätigt sie obligatorisch (V–I); Debussy kann sie ganz ignorieren", "Der Melodie selbst, die sich je nach Stil ändert", "Dem verwendeten Instrument"], a: 1, fb: "Der grundlegende Unterschied zwischen einer barocken und einer impressionistischen Harmonisierung liegt in der Behandlung der Dominante. Bach strukturiert seinen Diskurs obligatorisch um V–I. Debussy kann dieselbe Melodie mit parallelen Nonakkorden harmonisieren, ohne jede V–I-Auflösung — die Melodie ist dieselbe, die Harmonik befindet sich in einem grundlegend anderen Universum." },
  { q: "Welcher Komponist verwendet systematisch ausgeprägte Ganzschlüsse (V–I)?", opts: ["Debussy", "Mozart", "Webern", "Messiaen"], a: 1, fb: "Mozart ist die Verkörperung des klassischen Stils mit häufigen und klar ausgeprägten V–I-Ganzschlüssen, die die 4+4-Takt-Phrasen strukturieren. Debussy vermeidet diese funktionalen Kadenzen. Webern und Messiaen gehören dem 20. Jahrhundert an und verwenden post-tonale Sprachen." },
  { q: "Welcher Komponist ist am bekanntesten für Terzmodulationen (z. B. C-Dur → As-Dur)?", opts: ["Bach", "Mozart", "Schubert", "Debussy"], a: 2, fb: "Schubert ist berühmt für seine Terzmodulationen — eines seiner erkennbarsten stilistischen Merkmale. In seinen Liedern und Sonaten gleitet er häufig in Tonarten, die eine Terz entfernt liegen (groß oder klein), was plötzliche und poetische Farbwechsel erzeugt. Bach moduliert durch Quinten; Mozart in Nachbartonarten; Debussy vermeidet modulierende Funktionen." },
  { q: "Welcher Komponist ist mit dem Konzept der 'unendlichen Melodie' (kontinuierlicher Fluss, der abschließende Kadenzen vermeidet) verbunden?", opts: ["Haydn", "Chopin", "Wagner", "Vivaldi"], a: 2, fb: "Wagner erfindet das Konzept der unendlichen Melodie für seine Musikdramen: Der orchestrale und vokale Fluss vermeidet abschließende Kadenzen und erzeugt eine anhaltende Spannung ohne Auflösung. Es ist das Gegenteil der klassischen Symmetrie von 4+4 Takten. Haydn und Vivaldi leben in einer Welt regelmäßig kadenzierter Phrasen." },
  { q: "Welcher Komponist ist für den Alberti-Bass (Grundton–Quinte–Terz–Quinte wiederholt) bekannt?", opts: ["Bach und der Kontrapunkt", "Mozart und der Wiener Klassikstil", "Debussy und der Impressionismus", "Wagner und die Spätromantik"], a: 1, fb: "Der Alberti-Bass ist eine Signatur des Wiener Klassikstils, insbesondere Mozarts. Diese in seinen Klaviersonaten allgegenwärtige Begleitformel ersetzt den barocken Kontrapunkt durch eine regelmäßige homophone Begleitung. Debussy entfernt sich radikal davon; Bach verwendet sie nie." },
  { q: "Ein Stück, das griechische Modi (Dorisch, Lydisch, Mixolydisch) und Parallelakkorde verwendet, ist wahrscheinlich:", opts: ["Eine Barockfuge von Bach", "Eine klassische Sonate von Haydn", "Ein impressionistisches Werk von Debussy oder Ravel", "Ein romantisches Lied von Schubert"], a: 2, fb: "Griechische Modi und Parallelakkorde (Planing) sind impressionistische Signaturen. Bach und Haydn verwenden keine griechischen Modi in ihrer Harmonik — sie arbeiten im Dur-Moll-System. Schubert verwendet manchmal den dorischen Modus, aber ohne Parallelismen. Debussy kombiniert bewusst Modi, Ganztonleiter und Planing." },
  { q: "Ein Stück, das den Tritonus intensiv als unaufgelöste Spannung verwendet, ist charakteristisch für:", opts: ["Mozarts klassische Harmonik (der Tritonus wird stets aufgelöst)", "Wagners Spätromantik, wo Dissonanzen lange unaufgelöst bleiben", "Barockmusik, wo der Tritonus streng verboten ist", "Die Pentatonik, die viele Tritoni enthält"], a: 1, fb: "Der Tritonus (diabolus in musica) muss in der Klassik und im Barock aufgelöst werden. Wagner verwendet in Tristan den Tritonus immer wieder und lässt seine Auflösung über lange Zeitspannen in der Schwebe — eine harmonische Kühnheit, die das unstillbare Verlangen symbolisiert. Die Pentatonik enthält keinen Tritonus (genau deshalb klingt sie 'weich')." },
  { q: "Welcher Harmonikstil verwendet die Progression V–I NICHT als strukturgebende Kadenz?", opts: ["Bachs Barock", "Mozarts Klassik", "Schuberts Romantik", "Debussys Impressionismus"], a: 3, fb: "Bach, Mozart und Schubert (in ihrer tonalen Schreibweise) verwenden alle die Progression V–I als grundlegende strukturgebende Kadenz. Debussy gibt dieses Prinzip bewusst auf: Seine Akkorde schreiten nach Farbe und Register fort, nicht durch Spannung-Auflösung. Nach funktionalen V–I-Kadenzen im Impressionismus zu suchen, bedeutet das falsche Analysewerkzeug anzuwenden." },
  { q: "Ein unaufgelöster großer Nonakkord, gefolgt von einem Nonakkord einen Halbton höher (Planing), ist charakteristisch für:", opts: ["Eine Barockfuge", "Eine klassische Sonate", "Debussys Impressionismus", "Ein romantisches Lied von Brahms"], a: 2, fb: "Das Planing komplexer Akkorde (None, Undezime, Tredezime) ohne Auflösung ist eine typische impressionistische Technik. Ein großer Nonakkord, der um einen Halbton zu einem anderen Nonakkord gleitet, ergibt im klassischen oder romantischen Spannungs-Auflösungs-System keinen Sinn — das ist Bewegung durch Farbe, nicht durch Funktion. Das ist Debussy in Aktion." },
  { q: "Debussys 'Préludes pour piano' mit den Funktionen T/SD/D zu analysieren ist:", opts: ["Angemessen — Debussy verwendet klassische Tonalfunktionen trotz seiner Dissonanzen", "Kontraproduktiv — seine Akkorde sind Farben, keine Funktionen; eine modale und klangliche Analyse ist geeigneter", "Für jede ernsthafte Harmonikanalyse obligatorisch", "Nur für Barockpräludien angebracht"], a: 1, fb: "T/SD/D-Funktionen auf Debussy anzuwenden bedeutet, das falsche Werkzeug zu benutzen: Seine Akkorde funktionieren nicht als Spannungen auf eine Auflösung hin. Eine treffende Analyse von Debussys Préludes untersucht die verwendeten Modi, die Parallelismen, die Klangfarben, die Registerbeziehungen — nicht funktionale 'Dominanten' und 'Subdominanten'." },
  { q: "Um die Epoche eines Werkes anhand von 3 Indizien zu bestimmen, muss man untersuchen:", opts: ["Das Herkunftsland des Komponisten, das verwendete Instrument und die Länge des Stücks", "Die Dichte der Chromatik, das Vorhandensein oder Fehlen der V–I-Auflösung und die Behandlung der Dissonanzen", "Nur Tempo, Dynamik und Artikulation", "Die Anzahl der Sätze, die Tonart und den Komponisten"], a: 1, fb: "Die drei aufschlussreichsten Indizien für die historische Epoche eines Werkes: (1) Dichte der Chromatik (gering=Barock/Klassik, mittel=Romantik, farblich=Impressionismus), (2) Vorhandensein/Fehlen von V–I (obligatorisch=Barock/Klassik, vermieden=Spätromantik, inexistent=Impressionismus), (3) Behandlung der Dissonanzen (sofortige Auflösung=Barock, verlängert=Romantik, unaufgelöst=Impressionismus)." },
  { q: "Welcher Komponist 'kannte die Regeln, die er übertrat, genau' — was zeigt, dass Freiheit vorherige Meisterschaft erfordert?", opts: ["Bach — der die modalen Regeln ignorierte, um frei zu schaffen", "Debussy — dessen impressionistische Freiheit auf einer perfekten Beherrschung des Kontrapunkts und der klassischen Harmonik beruht", "Mozart — der die Regeln der klassischen Sonate übertrat", "Händel — dessen Quintenparallelen absichtlich sind"], a: 1, fb: "Debussy illustriert perfekt das Paradox der schöpferischen Freiheit: Er studierte Kontrapunkt und klassische Harmonik am Pariser Konservatorium (Prix de Rome 1884) und beherrschte die Regeln, die er übertreten würde, perfekt. Seine scheinbare Freiheit ist berechnet — keine Unwissenheit. Um sich von Regeln zu befreien, muss man sie zunächst meistern." },
  { q: "Die Nachromantik (später Wagner, Mahler, Richard Strauss) unterscheidet sich von der Romantik durch:", opts: ["Aufgabe der Chromatik und Rückkehr zum klassischen Diatonismus", "Noch dichtere Chromatik, None–Undezim–Tredezimakkorde, eine vorhandene, aber erweiterte Tonalität und lang gehaltene Spannungen", "Verwendung der Ganztonleiter und des impressionistischen Planings", "Kontrapunktische Fugenstruktur"], a: 1, fb: "Die Nachromantik verstärkt die Romantik: totale Chromatik (alle 12 Töne können in einem kurzen Ausschnitt erscheinen), None-, Undezim-, Tredezimakkorde lange ohne Auflösung, Tonalität erhalten, aber unter extremer Spannung. Das ist die Tonalität an ihrer Grenze vor der Atonalität — Mahler und Strauss befinden sich in diesem Raum zwischen Romantik und Moderne." },
  { q: "Wenn ein Werk klare V–I-Kadenzen hat, aber auch Sekundärdominanten und einige Terzmodulationen, ist es wahrscheinlich:", opts: ["Streng barock", "Romantik (Schubert, früher Chopin) — die Tonalfunktionen bleiben, werden aber durch ausdrucksvolle Chromatik bereichert", "Reiner Impressionismus", "Strenge Klassik von Haydn"], a: 1, fb: "Diese Beschreibung entspricht der gemäßigten Romantik (Schubert, früher Chopin): Die tonalen Funktionen V–I bleiben präsent und strukturgebend, werden aber durch ausdrucksvolle Chromatik, Terzmodulationen und Sekundärdominanten bereichert. Das ist noch nicht die Spätromantik (Wagner), die die Auflösungen lange hinausschiebt. Es ist die Übergangszone zwischen Klassik und fortgeschrittener Romantik." },
];

const questionsIt: Question[] = [
  // ── ARGOMENTO 1: Identificazione del periodo barocco ─────────────────────
  { q: "Quale tecnica è caratteristica del basso continuo barocco?", opts: ["Un basso che imita il soprano", "Un basso cifrato suonato da un gruppo di continuo (clavicembalo, liuto, organo) che sostiene la melodia", "Un basso che tace alle cadenze", "Un basso suonato solo dagli archi"], a: 1, fb: "Il basso continuo (basso continuo) è il fondamento dello stile barocco: una realizzazione armonica suonata da strumenti d'accompagnamento (clavicembalo, tiorba, organo) mentre la melodia è affidata ad altre voci. È uno dei criteri più affidabili per identificare il barocco." },
  { q: "Come si riconosce una cadenza tipicamente barocca?", opts: ["La cadenza è evitata o sospesa — il barocco preferisce le semicadenze", "La cadenza è frequente, affermata, spesso con abbellimenti (trillo sulla sensibile)", "Il barocco usa solo la cadenza plagale IV–I", "Le cadenze barocche non cadono mai sul tempo forte"], a: 1, fb: "Lo stile barocco predilige cadenze frequenti e ben affermate. La cadenza autentica V–I con trillo sulla sensibile è una firma dell'epoca. Queste cadenze scandiscono regolarmente il discorso, strutturando i ritornelli." },
  { q: "Il contrappunto rigoroso (presenza di più voci indipendenti) è caratteristico di:", opts: ["Il periodo classico soltanto", "L'impressionismo", "Il periodo barocco (Bach, Haendel, Vivaldi)", "Il tardo romanticismo"], a: 2, fb: "Il contrappunto — l'arte di far coesistere più voci indipendenti secondo regole rigorose — è al cuore della scrittura barocca. Le fughe, le invenzioni e i canoni di Bach illustrano questa maestria. Il periodo classico semplifica la scrittura verso una melodia accompagnata." },
  { q: "Quale forma è emblematica della scrittura contrappuntistica barocca?", opts: ["La sonata di Beethoven", "La fuga — esposizione di un soggetto sviluppato per imitazione tra le voci", "L'opera di Wagner", "Il preludio di Debussy"], a: 1, fb: "La fuga è la forma contrappuntistica per eccellenza del barocco. Un soggetto viene presentato da solo, poi ripreso per imitazione da tutte le voci secondo rigide regole di entrata e risposta. Bach portò quest'arte al vertice nel Clavicembalo ben temperato e nell'Arte della fuga." },
  { q: "Nello stile barocco, le funzioni tonali I–IV–V sono:", opts: ["Assenti — il barocco non usa funzioni tonali", "Presenti ma vaghe — la modalità domina ancora", "Chiaramente stabilite e frequentemente affermate da cadenze", "Riservate solo alle cadenze finali"], a: 2, fb: "A differenza dei periodi modali precedenti, il barocco stabilisce chiaramente le funzioni tonali I, IV, V con cadenze frequenti e affermate. Bach e Haendel strutturano il loro discorso sistematicamente attorno alla tonica, dominante e sottodominante." },
  { q: "Bach (1685–1750) e Haendel (1685–1759) sono contemporanei. Questo fatto illustra:", opts: ["Che i due compositori avevano lo stesso stile", "Che anche nella stessa epoca, due compositori possono avere stili individuali molto distinti", "Che il barocco è un periodo molto breve", "Che tutti i compositori barocchi sono identificabili dagli stessi identici tratti"], a: 1, fb: "Bach e Haendel sono rigorosamente contemporanei ma stilisticamente diversi: Bach coltiva il contrappunto complesso e l'introspezione luterana; Haendel scrive opere italiane e oratori spettacolari. L'epoca fornisce una cornice, ma la firma individuale prevale sempre." },
  { q: "Il clavicembalo è lo strumento a tastiera emblematico del barocco. Perché è diverso dal pianoforte?", opts: ["Ha meno tasti", "Il suono è prodotto per pizzico delle corde (nessuna sfumatura dinamica con il tocco) — il pianoforte produce il suono per percussione e permette le sfumature dinamiche", "Non esiste più dal classicismo", "Suona esattamente come un pianoforte ma più acuto"], a: 1, fb: "Il clavicembalo produce il suo suono per pizzico delle corde tramite un plettro — il volume è costante indipendentemente dalla pressione delle dita. Il pianoforte (fortepiano, poi pianoforte), introdotto nel classicismo, permette di variare l'intensità con il tocco. Questa differenza spiega gli abbellimenti frequenti del barocco per compensare l'impossibilità del crescendo." },
  { q: "Nella musica barocca, l'ornamentazione (trilli, mordenti, appoggiature) ha come ruolo principale:", opts: ["Decorare arbitrariamente la melodia per renderla più complessa", "Sostituire le sfumature dinamiche impossibili sul clavicembalo, articolare le dissonanze e marcare le cadenze", "Indicare la tonalità al pubblico", "Sostituire le note mancanti della scala"], a: 1, fb: "L'ornamentazione barocca è funzionale: sul clavicembalo (senza sfumature dinamiche), i trilli allungano i suoni e marcano gli accenti; i mordenti e le appoggiature creano tensioni espressive; gli abbellimenti cadenziali segnalano le chiusure di frase. Non è decorazione — è sintassi musicale." },
  { q: "La 'Suite' barocca (allemanda, corrente, sarabanda, giga) è caratteristica di:", opts: ["Il periodo romantico", "Il periodo barocco — una serie di danze stilizzate a tempi e caratteri diversi", "L'impressionismo", "Il periodo classico viennese"], a: 1, fb: "La suite barocca è una raccolta di danze stilizzate (concepite per l'ascolto, non per il ballo): allemanda (moderato), corrente (veloce), sarabanda (lenta), giga (molto veloce), a volte con altre danze. Bach compose numerose suite per clavicembalo, liuto e orchestra. È una forma emblematicamente barocca." },
  { q: "Lo stile del 'concerto grosso' (Vivaldi, Haendel, Corelli) mette in contrasto:", opts: ["Un solista e un'orchestra da camera, alternandosi nel dialogo", "Solo clavicembalo e archi", "Un piccolo gruppo di solisti (concertino) contro la grande orchestra (ripieno), in alternanza e dialogo", "Voce e orchestra"], a: 2, fb: "Il concerto grosso barocco mette in contrasto due ensemble: il concertino (piccolo gruppo di solisti) e il ripieno (grande orchestra). I loro scambi creano un dialogo di masse sonore tipico del barocco. Vivaldi perfezionò questo principio con i suoi oltre 500 concerti per violino e orchestra." },
  { q: "Quale criterio identifica in modo più affidabile un'opera del periodo barocco?", opts: ["La presenza della chitarra elettrica", "Il basso continuo, il contrappunto rigoroso e le cadenze frequenti e affermate", "La totale assenza di cromatismo", "Gli accordi di settima sempre senza risoluzione"], a: 1, fb: "Tre criteri combinati identificano il barocco: (1) basso continuo con cifratura armonica, (2) contrappunto tra voci indipendenti, (3) cadenze frequenti e ben affermate con abbellimenti. Nessun singolo criterio è sufficiente da solo, ma la loro combinazione è caratteristica." },

  // ── ARGOMENTO 2: Identificazione del periodo classico ────────────────────
  { q: "Il 'basso di Alberti' è un accompagnamento tipico del periodo classico. Consiste in:", opts: ["Un basso contrappuntistico in contrappunto rigoroso", "Un arpeggio spezzato di tre note: fondamentale – quinta – terza – quinta, ripetuto", "Un basso che sale cromaticamente", "Un basso continuo cifrato"], a: 1, fb: "Il basso di Alberti è una formula di accompagnamento molto caratteristica dello stile classico viennese: si alternano fondamentale – nota alta – terza – nota alta in un movimento regolare. Mozart e Haydn lo usano abbondantemente nelle loro sonate e sinfonie. Il nome deriva dal compositore Domenico Alberti." },
  { q: "Le frasi simmetriche (periodi di 4+4 battute) sono caratteristiche di:", opts: ["L'improvvisazione barocca", "Il periodo classico viennese (Mozart, Haydn)", "L'impressionismo di Debussy", "Il tardo romanticismo di Wagner"], a: 1, fb: "Lo stile classico viennese struttura sistematicamente la musica in frasi simmetriche di 4+4 battute: una proposizione (antecedente) e una risposta (conseguente). Questa simmetria crea una logica formale molto percettibile, molto diversa dal contrappunto continuo barocco o dal flusso romantico." },
  { q: "Come vengono utilizzate le cadenze nel periodo classico rispetto al barocco?", opts: ["Le cadenze classiche sono più ambigue e vengono evitate — il classicismo preferisce la continuità", "Sono chiare, ben affermate e strutturano le frasi in modo simmetrico — simile al barocco ma in un contesto più omofonico", "Le cadenze scompaiono nel classicismo", "Le cadenze classiche sono sempre plagali (IV–I)"], a: 1, fb: "Il classicismo mantiene cadenze chiare e affermate, ma in un contesto più omofonico rispetto al barocco. Le cadenze perfette V–I strutturano le frasi di 4+4 battute in modo molto leggibile. Questa chiarezza cadenziale sistematica si differenzia dal romanticismo (cadenze evitate) e dall'impressionismo (cadenze assenti)." },
  { q: "La sonata classica (forma sonata) presenta una struttura caratteristica:", opts: ["Il tema A ripetuto indefinitamente", "Esposizione (2 temi) – Sviluppo – Riesposizione: opposizione e risoluzione di tensioni tonali", "Introduzione – Aria – Recitativo – Coda soltanto", "Variazioni continue su un tema di basso"], a: 1, fb: "La forma sonata classica segue uno schema tripartito: Esposizione (tema principale I, ponte, tema secondario V o III), Sviluppo (elaborazione armonica, frammentazione), Riesposizione (ritorno di entrambi i temi in I). Questo principio di opposizione tonale (I contro V) e successiva risoluzione definisce l'estetica classica." },
  { q: "Mozart (1756–1791) e Haydn (1732–1809) rappresentano:", opts: ["L'avanguardia del loro tempo, incompresa dai contemporanei", "Il cuore del classicismo viennese — equilibrio formale, chiarezza armonica, eleganza melodica", "Il tardo barocco, continuatori di Bach", "I precursori diretti dell'impressionismo"], a: 1, fb: "Mozart e Haydn incarnano l'ideale classico: equilibrio tra forma ed espressione, chiarezza armonica attorno alle funzioni I–IV–V, economia dei mezzi (nessun cromatismo inutile), eleganza melodica. Le loro opere definiscono lo standard stilistico a cui l'analisi si riferisce per identificare il classicismo." },
  { q: "L'armonia nello stile classico viennese è caratterizzata da:", opts: ["Saturazione cromatica e modulazioni frequenti per terze", "Economia armonica — pochi accordi (principalmente I, IV, V, II, VI) usati con chiarezza e logica funzionale", "Totale assenza di dominanti secondarie", "Accordi di nona, undicesima e tredicesima sistematici"], a: 1, fb: "Lo stile classico viennese si distingue per la sua economia armonica: Mozart e Haydn usano principalmente I, IV, V e loro rivolti, con alcune dominanti secondarie mirate. Nessun cromatismo eccessivo — la chiarezza funzionale ha la precedenza. Questo equilibrio lo distingue dal romanticismo sovrabbondante." },
  { q: "In un minuetto classico, la forma tipica è:", opts: ["Tema – Variazioni – Coda", "A (minuetto) – B (trio) – A (da capo) con struttura interna di 8+8 battute", "Fuga a 4 voci – Strette – Finale", "Introduzione – Allegro – Finale"], a: 1, fb: "Il minuetto classico segue la forma ternaria A–B–A (da capo): il minuetto principale, un trio contrastante (spesso nella tonalità della dominante o del relativo), poi ritorno del minuetto. Ogni sezione è strutturata in 8+8 battute simmetriche. È una forma molto riconoscibile del classicismo." },
  { q: "Come si riconosce stilisticamente un quartetto d'archi classico?", opts: ["Dalla presenza di un clavicembalo continuo nel basso", "Da quattro voci in scrittura principalmente omofonica, con scambi tematici tra gli strumenti, senza basso continuo", "Dalla presenza sistematica di una voce di basso indipendente contrappuntistica", "Dall'assenza del violoncello"], a: 1, fb: "Il quartetto classico (2 violini, viola, violoncello) abbandona il basso continuo barocco in favore di un dialogo tra le quattro voci. La scrittura è spesso omofonica con passaggi dialogati — lontana dal contrappunto barocco. Haydn fondò la forma; Mozart e Beethoven la perfezionarono." },
  { q: "Beethoven (1770–1827) è spesso collocato al confine tra classicismo e romanticismo. Cosa lo colloca lì?", opts: ["Compone esclusivamente fughe barocche", "Inizia nello stile classico viennese ma introduce progressivamente espressione drammatica, cromatismo accresciuto e forme allargate", "Non usa mai le funzioni classiche I–IV–V", "Il suo stile è identico a quello di Mozart"], a: 1, fb: "Beethoven parte dal classicismo ereditato da Haydn e Mozart ma lo allunga progressivamente: forme allungate (sinfonie 20-45 min), cromatismo espressivo accresciuto, contrasti dinamici radicali (pp subito ff), strutture armoniche più complesse. Le sue ultime opere (op. 130-135) prefigurano il romanticismo e persino il modernismo." },
  { q: "Per identificare uno stile classico viennese, quale triade di criteri è più pertinente?", opts: ["Basso continuo + fuga + cadenze evitate", "Frasi simmetriche 4+4 + armonia parsimoniosa + cadenze perfette affermate", "Cromatismo totale + modulazioni per terze + accordi alterati", "Modi greci + parallelismi + assenza di risoluzione V–I"], a: 1, fb: "Lo stile classico viennese si riconosce da tre criteri combinati: (1) frasi simmetriche di 4+4 battute con antecedente-conseguente, (2) armonia parsimoniosa attorno a I, IV, V, (3) cadenze perfette ben affermate che strutturano le frasi. Questa triade contrasta con il contrappunto barocco e il cromatismo romantico." },
  { q: "Nel periodo classico, le modulazioni avvengono principalmente:", opts: ["Verso tonalità molto lontane (terza, mediante)", "Verso la dominante (V) o il relativo minore/maggiore — tonalità vicine a ±1 diesis/bemolle", "Verso il tritono (sostituzione del tritono)", "Le modulazioni sono assenti nel periodo classico"], a: 1, fb: "Il classicismo modula principalmente verso tonalità vicine: dominante (V), relativo minore o maggiore, sopradominante. Queste modulazioni sono chiaramente affermate da cadenze nella nuova tonalità. Le modulazioni lontane (per terze) arrivano con il romanticismo." },

  // ── ARGOMENTO 3: Identificazione del romanticismo ─────────────────────────
  { q: "Il cromatismo romantico è caratterizzato da:", opts: ["L'uso esclusivo della scala diatonica senza alcuna alterazione", "Frequenti alterazioni cromatiche che arricchiscono e colorano l'armonia senza necessariamente modulare", "Quinte parallele sistematiche", "La totale assenza della sensibile"], a: 1, fb: "Il cromatismo romantico (Schubert, Chopin, Wagner) introduce alterazioni frequenti che arricchiscono il colore armonico: accordi in prestito, alterazioni espressive, note cromatiche nelle linee melodiche. Queste alterazioni creano tensioni che possono restare senza risoluzione immediata — lontano dalla chiarezza classica." },
  { q: "Le modulazioni per terza (es. Do maggiore → Mi maggiore) sono caratteristiche di:", opts: ["Il barocco rigoroso", "Il romanticismo (Schubert, in particolare)", "L'impressionismo soltanto", "Il periodo classico viennese"], a: 1, fb: "Le modulazioni per terza (Do → Mi, Do → Lab) sono una firma del romanticismo, in particolare di Schubert. Aggirano il circuito delle quinte classico (Do → Sol → Re...) per creare cambiamenti armonici sorprendenti e coloriti. Wagner le userà poi sistematicamente per creare effetti di luce orchestrale." },
  { q: "L'accordo di sesta aumentata (italiano, francese o tedesco) è tipico di:", opts: ["Il barocco di Bach", "Il periodo classico senza alterazioni", "Il romanticismo — prepara la dominante con un'ulteriore tensione cromatica", "L'impressionismo di Debussy"], a: 2, fb: "L'accordo di sesta aumentata (fondamentale + terza + sesta aumentata, con varianti) è una tecnica romantica per eccellenza. Prepara la dominante con una doppia tensione cromatica: due note convergono cromaticamente verso V per semitoni opposti. Schubert, Chopin e Brahms lo usano regolarmente." },
  { q: "Wagner (1813–1883) è noto per l'uso dell'accordo di Tristano (inizio di Tristano e Isotta, 1859). Perché è rivoluzionario?", opts: ["Perché evita ogni dissonanza", "Perché è profondamente ambiguo tonalmente — le sue molteplici risoluzioni possibili mettono in discussione la tonalità funzionale", "Perché usa soltanto la scala per toni interi", "Perché si risolve immediatamente su I"], a: 1, fb: "L'accordo di Tristano (Fa–Si–Re#–Sol#) è rivoluzionario per la sua ambiguità tonale: può essere analizzato come accordo di settima di sensibile semidiminuito, accordo francese di sesta aumentata, o altro a seconda del contesto. La sua risoluzione sospesa per tutta l'ouverture simbolizza il desiderio inappagato — e inaugura il crollo della tonalità." },
  { q: "Il Leitmotiv wagneriano è:", opts: ["Una tecnica barocca del basso continuo", "Un motivo musicale associato a un personaggio, un'idea o un sentimento, trasformato nel corso dell'opera", "Una forma di sonata classica", "Un abbellimento melodico tipico del romanticismo"], a: 1, fb: "Il Leitmotiv è una tecnica narrativa inventata da Wagner: un breve motivo melodico-armonico viene associato a un elemento drammatico (personaggio, oggetto, sentimento) e ritorna trasformato nel corso dell'opera. Questa tecnica influenza tutta la musica cinematografica contemporanea — John Williams vi attinge direttamente." },
  { q: "Chopin (1810–1849) è celebre per le sue armonie romantiche al pianoforte. Quale elemento le caratterizza?", opts: ["La rigidità funzionale I–IV–V senza deviazioni", "Una ricchezza cromatica, appoggiature espressive, pedale armonico e un uso poetico degli accordi in prestito", "La totale assenza di modulazione", "Una scrittura puramente contrappuntistica tipo fuga"], a: 1, fb: "Chopin innova attraverso la sua ricchezza armonica pianistica: appoggiature lunghe ed espressive, pedale armonico (note tenute sotto armonie mutevoli), modulazioni inaspettate, accordi in prestito (bVI in maggiore), cromatismo melodico. I suoi Notturni sono un dizionario vivente dell'armonia romantica." },
  { q: "La 'melodia infinita' (unendliche Melodie) di Wagner è definita come:", opts: ["Una melodia che si ripete esattamente all'infinito", "Un flusso melodico continuo che evita le cadenze conclusive e le frasi simmetriche, creando una tensione sostenuta", "Una melodia suonata solo dai violini senza accompagnamento", "Una melodia in modo dorico senza cadenza"], a: 1, fb: "La melodia infinita wagneriana rifiuta le cadenze conclusive e le frasi simmetriche classiche. Il flusso musicale è continuo, le tensioni restano irrisolte per lunghe durate. È l'opposto della frase classica di 4+4 battute — una sospensione permanente che genera il desiderio e l'attesa propri del dramma wagneriano." },
  { q: "Schubert (1797–1828) è celebre per i suoi Lieder (per voce e pianoforte). Cosa li caratterizza armonicamente?", opts: ["Un'armonia semplice e classica I–IV–V senza deviazioni", "Modulazioni inaspettate, prestiti dal minore al maggiore (bVI, bVII), cromatismo espressivo al servizio del testo poetico", "La totale assenza di pedale armonico", "Cadenze plagali esclusive"], a: 1, fb: "I Lieder di Schubert sono armonicamente innovativi per il loro tempo: modulazioni verso tonalità lontane (per terze), costanti prestiti dal modo parallelo minore (bVI, bVII in maggiore), cromatismo melodico e armonico. L'intero discorso armonico è al servizio del testo — la musica illustra e amplifica le immagini poetiche." },
  { q: "La crescente ambiguità tonale del tardo romanticismo (Wagner, Liszt) porta verso:", opts: ["Un ritorno al barocco rigoroso", "L'atonalismo del XX secolo — la tonalità svanisce progressivamente quando le dissonanze cessano di risolversi", "Il classicismo viennese di Haydn", "Solo l'impressionismo di Debussy"], a: 1, fb: "Il tardo romanticismo (il Tristano di Wagner, i Poemi sinfonici di Liszt, il tardo Brahms) spinge la tonalità ai suoi limiti: dissonanze sempre più lunghe senza risoluzione, modulazioni verso tonalità lontane, ambiguità del centro tonale. Questa evoluzione porta direttamente a Schoenberg e all'atonalismo — la tonalità non può più sostenersi." },
  { q: "Per identificare un'opera romantica, quale triade di criteri è più pertinente?", opts: ["Basso continuo + fuga + modulazioni vicine", "Frasi simmetriche + armonia parsimoniosa + basso di Alberti", "Cromatismo espressivo + modulazioni per terze + accordi alterati (bVI, seste aumentate)", "Parallelismi + modi greci + assenza di V–I"], a: 2, fb: "Il romanticismo si riconosce da tre criteri: (1) cromatismo espressivo frequente, (2) modulazioni per terze o verso tonalità lontane, (3) accordi alterati e in prestito (bVI in maggiore, sesta napoletana, seste aumentate). Questo cromatismo armonico lo distingue chiaramente dal classicismo parsimonioso e dall'impressionismo colorista." },
  { q: "La forma del poema sinfonico (Liszt, Strauss) è caratteristica di:", opts: ["Il periodo barocco — è una suite di danze", "Il romanticismo — un'opera orchestrale in un unico movimento con programma letterario o pittorico", "Il periodo classico — è una sinfonia in 4 movimenti", "L'impressionismo — è un pezzo atonale"], a: 1, fb: "Il poema sinfonico (termine coniato da Liszt) è un'opera orchestrale in un unico movimento ispirata a un programma extra-musicale (poesia, dipinto, racconto mitologico). Liszt ne compose una dozzina; Richard Strauss portò quest'arte al vertice (Don Juan, Till Eulenspiegel, Così parlò Zarathustra). È una forma emblematicamente romantica." },

  // ── ARGOMENTO 4: Identificazione dell'impressionismo ─────────────────────
  { q: "Il 'planing' armonico è una tecnica associata a:", opts: ["Bach e il contrappunto rigoroso", "L'impressionismo di Debussy e Ravel — movimento parallelo di tutti gli intervalli di un accordo", "Il romanticismo di Wagner", "Il periodo classico"], a: 1, fb: "Il planing (o movimento parallelo) consiste nello spostare un intero accordo in movimento parallelo — tutte le voci si muovono nella stessa direzione dello stesso intervallo. Bach lo vieta (quinte parallele = errore). Debussy ne fa una tecnica deliberata: gli accordi scivolano come macchie di colore, senza risoluzione funzionale." },
  { q: "La scala per toni interi (Do–Re–Mi–Fa#–Sol#–La#–Do) è caratteristica di:", opts: ["La scrittura barocca in modo dorico", "L'impressionismo di Debussy — crea una totale ambiguità tonale, senza sensibile né sottotonica", "Il periodo classico viennese", "Il cromatismo romantico di Wagner"], a: 1, fb: "La scala per toni interi è una scala a 6 suoni in cui ogni grado è separato da un tono intero. Senza semitoni, non ha sensibile né sottotonica — impossibile trovare una tonica chiara. Debussy la usa per creare atmosfere fluttuanti e colori armonici ambigui, senza tensione-risoluzione funzionale." },
  { q: "I modi medievali (dorico, frigio, lidio, misolidio) tornano in auge con:", opts: ["Bach e il tardo barocco", "Il classicismo di Mozart", "L'impressionismo e la musica di Debussy e Ravel", "Wagner e il tardo romanticismo"], a: 2, fb: "Debussy e Ravel riscoprivono i modi medievali per sfuggire alla tonalità maggiore-minore e alle sue funzioni obbligatorie. Il modo dorico (senza sottotonica rialzata), il frigio (sensibile abbassata), il lidio (quarta aumentata), il misolidio (settima abbassata) offrono nuovi colori. Questi modi ritornano anche nel jazz e nella musica del XX secolo." },
  { q: "Come Debussy usa gli accordi rispetto alla tensione-risoluzione classica?", opts: ["Rafforza la tensione-risoluzione V–I con più dissonanze del classicismo", "I suoi accordi sono macchie di colore che progrediscono per colore e registro — la tensione-risoluzione funzionale viene abbandonata", "Usa solo la cadenza plagale IV–I", "Risolve tutte le dissonanze su I secondo le regole classiche"], a: 1, fb: "Per Debussy, un accordo non è una funzione in un sistema di tensione-risoluzione — è un colore sonoro. Gli accordi di nona, undicesima, tredicesima non 'si risolvono'; scivolano verso altri colori. Questo pensiero armonico-cromatico piuttosto che funzionale è la rivoluzione impressionista: il colore prevale sulla funzione." },
  { q: "La scala pentatonica (Do–Re–Mi–Sol–La–Do, senza Fa né Si) è usata da Debussy per:", opts: ["Rafforzare la cadenza V–I eliminando la sottodominante", "Creare atmosfere esotiche e fluttuanti, influenzate dalla musica asiatica (gamelan giavanese ascoltato all'Esposizione Universale del 1889)", "Semplificare l'armonia per i principianti", "Ritrovare la purezza della musica barocca"], a: 1, fb: "Debussy scopre il gamelan giavanese all'Esposizione Universale di Parigi nel 1889 — rimane affascinato dai suoi suoni esotici basati sulla pentatonica. La scala pentatonica (5 suoni senza semitoni) crea un'atmosfera fluttuante e sospesa. Questa influenza orientale nutre il suo impressionismo: La cattedrale sommersa, Estampes." },
  { q: "Ravel (1875–1937) e Debussy sono spesso associati all'impressionismo. Quale differenza stilistica principale li distingue?", opts: ["Ravel usa la scala per toni, Debussy solo la pentatonica", "Ravel conserva una logica formale più classica e un contrappunto più rigoroso; Debussy è più libero e fluttuante nelle sue forme", "I due sono stilisticamente identici", "Debussy è più classico, Ravel più impressionista"], a: 1, fb: "Nonostante la loro associazione, Ravel e Debussy differiscono: Ravel mantiene una logica formale più netta (soprattutto nelle sue forme sonata), un contrappunto più rigoroso, un'architettura più chiara. Debussy è più libero nelle sue forme, più fluttuante nelle sue progressioni. Lo stesso Ravel affermava di non essere 'impressionista'." },
  { q: "Nell'impressionismo musicale, il titolo di un pezzo (La cattedrale sommersa, Il mare, Giochi d'acqua) suggerisce:", opts: ["Un programma drammatico come le opere di Wagner", "Impressioni sensoriali, immagini evocative piuttosto che una narrazione — la musica dipinge un'atmosfera", "Un riferimento a una forma classica astratta", "Un tema religioso soltanto"], a: 1, fb: "I titoli impressionisti evocano impressioni sensoriali, luci, riflessi, texture — non drammi o narrazioni. Il mare di Debussy non è una tempesta narrativa (come il op.110 di Beethoven) — è un'impressione del mare in momenti diversi. L'ispirazione viene dalla pittura impressionista (Monet): cogliere l'istante, la luce, non l'oggetto." },
  { q: "Sono permesse le quinte e le ottave parallele nell'armonia impressionista?", opts: ["No — le regole del contrappunto rigoroso si applicano sempre", "Sì — è persino una tecnica deliberata (planing) in Debussy", "Sì, ma solo a distanza di ottava", "No, ma le quinte sono ammesse se il moto è contrario"], a: 1, fb: "Le quinte e le ottave parallele sono vietate nel contrappunto classico e barocco. Debussy le usa deliberatamente come tecnica espressiva — il planing crea questo effetto di colori scorrevoli. Ciò che è un errore in uno stile (barocco, classico) è una tecnica in un altro (impressionismo). Il contesto storico è determinante." },
  { q: "Per identificare un'opera impressionista, quale triade di criteri è più pertinente?", opts: ["Basso continuo + fuga + cadenze frequenti", "Frasi simmetriche + cadenze V–I affermate + basso di Alberti", "Accordi paralleli (planing) + modi/scala per toni/pentatonica + assenza di risoluzione funzionale V–I", "Cromatismo denso + modulazioni per terze + accordi alterati"], a: 2, fb: "L'impressionismo si riconosce da tre criteri: (1) accordi paralleli (planing) senza risoluzione funzionale, (2) uso di modi, scala per toni e pentatonica, (3) assenza o dissoluzione della cadenza funzionale V–I. Questa triade lo distingue chiaramente dal romanticismo (cromatismo funzionale) e dal classicismo (funzioni chiare)." },
  { q: "Cosa distingue il cromatismo romantico dal cromatismo impressionista?", opts: ["Non c'è alcuna differenza tra i due", "Il romanticismo usa il cromatismo per creare tensioni funzionali che vengono risolte; l'impressionismo usa colori non funzionali (modi, toni interi) senza tensione-risoluzione obbligatoria", "L'impressionismo è più cromatico del romanticismo", "Il romanticismo evita il cromatismo"], a: 1, fb: "La distinzione è fondamentale: il cromatismo romantico (Wagner, Chopin) crea tensioni funzionali che richiedono risoluzione — le alterazioni si inscrivono in un sistema tensione-risoluzione. L'impressionismo (Debussy) usa colori non funzionali — modi, scala per toni, pentatonica — senza tensione-risoluzione obbligatoria. Non è 'più cromatismo', è un uso radicalmente diverso." },

  // ── ARGOMENTO 5: Confronto stilistico ────────────────────────────────────
  { q: "La stessa melodia Do–Mi–Sol–Do armonizzata 'alla maniera di Bach' e 'alla maniera di Debussy' differisce principalmente in:", opts: ["Il tempo usato per suonarla", "Il trattamento della dominante: Bach la afferma obbligatoriamente (V–I); Debussy può ignorarla totalmente", "La melodia stessa che cambia secondo lo stile", "Lo strumento utilizzato"], a: 1, fb: "La differenza fondamentale tra un'armonizzazione barocca e una impressionista sta nel trattamento della dominante. Bach struttura obbligatoriamente il suo discorso attorno a V–I. Debussy può armonizzare la stessa melodia con accordi di nona in parallelo, senza alcuna risoluzione V–I — la melodia è la stessa, l'armonia è in un universo radicalmente diverso." },
  { q: "Quale compositore usa sistematicamente cadenze perfette affermate (V–I)?", opts: ["Debussy", "Mozart", "Webern", "Messiaen"], a: 1, fb: "Mozart è l'incarnazione dello stile classico con cadenze perfette V–I frequenti e ben affermate, che strutturano le frasi di 4+4 battute. Debussy evita queste cadenze funzionali. Webern e Messiaen appartengono al XX secolo e usano linguaggi post-tonali." },
  { q: "Quale compositore è più noto per le modulazioni per terza (es. Do maggiore → Lab maggiore)?", opts: ["Bach", "Mozart", "Schubert", "Debussy"], a: 2, fb: "Schubert è celebre per le sue modulazioni per terza — uno dei suoi tratti stilistici più riconoscibili. Nei suoi Lieder e nelle sonate scivola frequentemente verso tonalità a distanza di terza (maggiore o minore), creando cambiamenti di colore improvvisi e poetici. Bach modula per quinte; Mozart verso tonalità vicine; Debussy evita le funzioni modulanti." },
  { q: "Quale compositore è associato al concetto di 'melodia infinita' (flusso continuo che evita le cadenze conclusive)?", opts: ["Haydn", "Chopin", "Wagner", "Vivaldi"], a: 2, fb: "Wagner inventa il concetto di melodia infinita (unendliche Melodie) per i suoi drammi musicali: il flusso orchestrale e vocale evita le cadenze conclusive, creando una tensione sostenuta senza risoluzione. È l'opposto della simmetria classica di 4+4 battute. Haydn e Vivaldi vivono in un mondo di frasi regolarmente cadenzate." },
  { q: "Quale compositore è noto per il basso di Alberti (fondamentale–quinta–terza–quinta ripetuto)?", opts: ["Bach e il contrappunto", "Mozart e lo stile classico viennese", "Debussy e l'impressionismo", "Wagner e il tardo romanticismo"], a: 1, fb: "Il basso di Alberti è una firma dello stile classico viennese, in particolare di Mozart. Questa formula di accompagnamento onnipresente nelle sue sonate per pianoforte sostituisce il contrappunto barocco con un accompagnamento omofonico regolare. Debussy se ne allontana radicalmente; Bach non lo usa mai." },
  { q: "Un pezzo che usa modi greci (dorico, lidio, misolidio) e accordi paralleli è probabilmente:", opts: ["Una fuga barocca di Bach", "Una sonata classica di Haydn", "Un'opera impressionista di Debussy o Ravel", "Un Lied romantico di Schubert"], a: 2, fb: "I modi greci e gli accordi paralleli (planing) sono firme impressioniste. Bach e Haydn non usano modi greci nella loro armonia — lavorano nel sistema maggiore/minore. Schubert usa a volte il modo dorico ma senza parallelismi. Debussy combina deliberatamente modi, scala per toni e planing." },
  { q: "Un pezzo che usa intensamente il tritono come tensione irrisolta è caratteristico di:", opts: ["L'armonia classica di Mozart (il tritono è sempre risolto)", "Il tardo romanticismo di Wagner dove le dissonanze restano irrisolte a lungo", "La musica barocca dove il tritono è severamente vietato", "La scala pentatonica che contiene molti tritoni"], a: 1, fb: "Il tritono (diabolus in musica) deve essere risolto nella musica classica e barocca. Wagner nel Tristano usa il tritono in modo ricorrente lasciando la sua risoluzione sospesa per lunghe durate — un'audacia armonica che simboleggia il desiderio inappagato. La scala pentatonica non contiene tritoni (è proprio per questo che suona 'dolce')." },
  { q: "Quale stile armonico NON usa la progressione V–I come cadenza strutturante?", opts: ["Il barocco di Bach", "Il classicismo di Mozart", "Il romanticismo di Schubert", "L'impressionismo di Debussy"], a: 3, fb: "Bach, Mozart e Schubert (nella loro scrittura tonale) usano tutti la progressione V–I come cadenza strutturante fondamentale. Debussy abbandona deliberatamente questo principio: i suoi accordi progrediscono per colore e registro, non per tensione-risoluzione. Cercare cadenze V–I funzionali nell'impressionismo significa applicare lo strumento analitico sbagliato." },
  { q: "Un accordo di nona maggiore irrisolto, seguito da un accordo di nona un semitono più in alto (planing), è caratteristico di:", opts: ["Una fuga barocca", "Una sonata classica", "L'impressionismo di Debussy", "Un Lied romantico di Brahms"], a: 2, fb: "Il planing di accordi complessi (nona, undicesima, tredicesima) senza risoluzione è una tecnica impressionista tipica. Un accordo di nona maggiore che scivola di un semitono verso un altro accordo di nona non ha senso nel sistema tensione-risoluzione classico o romantico — è movimento per colore, non per funzione. Questo è Debussy in azione." },
  { q: "Analizzare i 'Préludes pour piano' di Debussy con le funzioni T/SD/D è:", opts: ["Pertinente — Debussy usa le funzioni tonali classiche nonostante le sue dissonanze", "Controproducente — i suoi accordi sono colori, non funzioni; l'analisi modale e timbrica è più adatta", "Obbligatorio per qualsiasi analisi armonica seria", "Appropriato solo per i preludi barocchi"], a: 1, fb: "Applicare le funzioni T/SD/D a Debussy significa usare lo strumento sbagliato: i suoi accordi non funzionano come tensioni verso una risoluzione. Un'analisi pertinente dei Préludes di Debussy esamina i modi usati, i parallelismi, i colori timbrici, i rapporti di registro — non 'dominanti' e 'sottodominanti' funzionali." },
  { q: "Per identificare l'epoca di un'opera in base a 3 indizi, occorre esaminare:", opts: ["Il paese del compositore, lo strumento utilizzato e la lunghezza del pezzo", "La densità del cromatismo, la presenza o assenza della risoluzione V–I e il trattamento delle dissonanze", "Solo tempo, dinamica e articolazione", "Il numero di movimenti, la tonalità e il compositore"], a: 1, fb: "I tre indizi più rivelatori dell'epoca storica di un'opera: (1) densità del cromatismo (bassa=barocco/classico, media=romantico, per colore=impressionismo), (2) presenza/assenza di V–I (obbligatorio=barocco/classico, evitato=tardo romanticismo, assente=impressionismo), (3) trattamento delle dissonanze (risoluzione immediata=barocco, prolungata=romanticismo, irrisolta=impressionismo)." },
  { q: "Quale compositore 'conosceva perfettamente le regole che trasgrediva' — illustrando che la libertà richiede la padronanza preliminare?", opts: ["Bach — che ignorava le regole modali per creare liberamente", "Debussy — la cui libertà impressionista si basa su una perfetta padronanza del contrappunto e dell'armonia classica", "Mozart — che trasgrediva le regole della sonata classica", "Haendel — le cui quinte parallele sono intenzionali"], a: 1, fb: "Debussy illustra perfettamente il paradosso della libertà creativa: studiò contrappunto e armonia classica al Conservatorio di Parigi (Prix de Rome 1884), padroneggiando perfettamente le regole che avrebbe trasgredito. La sua apparente libertà è calcolata — non ignoranza. Per liberarsi dalle regole, bisogna prima padroneggiarle." },
  { q: "Il post-romanticismo (tardo Wagner, Mahler, Richard Strauss) si distingue dal romanticismo per:", opts: ["L'abbandono del cromatismo e il ritorno al diatonismo classico", "Un cromatismo ancora più denso, accordi di nona–undicesima–tredicesima, una tonalità presente ma allargata e lunghe tensioni mantenute", "L'uso della scala per toni e del planing impressionista", "La struttura in fuga contrappuntistica"], a: 1, fb: "Il post-romanticismo amplifica il romanticismo: cromatismo totale (tutti i 12 suoni possono apparire in un breve estratto), accordi di nona, undicesima, tredicesima a lungo irrisolti, tonalità mantenuta ma sotto tensione estrema. È la tonalità al suo limite prima dell'atonalismo — Mahler e Strauss si trovano in questo spazio tra romanticismo e modernismo." },
  { q: "Se un'opera ha chiare cadenze V–I ma anche accordi di dominante secondaria e alcune modulazioni per terze, è probabilmente:", opts: ["Rigorosamente barocca", "Del romanticismo (Schubert, primo Chopin) — le funzioni tonali rimangono ma si arricchiscono di cromatismo espressivo", "Dell'impressionismo puro", "Del classicismo rigoroso di Haydn"], a: 1, fb: "Questa descrizione corrisponde al romanticismo moderato (Schubert, primo Chopin): le funzioni tonali V–I rimangono presenti e strutturanti, ma arricchite da cromatismo espressivo, modulazioni per terze, dominanti secondarie. Non è ancora il tardo romanticismo (Wagner) che sospende a lungo le risoluzioni. È la zona di transizione tra classicismo e romanticismo avanzato." },
];

const questionsPt: Question[] = [
  // ── TÓPICO 1: Identificação do período barroco ────────────────────────────
  { q: "Qual técnica é característica do baixo contínuo barroco?", opts: ["Um baixo que imita o soprano", "Um baixo cifrado tocado por um grupo de contínuo (cravo, alaúde, órgão) que sustenta a melodia", "Um baixo que silencia nas cadências", "Um baixo tocado apenas pelos cordofones"], a: 1, fb: "O baixo contínuo (basso continuo) é o fundamento do estilo barroco: uma realização harmônica tocada por instrumentos de acompanhamento (cravo, tiorba, órgão) enquanto a melodia é confiada a outras vozes. É um dos critérios mais seguros para identificar o barroco." },
  { q: "Como reconhecer uma cadência tipicamente barroca?", opts: ["A cadência é evitada ou suspensa — o barroco prefere as semicadências", "A cadência é frequente, afirmada, frequentemente com ornamentos (trinado na sensível)", "O barroco usa apenas a cadência plagal IV–I", "As cadências barrocas nunca caem no tempo forte"], a: 1, fb: "O estilo barroco aprecia as cadências frequentes e bem afirmadas. A cadência autêntica V–I com trinado na sensível é uma marca da época. Essas cadências pontuam o discurso regularmente, estruturando os ritornelos." },
  { q: "O contraponto rigoroso (presença de várias vozes independentes) é característico de:", opts: ["O período clássico somente", "O impressionismo", "O período barroco (Bach, Haendel, Vivaldi)", "O romantismo tardio"], a: 2, fb: "O contraponto — a arte de fazer coexistir várias vozes independentes segundo regras rigorosas — está no coração da escrita barroca. As fugas, invenções e cânones de Bach ilustram essa maestria. O período clássico simplifica a escrita em direção a uma melodia acompanhada." },
  { q: "Qual forma é emblemática da escrita contrapontística barroca?", opts: ["A sonata de Beethoven", "A fuga — exposição de um sujeito desenvolvido por imitação entre as vozes", "A ópera de Wagner", "O prelúdio de Debussy"], a: 1, fb: "A fuga é a forma contrapontística por excelência do barroco. Um sujeito é apresentado a solo, depois retomado por imitação por todas as vozes segundo regras estritas de entrada e resposta. Bach levou essa arte ao auge no Cravo bem temperado e na Arte da fuga." },
  { q: "No estilo barroco, as funções tonais I–IV–V são:", opts: ["Ausentes — o barroco não usa funções tonais", "Presentes mas vagas — a modalidade ainda domina", "Claramente estabelecidas e frequentemente afirmadas por cadências", "Reservadas apenas para as cadências finais"], a: 2, fb: "Ao contrário dos períodos modais anteriores, o barroco estabelece claramente as funções tonais I, IV, V com cadências frequentes e afirmadas. Bach e Haendel estruturam seu discurso sistematicamente em torno da tônica, dominante e subdominante." },
  { q: "Bach (1685–1750) e Haendel (1685–1759) são contemporâneos. Esse fato ilustra:", opts: ["Que os dois compositores tinham o mesmo estilo", "Que mesmo na mesma época, dois compositores podem ter estilos individuais muito distintos", "Que o barroco é um período muito curto", "Que todos os barrocos são identificáveis pelos mesmos traços exatos"], a: 1, fb: "Bach e Haendel são rigorosamente contemporâneos, mas estilisticamente diferentes: Bach cultiva o contraponto complexo e a introspecção luterana; Haendel escreve óperas italianas e oratórios espetaculares. A época fornece uma moldura, mas a assinatura individual sempre prevalece." },
  { q: "O cravo é o instrumento de teclado emblemático do barroco. Por que é diferente do piano?", opts: ["Tem menos teclas", "O som é produzido por pinçamento das cordas (sem nuance dinâmica pelo toque) — o piano produz o som por percussão e permite as nuances dinâmicas", "Não existe mais desde o classicismo", "Soa exatamente como um piano, mas mais agudo"], a: 1, fb: "O cravo produz seu som por pinçamento das cordas via um plectro — o volume é constante independentemente da pressão dos dedos. O piano (fortepiano, depois pianoforte), introduzido no classicismo, permite variar a intensidade pelo toque. Essa diferença explica os ornamentos frequentes do barroco para compensar a impossibilidade do crescendo." },
  { q: "Na música barroca, a ornamentação (trilos, mordentes, apogiaturas) tem como papel principal:", opts: ["Decorar arbitrariamente a melodia para torná-la mais complexa", "Substituir as nuances dinâmicas impossíveis no cravo, articular as dissonâncias e marcar as cadências", "Indicar a tonalidade ao público", "Substituir as notas ausentes da escala"], a: 1, fb: "A ornamentação barroca é funcional: no cravo (sem nuances dinâmicas), os trilos allongam os sons e marcam os apoios; os mordentes e apogiaturas criam tensões expressivas; os ornamentos cadenciais sinalizam os finais de frase. Não é decoração — é sintaxe musical." },
  { q: "A 'Suite' barroca (allemande, courante, sarabanda, giga) é característica de:", opts: ["O período romântico", "O período barroco — série de danças estilizadas em tempos e carácteres diferentes", "O impressionismo", "O período clássico vienense"], a: 1, fb: "A suite barroca é uma coleção de danças estilizadas (concebidas para a audição, não para dançar): allemande (moderado), courante (rápida), sarabanda (lenta), giga (muito rápida), às vezes com outras danças. Bach compôs numerosas suites para cravo, alaúde e orquestra. É uma forma emblemática do barroco." },
  { q: "O estilo 'concerto grosso' (Vivaldi, Haendel, Corelli) contrapõe:", opts: ["Um solista e uma orquestra de câmara, alternando-se no diálogo", "Apenas cravo e cordas", "Um pequeno grupo de solistas (concertino) contra a grande orquestra (ripieno), em alternância e diálogo", "A voz e a orquestra"], a: 2, fb: "O concerto grosso barroco contrapõe dois conjuntos: o concertino (pequeno grupo de solistas) e o ripieno (grande orquestra). Suas trocas criam um diálogo de massas sonoras típico do barroco. Vivaldi aperfeiçoou esse princípio com seus mais de 500 concertos para violino e orquestra." },
  { q: "Qual critério identifica de forma mais segura uma obra do período barroco?", opts: ["A presença de guitarra elétrica", "O baixo contínuo, o contraponto rigoroso e as cadências frequentes e afirmadas", "A ausência total de cromatismo", "Os acordes de sétima sempre sem resolução"], a: 1, fb: "Três critérios combinados identificam o barroco: (1) baixo contínuo com cifragem harmônica, (2) contraponto entre vozes independentes, (3) cadências frequentes e bem afirmadas com ornamentos. Nenhum critério isolado é suficiente, mas sua combinação é característica." },

  // ── TÓPICO 2: Identificação do período clássico ───────────────────────────
  { q: "O 'baixo de Alberti' é um acompanhamento típico do período clássico. Consiste em:", opts: ["Um baixo contrapontístico em contraponto estrito", "Um arpejo quebrado de três notas: fundamental – quinta – terça – quinta, repetido", "Um baixo que sobe cromaticamente", "Um baixo contínuo cifrado"], a: 1, fb: "O baixo de Alberti é uma fórmula de acompanhamento muito característica do estilo clássico vienense: alterna-se fundamental – nota alta – terça – nota alta em um movimento regular. Mozart e Haydn o usam abundantemente em suas sonatas e sinfonias. Seu nome vem do compositor Domenico Alberti." },
  { q: "As frases simétricas (períodos de 4+4 compassos) são características de:", opts: ["A improvisação barroca", "O período clássico vienense (Mozart, Haydn)", "O impressionismo de Debussy", "O romantismo tardio de Wagner"], a: 1, fb: "O estilo clássico vienense estrutura sistematicamente a música em frases simétricas de 4+4 compassos: uma proposição (antecedente) e uma resposta (consequente). Essa simetria cria uma lógica formal muito perceptível, muito diferente do contraponto contínuo barroco ou do fluxo romântico." },
  { q: "Como são usadas as cadências no período clássico em comparação ao barroco?", opts: ["As cadências clássicas são mais ambíguas e evitadas — o classicismo prefere a continuidade", "São claras, bem afirmadas e estruturam as frases de forma simétrica — semelhante ao barroco, mas em um contexto mais homofônico", "As cadências desaparecem no classicismo", "As cadências clássicas são sempre plagais (IV–I)"], a: 1, fb: "O classicismo mantém cadências claras e afirmadas, mas em um contexto mais homofônico do que o barroco. As cadências perfeitas V–I estruturam as frases de 4+4 compassos de forma muito legível. Essa clareza cadencial sistemática diferencia-se do romantismo (cadências evitadas) e do impressionismo (cadências ausentes)." },
  { q: "A sonata clássica (forma-sonata) apresenta uma estrutura característica:", opts: ["O tema A repetido indefinidamente", "Exposição (2 temas) – Desenvolvimento – Reexposição: oposição e resolução de tensões tonais", "Introdução – Ária – Recitativo – Coda somente", "Variações contínuas sobre um tema de baixo"], a: 1, fb: "A forma-sonata clássica segue um esquema tripartido: Exposição (tema principal I, ponte modulante, tema secundário V ou III), Desenvolvimento (exploração harmônica, fragmentação), Reexposição (retorno dos dois temas em I). Esse princípio de oposição tonal (I contra V) e posterior resolução define a estética clássica." },
  { q: "Mozart (1756–1791) e Haydn (1732–1809) representam:", opts: ["A vanguarda de sua época, incompreendidos pelos contemporâneos", "O coração do classicismo vienense — equilíbrio formal, clareza harmônica, elegância melódica", "O barroco tardio, continuadores de Bach", "Os precursores diretos do impressionismo"], a: 1, fb: "Mozart e Haydn encarnam o ideal clássico: equilíbrio entre forma e expressão, clareza harmônica em torno das funções I–IV–V, economia de meios (sem cromatismo desnecessário), elegância melódica. Suas obras definem o padrão estilístico ao qual a análise se refere para identificar o classicismo." },
  { q: "A harmonia no estilo clássico vienense é caracterizada por:", opts: ["Saturação cromática e modulações frequentes por terças", "Economia harmônica — poucos acordes (principalmente I, IV, V, II, VI) usados com clareza e lógica funcional", "Ausência total de dominantes secundárias", "Acordes de nona, décima-primeira e décima-terceira sistemáticos"], a: 1, fb: "O estilo clássico vienense se distingue por sua economia harmônica: Mozart e Haydn usam principalmente I, IV, V e suas inversões, com algumas dominantes secundárias específicas. Sem cromatismo excessivo — a clareza funcional tem prioridade. É esse equilíbrio que o distingue do romantismo sobrecarregado." },
  { q: "Em um minueto clássico, a forma típica é:", opts: ["Tema – Variações – Coda", "A (minueto) – B (trio) – A (da capo) com estrutura interna de 8+8 compassos", "Fuga a 4 vozes – Estrete – Final", "Introdução – Allegro – Final"], a: 1, fb: "O minueto clássico segue a forma ternária A–B–A (da capo): o minueto principal, um trio contrastante (frequentemente na tonalidade da dominante ou do relativo), depois retorno do minueto. Cada seção é estruturada em 8+8 compassos simétricos. É uma forma muito reconhecível do classicismo." },
  { q: "Como reconhecer estilisticamente um quarteto de cordas clássico?", opts: ["Pela presença de um cravo contínuo no baixo", "Por quatro vozes em escrita principalmente homofônica, com trocas temáticas entre os instrumentos, sem baixo contínuo", "Pela presença sistemática de uma voz de baixo independente contrapontística", "Pela ausência do violoncelo"], a: 1, fb: "O quarteto clássico (2 violinos, viola, violoncelo) abandona o baixo contínuo barroco em favor de um diálogo entre as quatro vozes. A escrita é frequentemente homofônica com passagens dialogadas — longe do contraponto barroco. Haydn fundou a forma; Mozart e Beethoven a aperfeiçoaram." },
  { q: "Beethoven (1770–1827) é frequentemente situado na fronteira entre classicismo e romantismo. O que o coloca lá?", opts: ["Ele compõe exclusivamente fugas barrocas", "Ele começa no estilo clássico vienense, mas introduz progressivamente expressão dramática, cromatismo aumentado e formas ampliadas", "Ele nunca usa as funções clássicas I–IV–V", "Seu estilo é idêntico ao de Mozart"], a: 1, fb: "Beethoven parte do classicismo herdado de Haydn e Mozart, mas o estira progressivamente: formas alongadas (sinfonias 20-45 min), cromatismo expressivo aumentado, contrastes dinâmicos radicais (pp subito ff), estruturas harmônicas mais complexas. Suas últimas obras (op. 130-135) antecipam o romantismo e mesmo o modernismo." },
  { q: "Para identificar um estilo clássico vienense, qual tríade de critérios é mais pertinente?", opts: ["Baixo contínuo + fuga + cadências evitadas", "Frases simétricas 4+4 + harmonia econômica + cadências perfeitas afirmadas", "Cromatismo total + modulações por terças + acordes alterados", "Modos gregos + paralelismos + ausência de resolução V–I"], a: 1, fb: "O estilo clássico vienense reconhece-se por três critérios combinados: (1) frases simétricas de 4+4 compassos com antecedente-consequente, (2) harmonia econômica em torno de I, IV, V, (3) cadências perfeitas bem afirmadas que estruturam as frases. Essa tríade contrasta com o contraponto barroco e o cromatismo romântico." },
  { q: "No período clássico, as modulações ocorrem principalmente:", opts: ["Para tonalidades muito distantes (terça, mediante)", "Para a dominante (V) ou o relativo menor/maior — tonalidades vizinhas com ±1 sustenido/bemol", "Para a tonalidade do trítono (substituição de trítono)", "As modulações estão ausentes no período clássico"], a: 1, fb: "O classicismo modula principalmente para tonalidades próximas: dominante (V), relativo menor ou maior, superdominante. Essas modulações são claramente afirmadas por cadências na nova tonalidade. As modulações distantes (por terças) chegam com o romantismo." },

  // ── TÓPICO 3: Identificação do romantismo ────────────────────────────────
  { q: "O cromatismo romântico é caracterizado por:", opts: ["O uso exclusivo da escala diatônica sem nenhuma alteração", "Frequentes alterações cromáticas que enriquecem e colorem a harmonia sem necessariamente modular", "Quintas paralelas sistemáticas", "A ausência total da sensível"], a: 1, fb: "O cromatismo romântico (Schubert, Chopin, Wagner) introduz alterações frequentes que enriquecem a cor harmônica: acordes emprestados, alterações expressivas, notas cromáticas nas linhas melódicas. Essas alterações criam tensões que podem permanecer sem resolução imediata — longe da clareza clássica." },
  { q: "As modulações por terça (ex. Dó maior → Mi maior) são características de:", opts: ["O barroco estrito", "O romantismo (Schubert, em particular)", "O impressionismo somente", "O período clássico vienense"], a: 1, fb: "As modulações por terça (Dó → Mi, Dó → Láb) são uma assinatura do romantismo, especialmente de Schubert. Elas contornam o circuito das quintas clássico (Dó → Sol → Ré...) para criar mudanças harmônicas surpreendentes e coloridas. Wagner as usará sistematicamente para criar efeitos de luz orquestral." },
  { q: "O acorde de sexta aumentada (italiano, francês ou alemão) é típico de:", opts: ["O barroco de Bach", "O período clássico sem alterações", "O romantismo — ele prepara a dominante com uma tensão cromática adicional", "O impressionismo de Debussy"], a: 2, fb: "O acorde de sexta aumentada (fundamental + terça + sexta aumentada, com variantes) é uma técnica romântica por excelência. Ele prepara a dominante com dupla tensão cromática: duas notas convergem cromaticamente para V por semitons opostos. Schubert, Chopin e Brahms o usam regularmente." },
  { q: "Wagner (1813–1883) é conhecido pelo uso do acorde de Tristão (início de Tristão e Isolda, 1859). Por que ele é revolucionário?", opts: ["Porque evita toda dissonância", "Porque é profundamente ambíguo tonalmente — suas múltiplas resoluções possíveis colocam em questão a tonalidade funcional", "Porque usa apenas a escala de tons inteiros", "Porque resolve imediatamente em I"], a: 1, fb: "O acorde de Tristão (Fá–Si–Ré#–Sol#) é revolucionário por sua ambiguidade tonal: pode ser analisado como acorde de sétima de sensível semidiminuto, acorde francês de sexta aumentada, ou outra coisa dependendo do contexto. Sua resolução suspensa durante toda a abertura simboliza o desejo insatisfeito — e inaugura o colapso da tonalidade." },
  { q: "O Leitmotiv wagneriano é:", opts: ["Uma técnica barroca do baixo contínuo", "Um motivo musical associado a um personagem, uma ideia ou um sentimento, transformado ao longo da ópera", "Uma forma de sonata clássica", "Um ornamento melódico típico do romantismo"], a: 1, fb: "O Leitmotiv é uma técnica narrativa inventada por Wagner: um breve motivo melódico-harmônico é associado a um elemento dramático (personagem, objeto, sentimento) e retorna transformado ao longo da obra. Essa técnica influencia toda a música cinematográfica contemporânea — John Williams inspira-se diretamente nela." },
  { q: "Chopin (1810–1849) é célebre por suas harmonias românticas ao piano. Qual elemento as caracteriza?", opts: ["A rigidez funcional I–IV–V sem desvios", "Uma riqueza cromática, apogiaturas expressivas, pedaleiras harmônicas e um uso poético dos acordes emprestados", "A ausência total de modulação", "Uma escrita puramente contrapontística tipo fuga"], a: 1, fb: "Chopin inova por sua riqueza harmônica pianística: apogiaturas longas e expressivas, pedaleiras harmônicas (notas sustentadas sob harmonias mutáveis), modulações inesperadas, acordes emprestados (bVI em maior), cromatismo melódico. Seus Noturnos são um dicionário vivo da harmonia romântica." },
  { q: "A 'melodia infinita' (unendliche Melodie) de Wagner é definida como:", opts: ["Uma melodia que se repete exatamente ao infinito", "Um fluxo melódico contínuo que evita as cadências conclusivas e as frases simétricas, criando uma tensão sustentada", "Uma melodia tocada apenas pelos violinos sem acompanhamento", "Uma melodia em modo dórico sem cadência"], a: 1, fb: "A melodia infinita wagneriana recusa as cadências conclusivas e as frases simétricas clássicas. O fluxo musical é contínuo, as tensões permanecem sem resolução por longas durações. É o oposto da frase clássica de 4+4 compassos — uma suspensão permanente que gera o desejo e a espera próprios do drama wagneriano." },
  { q: "Schubert (1797–1828) é célebre por seus Lieder (para voz e piano). O que os caracteriza harmonicamente?", opts: ["Uma harmonia simples e clássica I–IV–V sem desvios", "Modulações inesperadas, empréstimos do menor ao maior (bVI, bVII), cromatismo expressivo a serviço do texto poético", "A ausência total de pedaleira harmônica", "Cadências plagais exclusivas"], a: 1, fb: "Os Lieder de Schubert são harmonicamente inovadores para sua época: modulações para tonalidades distantes (por terças), empréstimos constantes do modo paralelo menor (bVI, bVII em maior), cromatismo melódico e harmônico. Todo o discurso harmônico está a serviço do texto — a música ilustra e amplifica as imagens poéticas." },
  { q: "A crescente ambiguidade tonal do romantismo tardio (Wagner, Liszt) leva em direção a:", opts: ["Um retorno ao barroco estrito", "O atonalismo do século XX — a tonalidade desaparece progressivamente quando as dissonâncias param de se resolver", "O classicismo vienense de Haydn", "Apenas o impressionismo de Debussy"], a: 1, fb: "O romantismo tardio (o Tristão de Wagner, os Poemas sinfônicos de Liszt, o tardio Brahms) leva a tonalidade a seus limites: dissonâncias cada vez mais longas sem resolução, modulações para tonalidades distantes, ambiguidade do centro tonal. Essa evolução leva diretamente a Schoenberg e ao atonalismo — a tonalidade não pode mais se sustentar." },
  { q: "Para identificar uma obra romântica, qual tríade de critérios é mais pertinente?", opts: ["Baixo contínuo + fuga + modulações próximas", "Frases simétricas + harmonia econômica + baixo de Alberti", "Cromatismo expressivo + modulações por terças + acordes alterados (bVI, sextas aumentadas)", "Paralelismos + modos gregos + ausência de V–I"], a: 2, fb: "O romantismo reconhece-se por três critérios: (1) cromatismo expressivo frequente, (2) modulações por terças ou para tonalidades distantes, (3) acordes alterados e emprestados (bVI em maior, sexta napolitana, sextas aumentadas). Esse cromatismo harmônico o distingue claramente do classicismo econômico e do impressionismo colorista." },
  { q: "A forma do poema sinfônico (Liszt, Strauss) é característica de:", opts: ["O período barroco — é uma suíte de danças", "O romantismo — uma obra orquestral em um único movimento com programa literário ou pictórico", "O período clássico — é uma sinfonia em 4 movimentos", "O impressionismo — é uma peça atonal"], a: 1, fb: "O poema sinfônico (termo cunhado por Liszt) é uma obra orquestral em um único movimento inspirada em um programa extra-musical (poema, pintura, narrativa mitológica). Liszt compôs uma dúzia; Richard Strauss levou essa arte ao auge (Don Juan, Till Eulenspiegel, Assim falou Zaratustra). É uma forma emblematicamente romântica." },

  // ── TÓPICO 4: Identificação do impressionismo ─────────────────────────────
  { q: "O 'planing' harmônico é uma técnica associada a:", opts: ["Bach e o contraponto estrito", "O impressionismo de Debussy e Ravel — movimento paralelo de todos os intervalos de um acorde", "O romantismo de Wagner", "O período clássico"], a: 1, fb: "O planing (ou movimento paralelo) consiste em deslocar um acorde inteiro em movimento paralelo — todas as vozes movem-se na mesma direção pelo mesmo intervalo. Bach o proíbe (quintas paralelas = erro). Debussy faz disso uma técnica deliberada: os acordes deslizam como manchas de cor, sem resolução funcional." },
  { q: "A escala de tons inteiros (Dó–Ré–Mi–Fá#–Sol#–Lá#–Dó) é característica de:", opts: ["A escrita barroca em modo dórico", "O impressionismo de Debussy — ela cria total ambiguidade tonal, sem sensível nem subtônica", "O período clássico vienense", "O cromatismo romântico de Wagner"], a: 1, fb: "A escala de tons inteiros é uma escala de 6 sons em que cada grau é separado por um tom inteiro. Sem semitom, não tem sensível nem subtônica — impossível encontrar uma tônica clara. Debussy a usa para criar atmosferas flutuantes e cores harmônicas ambíguas, sem tensão-resolução funcional." },
  { q: "Os modos medievais (dórico, frígio, lídio, mixolídio) voltam à moda com:", opts: ["Bach e o barroco tardio", "O classicismo de Mozart", "O impressionismo e a música de Debussy e Ravel", "Wagner e o romantismo tardio"], a: 2, fb: "Debussy e Ravel redescobrem os modos medievais para escapar da tonalidade maior-menor e suas funções obrigatórias. O modo dórico (sem subtônica elevada), o frígio (sensível abaixada), o lídio (quarta aumentada), o mixolídio (sétima abaixada) oferecem novas cores. Esses modos também retornam no jazz e na música do século XX." },
  { q: "Como Debussy usa os acordes em relação à tensão-resolução clássica?", opts: ["Ele reforça a tensão-resolução V–I com mais dissonâncias do que o classicismo", "Seus acordes são manchas de cor que progridem por cor e registro — a tensão-resolução funcional é abandonada", "Ele usa apenas a cadência plagal IV–I", "Ele resolve todas as dissonâncias em I segundo as regras clássicas"], a: 1, fb: "Para Debussy, um acorde não é uma função em um sistema de tensão-resolução — é uma cor sonora. Os acordes de nona, décima-primeira, décima-terceira não 'se resolvem'; eles deslizam para outras cores. Esse pensamento harmônico-cromático em vez de funcional é a revolução impressionista: a cor prevalece sobre a função." },
  { q: "A escala pentatônica (Dó–Ré–Mi–Sol–Lá–Dó, sem Fá nem Si) é usada por Debussy para:", opts: ["Reforçar a cadência V–I eliminando a subdominante", "Criar atmosferas exóticas e flutuantes, influenciadas pela música asiática (gamelan javanês ouvido na Exposição Universal de 1889)", "Simplificar a harmonia para iniciantes", "Recuperar a pureza da música barroca"], a: 1, fb: "Debussy descobre o gamelan javanês na Exposição Universal de Paris em 1889 — fica fascinado com seus sons exóticos baseados na pentatônica. A escala pentatônica (5 sons sem semitons) cria uma atmosfera flutuante e suspensa. Essa influência oriental nutre seu impressionismo: A catedral submersa, Estampes." },
  { q: "Ravel (1875–1937) e Debussy são frequentemente associados ao impressionismo. Qual diferença estilística principal os distingue?", opts: ["Ravel usa a escala de tons, Debussy apenas a pentatônica", "Ravel conserva uma lógica formal mais clássica e um contraponto mais rigoroso; Debussy é mais livre e flutuante em suas formas", "Os dois são estilisticamente idênticos", "Debussy é mais clássico, Ravel mais impressionista"], a: 1, fb: "Apesar de sua associação, Ravel e Debussy diferem: Ravel mantém uma lógica formal mais nítida (especialmente em suas formas-sonata), um contraponto mais rigoroso, uma arquitetura mais clara. Debussy é mais livre em suas formas, mais flutuante em suas progressões. O próprio Ravel afirmava não ser 'impressionista'." },
  { q: "No impressionismo musical, o título de uma peça (A catedral submersa, O mar, Jogos d'água) sugere:", opts: ["Um programa dramático como as óperas de Wagner", "Impressões sensoriais, imagens evocativas em vez de uma narração — a música pinta uma atmosfera", "Uma referência a uma forma clássica abstrata", "Um tema religioso somente"], a: 1, fb: "Os títulos impressionistas evocam impressões sensoriais, luzes, reflexos, texturas — não dramas ou narrativas. O mar de Debussy não é uma tempestade narrativa (como o op.110 de Beethoven) — é uma impressão do mar em diferentes momentos. A inspiração vem da pintura impressionista (Monet): capturar o instante, a luz, não o objeto." },
  { q: "Quintas e oitavas paralelas são permitidas na harmonia impressionista?", opts: ["Não — as regras do contraponto estrito se aplicam sempre", "Sim — é inclusive uma técnica deliberada (planing) em Debussy", "Sim, mas apenas à distância de oitava", "Não, mas as quintas são autorizadas se o movimento é contrário"], a: 1, fb: "Quintas e oitavas paralelas são proibidas no contraponto clássico e barroco. Debussy as usa deliberadamente como técnica expressiva — o planing cria esse efeito de cores deslizantes. O que é um erro em um estilo (barroco, clássico) é uma técnica em outro (impressionismo). O contexto histórico é determinante." },
  { q: "Para identificar uma obra impressionista, qual tríade de critérios é mais pertinente?", opts: ["Baixo contínuo + fuga + cadências frequentes", "Frases simétricas + cadências V–I afirmadas + baixo de Alberti", "Acordes paralelos (planing) + modos/escala de tons/pentatônica + ausência de resolução funcional V–I", "Cromatismo denso + modulações por terças + acordes alterados"], a: 2, fb: "O impressionismo reconhece-se por três critérios: (1) acordes paralelos (planing) sem resolução funcional, (2) uso de modos, escala de tons e pentatônica, (3) ausência ou dissolução da cadência funcional V–I. Essa tríade o distingue claramente do romantismo (cromatismo funcional) e do classicismo (funções claras)." },
  { q: "O que distingue o cromatismo romântico do cromatismo impressionista?", opts: ["Não há nenhuma diferença entre os dois", "O romantismo usa o cromatismo para criar tensões funcionais que são resolvidas; o impressionismo usa cores não funcionais (modos, tons inteiros) sem tensão-resolução obrigatória", "O impressionismo é mais cromático que o romantismo", "O romantismo evita o cromatismo"], a: 1, fb: "A distinção é fundamental: o cromatismo romântico (Wagner, Chopin) cria tensões funcionais que exigem resolução — as alterações inscrevem-se em um sistema tensão-resolução. O impressionismo (Debussy) usa cores não funcionais — modos, escala de tons, pentatônica — sem tensão-resolução obrigatória. Não é 'mais cromatismo', é um uso radicalmente diferente." },

  // ── TÓPICO 5: Comparação estilística ─────────────────────────────────────
  { q: "A mesma melodia Dó–Mi–Sol–Dó harmonizada 'ao estilo de Bach' e 'ao estilo de Debussy' difere principalmente em:", opts: ["O andamento usado para tocá-la", "O tratamento da dominante: Bach a afirma obrigatoriamente (V–I); Debussy pode ignorá-la totalmente", "A melodia em si, que muda conforme o estilo", "O instrumento utilizado"], a: 1, fb: "A diferença fundamental entre uma harmonização barroca e uma impressionista reside no tratamento da dominante. Bach estrutura obrigatoriamente seu discurso em torno de V–I. Debussy pode harmonizar a mesma melodia com acordes de nona em paralelas, sem nenhuma resolução V–I — a melodia é a mesma, a harmonia está em um universo radicalmente diferente." },
  { q: "Qual compositor usa sistematicamente cadências perfeitas afirmadas (V–I)?", opts: ["Debussy", "Mozart", "Webern", "Messiaen"], a: 1, fb: "Mozart é a encarnação do estilo clássico com cadências perfeitas V–I frequentes e bem afirmadas, estruturando as frases de 4+4 compassos. Debussy evita essas cadências funcionais. Webern e Messiaen pertencem ao século XX e usam linguagens pós-tonais." },
  { q: "Qual compositor é mais conhecido por suas modulações por terça (ex. Dó maior → Láb maior)?", opts: ["Bach", "Mozart", "Schubert", "Debussy"], a: 2, fb: "Schubert é célebre por suas modulações por terça — um de seus traços estilísticos mais reconhecíveis. Em seus Lieder e sonatas, ele desliza frequentemente para tonalidades à distância de terça (maior ou menor), criando mudanças de cor repentinas e poéticas. Bach modula por quintas; Mozart para tonalidades próximas; Debussy evita as funções modulantes." },
  { q: "Qual compositor está associado ao conceito de 'melodia infinita' (fluxo contínuo que evita as cadências conclusivas)?", opts: ["Haydn", "Chopin", "Wagner", "Vivaldi"], a: 2, fb: "Wagner inventa o conceito de melodia infinita (unendliche Melodie) para seus dramas musicais: o fluxo orquestral e vocal evita as cadências conclusivas, criando uma tensão sustentada sem resolução. É o oposto da simetria clássica de 4+4 compassos. Haydn e Vivaldi vivem em um mundo de frases regularmente cadenciadas." },
  { q: "Qual compositor é conhecido pelo baixo de Alberti (fundamental–quinta–terça–quinta repetido)?", opts: ["Bach e o contraponto", "Mozart e o estilo clássico vienense", "Debussy e o impressionismo", "Wagner e o romantismo tardio"], a: 1, fb: "O baixo de Alberti é uma assinatura do estilo clássico vienense, particularmente de Mozart. Essa fórmula de acompanhamento onipresente em suas sonatas para piano substitui o contraponto barroco por um acompanhamento homofônico regular. Debussy afasta-se radicalmente dele; Bach nunca o usa." },
  { q: "Uma peça que usa modos gregos (dórico, lídio, mixolídio) e acordes paralelos é provavelmente:", opts: ["Uma fuga barroca de Bach", "Uma sonata clássica de Haydn", "Uma obra impressionista de Debussy ou Ravel", "Um Lied romântico de Schubert"], a: 2, fb: "Os modos gregos e os acordes paralelos (planing) são assinaturas impressionistas. Bach e Haydn não usam modos gregos em sua harmonia — trabalham no sistema maior/menor. Schubert às vezes usa o modo dórico, mas sem paralelismos. Debussy combina deliberadamente modos, escala de tons e planing." },
  { q: "Uma peça que usa intensamente o trítono como tensão não resolvida é característica de:", opts: ["A harmonia clássica de Mozart (o trítono é sempre resolvido)", "O romantismo tardio de Wagner, onde as dissonâncias permanecem sem resolução por muito tempo", "A música barroca, onde o trítono é estritamente proibido", "A escala pentatônica, que contém numerosos trítonos"], a: 1, fb: "O trítono (diabolus in musica) deve ser resolvido na música clássica e barroca. Wagner em Tristão usa o trítono de forma recorrente deixando sua resolução suspensa por longas durações — uma audácia harmônica que simboliza o desejo insatisfeito. A escala pentatônica não contém trítono (é justamente por isso que soa 'suave')." },
  { q: "Qual estilo harmônico NÃO usa a progressão V–I como cadência estruturante?", opts: ["O barroco de Bach", "O classicismo de Mozart", "O romantismo de Schubert", "O impressionismo de Debussy"], a: 3, fb: "Bach, Mozart e Schubert (em sua escrita tonal) usam todos a progressão V–I como cadência estruturante fundamental. Debussy abandona deliberadamente esse princípio: seus acordes progridem por cor e registro, não por tensão-resolução. Buscar cadências V–I funcionais no impressionismo é aplicar a ferramenta analítica errada." },
  { q: "Um acorde de nona maior não resolvido, seguido de um acorde de nona um semitom mais agudo (planing), é característico de:", opts: ["Uma fuga barroca", "Uma sonata clássica", "O impressionismo de Debussy", "Um Lied romântico de Brahms"], a: 2, fb: "O planing de acordes complexos (nona, décima-primeira, décima-terceira) sem resolução é uma técnica impressionista típica. Um acorde de nona maior que desliza por semitom para outro acorde de nona não faz sentido no sistema tensão-resolução clássico ou romântico — é movimento por cor, não por função. Isso é Debussy em ação." },
  { q: "Analisar os 'Préludes pour piano' de Debussy com as funções T/SD/D é:", opts: ["Pertinente — Debussy usa as funções tonais clássicas apesar de suas dissonâncias", "Contraproducente — seus acordes são cores, não funções; a análise modal e tímbrica é mais adequada", "Obrigatório para qualquer análise harmônica séria", "Apropriado apenas para os prelúdios barrocos"], a: 1, fb: "Aplicar as funções T/SD/D a Debussy é usar a ferramenta errada: seus acordes não funcionam como tensões em direção a uma resolução. Uma análise pertinente dos Préludes de Debussy examina os modos utilizados, os paralelismos, as cores tímbricas, as relações de registro — não 'dominantes' e 'subdominantes' funcionais." },
  { q: "Para identificar a época de uma obra com base em 3 indícios, deve-se examinar:", opts: ["O país do compositor, o instrumento utilizado e a duração da peça", "A densidade do cromatismo, a presença ou ausência da resolução V–I e o tratamento das dissonâncias", "Apenas andamento, dinâmica e articulação", "O número de movimentos, a tonalidade e o compositor"], a: 1, fb: "Os três indícios mais reveladores da época histórica de uma obra: (1) densidade do cromatismo (baixa=barroco/clássico, média=romântico, por cor=impressionismo), (2) presença/ausência de V–I (obrigatório=barroco/clássico, evitado=romantismo tardio, inexistente=impressionismo), (3) tratamento das dissonâncias (resolução imediata=barroco, prolongada=romantismo, não resolvida=impressionismo)." },
  { q: "Qual compositor 'conhecia perfeitamente as regras que transgrediu' — ilustrando que a liberdade requer o domínio prévio?", opts: ["Bach — que ignorava as regras modais para criar livremente", "Debussy — cuja liberdade impressionista repousa em um perfeito domínio do contraponto e da harmonia clássica", "Mozart — que transgrediu as regras da sonata clássica", "Haendel — cujas quintas paralelas são propositais"], a: 1, fb: "Debussy ilustra perfeitamente o paradoxo da liberdade criativa: ele estudou contraponto e harmonia clássica no Conservatório de Paris (Prêmio de Roma 1884), dominando perfeitamente as regras que iria transgredir. Sua aparente liberdade é calculada — não ignorância. Para libertar-se das regras, é preciso primeiro dominá-las." },
  { q: "O pós-romantismo (Wagner tardio, Mahler, Richard Strauss) distingue-se do romantismo por:", opts: ["O abandono do cromatismo e o retorno ao diatonismo clássico", "Um cromatismo ainda mais denso, acordes de nona–décima-primeira–décima-terceira, uma tonalidade presente mas alargada e longas tensões mantidas", "O uso da escala de tons e do planing impressionista", "A estrutura em fuga contrapontística"], a: 1, fb: "O pós-romantismo amplifica o romantismo: cromatismo total (todas as 12 notas podem aparecer em um curto trecho), acordes de nona, décima-primeira, décima-terceira longamente irresolvidos, tonalidade mantida mas sob tensão extrema. É a tonalidade em seu ponto-limite antes do atonalismo — Mahler e Strauss estão nesse espaço entre romantismo e modernismo." },
  { q: "Se uma obra tem cadências claras V–I, mas também acordes de dominante secundária e algumas modulações por terças, ela é provavelmente:", opts: ["Estritamente barroca", "Do romantismo (Schubert, início de Chopin) — as funções tonais permanecem, mas se enriquecem de cromatismo expressivo", "Do impressionismo puro", "Do classicismo estrito de Haydn"], a: 1, fb: "Essa descrição corresponde ao romantismo moderado (Schubert, primeiro Chopin): as funções tonais V–I permanecem presentes e estruturantes, mas enriquecidas de cromatismo expressivo, modulações por terças, dominantes secundárias. Ainda não é o romantismo tardio (Wagner) que suspende as resoluções por longo tempo. É a zona de transição entre classicismo e romantismo avançado." },
];

